function selectInstance(instanceId, options = {}) {
  const previousSelectedInstanceId = selectedInstanceId;
  const selectedInstance = findInstance(instanceId);
  selectedInstanceId = selectedInstance?.id || null;
  storeLastInstanceId(selectedInstanceId);
  if (previousSelectedInstanceId !== selectedInstanceId) {
    clearInstanceLogs(selectedInstanceId ? "Refresh logs to load the selected instance." : "Select an instance and refresh logs.");
  }
  setInstanceDetails(selectedInstance);

  if (instancesList) {
    [...instancesList.querySelectorAll("tr")].forEach((row) => {
      row.classList.toggle("is-selected", row.dataset.instanceId === selectedInstanceId);
    });
  }

  updateInstanceActionButtons();

  if (selectedInstanceId && options.refreshMetrics !== false) {
    refreshSelectedInstanceMetrics();
  }
  syncInstanceConsolePolling();
}

function renderInstancesSnapshot(snapshot) {
  const previousInstances = getInstances();
  const normalizedSnapshot = normalizeInstancesPayload(snapshot);
  const incomingInstances = normalizedSnapshot.instances;
  const incomingIds = new Set(incomingInstances.map((instance) => instance.id));
  const preservedInstances = previousInstances.filter((instance) => {
    return instance?.id && !incomingIds.has(instance.id) && !instanceRemovalAllowedIds.has(instance.id);
  });
  const removedIds = previousInstances
    .filter((instance) => instance?.id && !incomingIds.has(instance.id) && instanceRemovalAllowedIds.has(instance.id))
    .map((instance) => instance.id);

  if (preservedInstances.length > 0 || removedIds.length > 0) {
    console.info("[Instances] List reconciliation.", {
      incomingCount: incomingInstances.length,
      preservedIds: preservedInstances.map((instance) => instance.id),
      removedIds,
    });
  }

  latestInstancesSnapshot = {
    ...normalizedSnapshot,
    instances: [...incomingInstances, ...preservedInstances],
  };
  latestInstancesSnapshotAt = Date.now();
  instanceRemovalAllowedIds.clear();
  const instances = getInstances();
  const previousSelectedInstanceId = selectedInstanceId;
  const storedInstanceId = readLastInstanceId();
  const rememberedInstanceId = storedInstanceId;
  const previousExists = Boolean(previousSelectedInstanceId && findInstance(previousSelectedInstanceId));
  const rememberedExists = Boolean(rememberedInstanceId && findInstance(rememberedInstanceId));
  const selected =
    findInstance(previousSelectedInstanceId) ||
    findInstance(rememberedInstanceId) ||
    instances[0] ||
    null;

  if (
    (previousSelectedInstanceId && !previousExists) ||
    (rememberedInstanceId && !rememberedExists && !previousExists)
  ) {
    notifyMissingSelectedInstance();
    storeLastInstanceId(null);
  }

  selectedInstanceId = selected?.id || null;

  renderInstanceSummary(instances);
  setField("instancesLoadingMessage", "Checking agent instance status...");
  renderInstanceRows(instances);
  selectInstance(selectedInstanceId, { refreshMetrics: false });
  renderConsoleWorkspace();
  setInstancesLoading(false);
  setInstancesEmpty(instances.length === 0);
  updateInstanceActionButtons();
  if (getActivePageName() === "marketplace") {
    renderMarketplaceTemplates();
    renderMarketplaceInstallSummary(findMarketplaceTemplate());
  }
  refreshNodeHealth({ notify: false });
  updateTitlebar();
}

function renderInstancesUnavailable(message = "Instance manager unavailable.") {
  latestInstancesSnapshot = null;
  latestInstancesSnapshotAt = 0;
  latestInstanceMetrics = null;
  selectedInstanceId = null;
  storeLastInstanceId(null);
  setField("instancesTotal", "Unavailable");
  setField("instancesRunning", "Unavailable");
  setField("instancesStopped", "Unavailable");
  setField("instancesTotalCpu", "Unavailable");
  setField("instancesTotalRam", "Unavailable");
  setField("instancesSelectedCpu", "Unavailable");
  setField("instancesSelectedMemory", "Unavailable");
  setInstancesLoading(false);
  setInstancesEmpty(true, message);
  clearInstanceRows();
  setInstanceDetails(null);
  clearInstanceLogs("Select an instance and refresh logs.");
  activeConsoleInstanceId = null;
  consoleOpenInstanceIds = [];
  consoleBufferedEntries = [];
  renderConsoleWorkspace();
  updateInstanceActionButtons();
  refreshNodeHealth({ notify: false });
  updateTitlebar();
}

function filterInstanceRows() {
  const query = (instancesSearchInput?.value || "").trim().toLowerCase();
  const statusFilter = (instancesFilterSelect?.value || "all").toLowerCase();

  if (!instancesList) {
    return;
  }

  [...instancesList.querySelectorAll("tr")].forEach((row) => {
    const matchesQuery = query.length === 0 || row.textContent.toLowerCase().includes(query);
    const matchesStatus = statusFilter === "all" || row.dataset.instanceState === statusFilter;
    row.hidden = !matchesQuery || !matchesStatus;
  });
}

function clearInstanceLogs(message = "Select an instance and refresh logs.") {
  instancesLogList?.replaceChildren();

  if (instancesLogEmpty) {
    instancesLogEmpty.hidden = false;
    const messageTarget = instancesLogEmpty.querySelector("span:last-child");
    if (messageTarget) {
      messageTarget.textContent = message;
    }
  }

  if (instancesLogCount) {
    instancesLogCount.textContent = "0 lines";
  }
}

function renderInstanceLogs(payload) {
  const entries = Array.isArray(payload?.entries) ? payload.entries : [];
  instancesLogList?.replaceChildren();

  entries.forEach((entry) => {
    const item = document.createElement("li");
    const severity = getLogSeverity(entry);
    item.dataset.stream = entry?.stream || "log";
    item.dataset.severity = severity;
    item.classList.toggle("is-stderr", entry?.stream === "stderr");
    item.classList.toggle("is-stdin", entry?.stream === "stdin");
    item.classList.toggle("is-warn", severity === "warn");
    item.classList.toggle("is-error", severity === "error");
    const time = document.createElement("time");
    time.dateTime = entry?.at || "";
    time.textContent = entry?.at ? formatDateTime(entry.at) : "No timestamp";
    const stream = document.createElement("span");
    stream.className = "instance-log-stream";
    stream.textContent = entry?.stream || "log";
    const message = document.createElement("span");
    appendAnsiText(message, entry?.message || "");
    item.append(time, stream, message);
    instancesLogList?.appendChild(item);
  });

  syncConsoleLogSearch();

  if (instanceConsoleAutoscrollInput?.checked && !instanceConsolePauseInput?.checked && instanceConsoleViewer) {
    instanceConsoleViewer.scrollTop = instanceConsoleViewer.scrollHeight;
  }

  if (instancesLogEmpty) {
    instancesLogEmpty.hidden = entries.length > 0;
  }

  if (instancesLogCount) {
    instancesLogCount.textContent = `${entries.length} ${entries.length === 1 ? "line" : "lines"}`;
  }
}

function getAgentErrorMessage(error, fallback = "Instance request failed.") {
  const backendCode = error?.payload?.error?.code || error?.code;
  const backendMessage = error?.payload?.error?.message;
  const wrappedMessage = String(error?.message || "");
  const detailedMessage = [wrappedMessage, backendMessage].find((message) => {
    const text = String(message || "");
    return text.includes("templateId=") ||
      text.includes(" | url=") ||
      text.includes(" | invalidUrl=") ||
      text.includes(" | status=") ||
      text.includes(" | body=") ||
      text.includes(" | code=") ||
      text.includes("envSourcesChecked=") ||
      text.includes("expectedEnvNames=") ||
      text.includes("isPackaged=") ||
      text.includes("userDataPath=");
  });
  if (detailedMessage) {
    return detailedMessage;
  }
  if (/\bHTTP\s+\d{3}\b/i.test(wrappedMessage) || /Invalid API key|Forbidden|Project not found|Rate limited|Network timeout|Invalid provider metadata|Missing server files|Unsupported modpack/i.test(wrappedMessage)) {
    return wrappedMessage;
  }
  const wrappedCode = wrappedMessage.match(/\b[A-Z][A-Z0-9_]{2,}\b/)?.[0] || null;
  if (wrappedCode === "HTTP") {
    return wrappedMessage || fallback;
  }
  const effectiveCode = backendCode && backendCode !== "AGENT_HTTP_ERROR" ? backendCode : wrappedCode;
  const friendlyMessages = {
    INSTANCE_ALREADY_EXISTS: "An instance with this ID already exists. Delete the failed partial instance or choose a different name, then retry.",
    INSTANCE_NOT_FOUND: "The selected instance no longer exists.",
    INSTANCE_VERIFICATION_FAILED: error?.message || "Created instance could not be verified.",
    AGENT_TOKEN_MISSING: "Agent token is missing. Run npm run agent:token:status to create the shared token, then restart the agent and desktop app.",
    UNAUTHORIZED: "Agent token rejected. The desktop app and agent are not using the same shared token. Run npm run agent:token:status and restart both apps.",
    NOT_FOUND: "The selected instance no longer exists.",
    INSTANCE_RUNNING: "Stop the instance before deleting it.",
    INSTANCE_DELETE_FAILED: "Instance files could not be deleted.",
    INSTANCE_FORGET_FAILED: "Instance record could not be removed.",
    INSTANCE_ALREADY_RUNNING: "This instance is already running.",
    INSTANCE_NOT_RUNNING: "This instance is not running.",
    EXECUTABLE_NOT_ALLOWED: "This executable is not allowed by the agent.",
    INVALID_MEMORY_LIMIT: "Use memory like 512M, 2G, or 2048M.",
    INVALID_INSTANCE_ID: "Use an ID with 2-64 letters, numbers, underscores, or dashes.",
    INVALID_DISPLAY_NAME: "Enter a valid instance name.",
    INVALID_PORTS: "Enter valid ports between 1 and 65535.",
    PATH_NOT_FOUND: "The requested file or folder was not found.",
    DOWNLOAD_FAILED: "The template download failed.",
    DOWNLOAD_REQUIRED: "This template requires a downloadable server file.",
    DOWNLOAD_URL_INCOMPLETE: "The template download URL is incomplete.",
    DOWNLOAD_RESOLVE_FAILED: "Unable to resolve the latest server download.",
    INSTALLER_TYPE_UNSUPPORTED: "This Marketplace installer type is not supported.",
    MARKETPLACE_MANIFEST_INVALID: "This Marketplace entry has an invalid definition.",
    MINECRAFT_PORT_INVALID: "Enter a whole-number Minecraft port between 1 and 65535.",
    MINECRAFT_PORT_IN_USE: "That Minecraft port is already in use.",
    SERVER_PROPERTIES_NOT_WRITABLE: "server.properties could not be written.",
    SERVER_PROPERTIES_UPDATE_FAILED: "The selected Minecraft port could not be saved to server.properties.",
    STEAMCMD_NOT_FOUND: "SteamCMD is required on the selected node.",
    STEAMCMD_INSTALL_FAILED: "SteamCMD failed to install this dedicated server.",
    FABRIC_RESOLVE_FAILED: "Unable to resolve Fabric download.",
    FORGE_RESOLVE_FAILED: "Unable to download Forge installer.",
    NEOFORGE_RESOLVE_FAILED: "Unable to download NeoForge installer.",
    PROXY_RESOLVE_FAILED: "Unable to resolve proxy download.",
    TEMPLATE_NOT_READY: "This template is not ready yet.",
    TEMPLATE_INSTALL_TIMEOUT: "The template installer did not finish in time.",
    STARTUP_CONFIGURATION_FAILED: "The startup command could not be configured.",
    MARKETPLACE_INSTALL_FAILED: "Template install failed.",
    FIVEM_LICENSE_REQUIRED: "FiveM needs a valid license key in server.cfg before it can start.",
    FIVEM_SETUP_REQUIRED: "FiveM setup is required before this server can start.",
    INVALID_FIVEM_LICENSE_KEY: "Enter a valid FiveM license key from Cfx.re Keymaster.",
  };

  if (friendlyMessages[effectiveCode]) {
    return friendlyMessages[effectiveCode];
  }

  if (backendCode && backendCode !== "AGENT_HTTP_ERROR") {
    return backendMessage && backendMessage !== "Request failed."
      ? `${backendCode}: ${backendMessage}`
      : backendCode;
  }

  if (wrappedCode) {
    return wrappedCode;
  }

  return error?.message || fallback;
}

function getAgentErrorCode(error) {
  const backendCode = error?.payload?.error?.code || error?.code;
  if (backendCode && backendCode !== "AGENT_HTTP_ERROR") {
    return backendCode;
  }

  return String(error?.message || "").match(/\b[A-Z][A-Z0-9_]{2,}\b/)?.[0] || null;
}

function isInstanceNotFoundError(error) {
  const code = getAgentErrorCode(error);
  return code === "INSTANCE_NOT_FOUND" || code === "NOT_FOUND";
}

function isInstanceRunningError(error) {
  return getAgentErrorCode(error) === "INSTANCE_RUNNING";
}

function formatInstanceDeletionResult(result, fallback) {
  if (!result || typeof result !== "object") {
    return fallback;
  }
  const parts = [];
  if (result.filesDeleted) parts.push("files deleted");
  if (result.metadataRemoved) parts.push("metadata removed");
  if (result.alreadyMissing) parts.push("already missing");
  if (result.tombstoneAdded && !result.metadataRemoved) parts.push("hidden from this list");
  if (result.partiallyFailed) parts.push("partial cleanup");
  return parts.length ? `${fallback} (${parts.join(", ")}).` : fallback;
}

function notifyMissingSelectedInstance(error = null) {
  if (error) {
    console.warn("[Instances] Selected instance no longer exists.", error);
  }

  const now = Date.now();
  if (now - lastMissingInstanceNoticeAt > 5000) {
    showToast("Selected instance no longer exists.", "warning");
    lastMissingInstanceNoticeAt = now;
  }
}

async function handleMissingSelectedInstance(error = null, instanceId = selectedInstanceId, reason = "instance-not-found") {
  const missingInstanceId = instanceId || selectedInstanceId;

  if (missingInstanceId) {
    console.warn("[Instances] Instance request failed; keeping renderer list intact.", {
      instanceId: missingInstanceId,
      reason,
      errorCode: error ? getAgentErrorCode(error) : null,
    });
  } else {
    notifyMissingSelectedInstance(error);
  }

  latestInstanceMetrics = null;

  if (missingInstanceId && findInstance(missingInstanceId)) {
    updateInstanceSnapshot(missingInstanceId, {
      state: "Failed",
      failureReason: getAgentErrorMessage(error, "Instance request failed."),
    });
    showToast(getAgentErrorMessage(error, "Instance request failed."), "warning");
    return;
  }

  if (selectedInstanceId === missingInstanceId) {
    selectedInstanceId = null;
    storeLastInstanceId(null);
    clearInstanceLogs("Selected instance no longer exists.");
    setInstanceDetails(null);
  }

  updateInstanceActionButtons();
}

function getMarketplaceField(name) {
  return document.querySelector(`[data-marketplace-field="${name}"]`);
}

function getMarketplacePortHelpText() {
  const template = findMarketplaceTemplate();
  if (template?.id === "palworld") {
    return "Port must be a number from 1 to 65535. For Palworld, use 8211. Do not include commas, /udp, hostnames, or URLs.";
  }
  return "Port must be a number from 1 to 65535. Do not include commas, /tcp, /udp, hostnames, or URLs.";
}

function syncMarketplacePortValidity({ report = false } = {}) {
  const portField = getMarketplaceField("port");
  if (!portField) return true;
  portField.setCustomValidity("");
  const value = String(portField.value || "").trim();
  const numericValue = Number(value);
  const invalid = portField.validity.badInput
    || portField.validity.rangeUnderflow
    || portField.validity.rangeOverflow
    || (value && (!Number.isInteger(numericValue) || numericValue < 1 || numericValue > 65535));
  if (invalid) {
    portField.setCustomValidity(getMarketplacePortHelpText());
    if (marketplaceSelectedTemplateId) {
      setMarketplaceMessage(getMarketplacePortHelpText(), "error");
    }
    if (report) portField.reportValidity();
    return false;
  }
  return true;
}

function syncMarketplaceMemoryValidity({ report = false } = {}) {
  const memoryField = getMarketplaceField("memory");
  if (!memoryField) return true;
  memoryField.setCustomValidity("");
  const value = String(memoryField.value || "").trim();
  if (!value) {
    return true;
  }
  if (!/^[1-9][0-9]{0,5}[kKmMgG]?$/.test(value)) {
    const message = "Memory must be a value such as 512M, 2G, or 2048M.";
    memoryField.setCustomValidity(message);
    if (marketplaceSelectedTemplateId) {
      setMarketplaceMessage(message, "error");
    }
    if (report) memoryField.reportValidity();
    return false;
  }
  return true;
}

function readMarketplaceWholeNumberField(name, { label, min = 1, max = Number.MAX_SAFE_INTEGER, optional = false } = {}) {
  const field = getMarketplaceField(name);
  const raw = String(field?.value || "").trim();
  if (!raw) {
    return undefined;
  }
  if (!/^[0-9]+$/.test(raw)) {
    throw new Error(`${label || name} must be a whole number from ${min} to ${max}.`);
  }
  const parsed = Number(raw);
  if (!Number.isSafeInteger(parsed) || parsed < min || parsed > max) {
    throw new Error(`${label || name} must be a whole number from ${min} to ${max}.`);
  }
  return optional && raw === "" ? undefined : parsed;
}

function setMarketplaceMessage(message, tone = "neutral") {
  if (!marketplaceMessage) {
    return;
  }

  marketplaceMessage.textContent = message;
  marketplaceMessage.dataset.tone = tone;
}

function openCurseForgeIntegrationSettings() {
  showPage("settings");
  if (marketplaceConfigInput) {
    marketplaceConfigInput.scrollIntoView({ block: "center", behavior: "smooth" });
    marketplaceConfigInput.focus();
  }
}

function isCurseForgeApiKeyRequiredError(error = {}) {
  const message = String(error?.message || "").trim();
  const code = error?.details?.code || error?.payload?.error?.code || error?.code;
  return code === "CURSEFORGE_API_KEY_REQUIRED" || message === "CurseForge API key required";
}

function createMarketplaceEmptyStateContent(state = {}) {
  const title = document.createElement("strong");
  title.textContent = state.title || "No templates found";

  const detail = document.createElement("span");
  detail.textContent = state.message || "Marketplace templates appear here after the catalog loads. Clear filters, choose a category, or check dependencies for the selected node.";

  if (state.action === "open-settings") {
    const action = document.createElement("button");
    action.type = "button";
    action.className = "inline-action";
    action.textContent = "Open Settings";
    action.addEventListener("click", openCurseForgeIntegrationSettings);
    return [title, detail, action];
  }

  return [title, detail];
}

function renderMarketplaceEmptyState(state = null) {
  if (!marketplaceEmpty) {
    return;
  }

  const activeState = state || {
    title: "No templates found",
    message: "Marketplace templates appear here after the catalog loads. Clear filters, choose a category, or check dependencies for the selected node.",
  };
  marketplaceEmpty.replaceChildren(...createMarketplaceEmptyStateContent(activeState));
  marketplaceEmpty.hidden = marketplaceRequestInFlight || marketplaceProviderRequestInFlight || Boolean(activeState.hidden);
}

function getMarketplaceTemplates() {
  const templates = Array.isArray(marketplaceCatalog.templates) ? marketplaceCatalog.templates : [];
  return [...templates, ...marketplaceProviderTemplates.values()];
}

function getStaticMarketplaceTemplates() {
  return Array.isArray(marketplaceCatalog.templates) ? marketplaceCatalog.templates : [];
}

function findMarketplaceTemplate(templateId = marketplaceSelectedTemplateId) {
  return getMarketplaceTemplates().find((template) => template.id === templateId) || null;
}

function setMarketplaceLoading(loading) {
  marketplaceRequestInFlight = Boolean(loading);
  if (marketplaceLoading) {
    marketplaceLoading.hidden = !loading;
    marketplaceLoading.setAttribute("aria-busy", loading ? "true" : "false");
  }
  if (marketplaceRefreshButton) {
    marketplaceRefreshButton.disabled = loading;
  }
  document.querySelector('[data-page="marketplace"]')?.setAttribute("aria-busy", loading ? "true" : "false");
}

function renderMarketplaceCategories() {
  if (!marketplaceCategories) {
    return;
  }

  marketplaceCategories.replaceChildren();
  const categories = ["All", ...(Array.isArray(marketplaceCatalog.categories) ? marketplaceCatalog.categories : []), "Modpacks"]
    .filter((category, index, source) => source.indexOf(category) === index);

  categories.forEach((category) => {
    const button = document.createElement("button");
    button.type = "button";
    button.className = "marketplace-category";
    button.textContent = category;
    button.classList.toggle("is-active", category === marketplaceActiveCategory);
    button.addEventListener("click", () => {
      marketplaceActiveCategory = category;
      marketplaceProviderError = null;
      renderMarketplaceCategories();
      renderMarketplaceTemplates();
      if (category === "Modpacks" && marketplaceProviderResults.length === 0) {
        loadMarketplaceProviderPacks({ reset: true });
      }
    });
    marketplaceCategories.append(button);
  });
}

function getFilteredMarketplaceTemplates() {
  const query = (marketplaceSearchInput?.value || "").trim().toLowerCase();
  return getStaticMarketplaceTemplates().filter((template) => {
    const matchesCategory = marketplaceActiveCategory === "All" || template.category === marketplaceActiveCategory;
    const haystack = [
      template.displayName,
      template.name,
      template.description,
      template.author,
      template.version,
      template.category,
      template.id,
      Array.isArray(template.tags) ? template.tags.join(" ") : "",
    ].filter(Boolean).join(" ").toLowerCase();
    return matchesCategory && (!query || haystack.includes(query));
  });
}

function isMarketplaceProviderBrowserActive() {
  return marketplaceActiveCategory === "Modpacks";
}

function isMarketplaceProviderSectionVisible() {
  return isMarketplaceProviderBrowserActive();
}

function renderMarketplaceTemplates() {
  if (!marketplaceGrid) {
    return;
  }

  renderMarketplaceProviderControls();
  marketplaceGrid.replaceChildren();
  const providerBrowserActive = isMarketplaceProviderBrowserActive();
  const fetchedCount = providerBrowserActive ? marketplaceProviderResults.length : getStaticMarketplaceTemplates().length;
  const templates = providerBrowserActive
    ? marketplaceProviderResults.map(registerProviderMarketplaceTemplate)
    : getFilteredMarketplaceTemplates();
  console.info("[Marketplace][Renderer] renderMarketplaceTemplates.", {
    category: marketplaceActiveCategory,
    provider: providerBrowserActive ? marketplaceProviderActive : "static",
    fetchedCount,
    filteredCount: templates.length,
    renderedCount: templates.length,
    query: marketplaceSearchInput?.value || "",
    loader: marketplaceProviderLoader?.value || "",
    minecraftVersion: marketplaceProviderMinecraftVersion?.value || "",
  });
  renderMarketplaceEmptyState(templates.length > 0 ? { hidden: true } : marketplaceProviderError);

  templates.forEach((template) => {
    const templateState = getMarketplaceStateForTemplate(template);
    const card = document.createElement("article");
    card.className = "marketplace-card";
    card.classList.toggle("is-selected", template.id === marketplaceSelectedTemplateId);
    card.classList.toggle("is-disabled", Boolean(template.comingSoon || template.disabled));
    card.dataset.marketplaceState = templateState.label.toLowerCase().replace(/[^a-z0-9]+/g, "-");
    card.tabIndex = 0;
    card.setAttribute("aria-label", `${template.displayName || template.id || "Marketplace template"}: ${templateState.label}`);

    const icon = document.createElement("span");
    icon.className = "marketplace-card__icon";
    if (template.iconUrl) {
      const image = document.createElement("img");
      image.src = template.iconUrl;
      image.alt = "";
      icon.append(image);
    } else {
      icon.textContent = template.icon || "APP";
    }

    const body = document.createElement("div");
    body.className = "marketplace-card__body";
    const title = document.createElement("strong");
    title.textContent = template.displayName || template.id;
    const description = document.createElement("p");
    description.textContent = template.description || "No description provided.";
    const meta = document.createElement("span");
    meta.className = "marketplace-card__meta";
    const downloads = template.category === "Modpacks" ? ` · ${formatProviderDownloads(template.downloads)} downloads` : "";
    meta.textContent = `${template.author || "Unknown"} · v${template.version || "0.0.0"} · ${template.category || "Uncategorized"}${downloads}`;
    const stateBadge = document.createElement("span");
    stateBadge.className = `marketplace-card__state status-pill status-pill--${templateState.tone}`;
    stateBadge.textContent = templateState.instances.length > 1
      ? `${templateState.label} (${templateState.instances.length})`
      : templateState.label;
    const badges = document.createElement("div");
    badges.className = "marketplace-card__badges";
    [
      formatMarketplaceProviderLabel(template),
      formatMarketplaceLoaderLabel(template),
      template.minecraftVersion || template.gameVersion || template.serverVersion || "",
    ].filter(Boolean).forEach((label) => {
      const badge = document.createElement("span");
      badge.className = "marketplace-card__badge";
      badge.textContent = label;
      badges.append(badge);
    });
    body.append(title, description, meta, stateBadge, badges);

    const install = document.createElement("button");
    install.type = "button";
    install.className = "inline-action";
    install.textContent = template.comingSoon || template.disabled ? "Coming soon" : templateState.action;
    install.disabled = Boolean(template.comingSoon || template.disabled || templateState.disabled);
    install.addEventListener("click", () => {
      if (templateState.action === "Review recovery") {
        reviewMarketplaceRecovery(template);
        return;
      }
      if (templateState.instances.length && templateState.action === "Open instance") {
        openMarketplaceInstance(templateState.instances[0].id);
        return;
      }
      openMarketplaceWizard(template.id);
    });

    card.append(icon, body, install);
    card.addEventListener("keydown", (event) => {
      if (event.key !== "Enter" && event.key !== " ") return;
      event.preventDefault();
      if (templateState.action === "Review recovery") {
        reviewMarketplaceRecovery(template);
        return;
      }
      if (templateState.instances.length && templateState.action === "Open instance") {
        openMarketplaceInstance(templateState.instances[0].id);
        return;
      }
      if (!template.comingSoon && !template.disabled) openMarketplaceWizard(template.id);
    });
    card.addEventListener("dblclick", () => {
      if (template.comingSoon || template.disabled) {
        setMarketplaceMessage(template.comingSoonMessage || "This template is not ready yet.", "warning");
        return;
      }
      if (templateState.action === "Review recovery") {
        reviewMarketplaceRecovery(template);
        return;
      }
      if (templateState.instances.length && templateState.action === "Open instance") {
        openMarketplaceInstance(templateState.instances[0].id);
        return;
      }
      openMarketplaceWizard(template.id);
    });
    marketplaceGrid.append(card);
  });
}

async function loadMarketplaceProviderPacks({ reset = false } = {}) {
  const desktopApiState = getDesktopApiState();
  const page = reset ? 1 : Math.floor((Number(marketplaceProviderOffset) || 0) / MARKETPLACE_PROVIDER_PAGE_SIZE) + 1;
  console.info("[Marketplace][Renderer] Provider refresh requested.", {
    category: marketplaceActiveCategory,
    provider: marketplaceProviderActive,
    mode: marketplaceProviderMode,
    query: marketplaceSearchInput?.value || "",
    minecraftVersion: marketplaceProviderMinecraftVersion?.value || "",
    loader: marketplaceProviderLoader?.value || "",
    page,
    reset,
    inFlight: marketplaceProviderRequestInFlight,
    providerInstallAvailable: desktopApiState.hasMarketplaceProviderInstall,
  });
  if (!desktopApiState.hasMarketplaceProviderInstall || marketplaceProviderRequestInFlight) {
    if (!desktopApiState.hasMarketplaceProviderInstall) {
      setMarketplaceProviderStatus("Provider browser is unavailable in this build.", "warning");
    }
    return;
  }

  marketplaceProviderRequestInFlight = true;
  marketplaceProviderRequestId += 1;
  const requestId = marketplaceProviderRequestId;
  if (reset) {
    marketplaceProviderOffset = 0;
    marketplaceProviderHasMore = false;
    marketplaceProviderResults = [];
    marketplaceProviderError = null;
  }
  renderMarketplaceProviderControls();
  setMarketplaceProviderStatus(`Loading ${formatMarketplaceProviderLabel({ provider: marketplaceProviderActive })} modpacks...`);
  if (marketplaceLoading) {
    marketplaceLoading.hidden = false;
  }

  try {
    const payload = getMarketplaceProviderQueryPayload({ reset });
    console.info("[Marketplace][Renderer] Provider IPC request.", payload);
    const result = await desktopApiState.api.marketplace.searchProviderPacks(payload);
    if (requestId !== marketplaceProviderRequestId) {
      return;
    }
    const results = Array.isArray(result?.results) ? result.results : [];
    const fetchedCount = results.length;
    marketplaceProviderResults = reset ? results : [...marketplaceProviderResults, ...results];
    marketplaceProviderOffset = Number(result?.nextOffset) || marketplaceProviderResults.length;
    marketplaceProviderHasMore = Boolean(result?.hasMore);
    marketplaceProviderError = null;
    const filteredCount = marketplaceProviderResults.length;
    const renderedCount = filteredCount;
    console.info("[Marketplace][Renderer] Provider render counts.", {
      provider: marketplaceProviderActive,
      fetchedCount,
      filteredCount,
      renderedCount,
      totalLoaded: marketplaceProviderResults.length,
      diagnostics: result?.diagnostics || null,
    });
    const zeroReason = result?.diagnostics?.zeroReason || null;
    if (marketplaceProviderResults.length === 0) {
      const diagnostic = zeroReason ? ` (${zeroReason.replace(/_/g, " ")})` : "";
      const url = result?.diagnostics?.url ? ` URL: ${result.diagnostics.url}` : "";
      setMarketplaceProviderStatus(`No ${formatMarketplaceProviderLabel({ provider: marketplaceProviderActive })} modpacks loaded${diagnostic}.${url}`, "warning");
    } else {
      setMarketplaceProviderStatus(`${marketplaceProviderResults.length} ${formatMarketplaceProviderLabel({ provider: marketplaceProviderActive })} modpacks loaded.`, "success");
    }
    renderMarketplaceTemplates();
  } catch (error) {
    if (requestId !== marketplaceProviderRequestId) {
      return;
    }
    console.error("[Marketplace][Renderer] Provider search failed.", {
      provider: marketplaceProviderActive,
      query: marketplaceSearchInput?.value || "",
      minecraftVersion: marketplaceProviderMinecraftVersion?.value || "",
      loader: marketplaceProviderLoader?.value || "",
      page,
      message: error?.message || null,
      stack: error?.stack || null,
      error,
    });
    marketplaceProviderResults = [];
    marketplaceProviderOffset = 0;
    marketplaceProviderHasMore = false;
    if (isCurseForgeApiKeyRequiredError(error)) {
      marketplaceProviderError = {
        title: "CurseForge API key required",
        message: "Save your CurseForge API key in Settings to browse and install CurseForge modpacks.",
        action: "open-settings",
      };
      setMarketplaceProviderStatus("CurseForge API key required", "error");
      showToast("CurseForge API key required", "warning");
    } else {
      marketplaceProviderError = {
        title: "Provider unavailable",
        message: "Marketplace provider results could not be loaded. Check the developer console for diagnostics.",
      };
      setMarketplaceProviderStatus("Provider unavailable", "error");
      showToast("Provider unavailable", "warning");
    }
    renderMarketplaceTemplates();
  } finally {
    if (requestId === marketplaceProviderRequestId) {
      marketplaceProviderRequestInFlight = false;
      if (marketplaceLoading) {
        marketplaceLoading.hidden = true;
      }
      renderMarketplaceProviderControls();
    }
  }
}

function setMarketplaceInstallState(label, status = "ready") {
  if (marketplaceInstallState) {
    marketplaceInstallState.textContent = label;
    marketplaceInstallState.dataset.status = status;
  }
}

function isMinecraftMarketplaceTemplate(template) {
  return template?.category === "Minecraft" || template?.game === "minecraft" || template?.type === "modpack";
}

function getMarketplaceProvider(template) {
  return String(template?.provider || "anxhub").trim().toLowerCase() || "anxhub";
}

function isProviderMarketplaceTemplate(template) {
  return ["modrinth", "curseforge"].includes(getMarketplaceProvider(template)) &&
    Boolean(template?.providerProjectId || template?.projectId) &&
    !["steamcmd-native", "archive-download", "direct-download", "java-runtime", "docker-image"].includes(String(template?.installerType || "").toLowerCase());
}

function formatMarketplaceProviderLabel(template) {
  const provider = getMarketplaceProvider(template);
  if (provider === "modrinth") return "Modrinth";
  if (provider === "curseforge") return "CurseForge";
  return "AnxOS";
}

function formatMarketplaceLoaderLabel(template) {
  return String(template?.loader || template?.serverType || template?.instanceType || "").replace(/^minecraft-/i, "") || "";
}

const MARKETPLACE_DEPENDENCY_LABELS = {
  java: "Java runtime",
  "dotnet-runtime": ".NET runtime",
  steamcmd: "SteamCMD",
  docker: "Docker",
  nodejs: "Node.js",
  python: "Python",
  unzip: "Unzip",
  tar: "tar",
  xz: "XZ tools",
  curl: "curl",
  wine: "Wine",
};

const MARKETPLACE_DEPENDENCY_REASONS = {
  java: "Required by Minecraft servers, Java applications, and Java-based installers.",
  "dotnet-runtime": "Required by .NET-based servers such as TShock.",
  steamcmd: "Required by Steam dedicated server templates.",
  docker: "Required by Docker-backed templates.",
  nodejs: "Required by Node.js app and bot templates.",
  python: "Required by Python app and bot templates.",
  unzip: "Required to extract ZIP-based server archives.",
  tar: "Required to extract tar archives and nested Linux server payloads.",
  xz: "Required to extract .tar.xz archives.",
  curl: "Required by templates that fetch external runtime assets.",
  wine: "Required by Windows-only server runtimes running on Linux.",
};

function normalizeMarketplaceDependencyId(id) {
  const value = String(id || "").trim().toLowerCase();
  return /^[a-z][a-z0-9-]{1,63}$/.test(value) ? value : "";
}

function uniqueMarketplaceValues(values = []) {
  const seen = new Set();
  return values.filter((value) => {
    const key = String(value || "").trim();
    if (!key || seen.has(key)) return false;
    seen.add(key);
    return true;
  });
}

function getMarketplaceTemplateDependencyIds(template = {}) {
  const ids = [];
  const push = (value) => {
    if (Array.isArray(value)) {
      value.forEach(push);
      return;
    }
    if (typeof value === "object" && value !== null) {
      push(value.id || value.dependencyId || value.command);
      return;
    }
    const normalized = normalizeMarketplaceDependencyId(value);
    if (normalized) ids.push(normalized);
  };

  push(template.hostDependencies);
  push(template.dependencies?.host);
  push(template.runtimeDependencies);
  const installerType = String(template.installerType || template.installer?.type || template.downloadSource?.type || "").toLowerCase();
  const runtime = String(template.runtime || template.startupType || template.instanceType || "").toLowerCase();
  const category = String(template.category || "").toLowerCase();
  if (category === "minecraft" || runtime.includes("java") || template.startupType === "java-jar") ids.push("java");
  if (runtime.includes("steamcmd") || installerType.includes("steamcmd") || template.downloadSource?.type === "steamcmd") ids.push("steamcmd");
  if (runtime.includes("docker") || template.startupType === "docker-image" || template.runtime === "docker") ids.push("docker");
  if (template.instanceType === "node-app") ids.push("nodejs");
  if (template.instanceType === "python-app") ids.push("python");
  if (template.installer?.type === "archive" || installerType.includes("archive")) {
    ids.push("unzip", "tar");
    const archiveName = String(template.installer?.archive || template.downloadSource?.fileName || "").toLowerCase();
    if (archiveName.endsWith(".xz") || archiveName.endsWith(".tar.xz")) ids.push("xz");
  }
  (Array.isArray(template.startup?.requiredCommands) ? template.startup.requiredCommands : []).forEach((command) => {
    const dependencyId = {
      java: "java",
      dotnet: "dotnet-runtime",
      steamcmd: "steamcmd",
      docker: "docker",
      node: "nodejs",
      nodejs: "nodejs",
      python: "python",
      python3: "python",
      unzip: "unzip",
      tar: "tar",
      xz: "xz",
      curl: "curl",
      wine: "wine",
    }[String(command || "").trim().toLowerCase()];
    if (dependencyId) ids.push(dependencyId);
  });
  return uniqueMarketplaceValues(ids);
}

function getMarketplaceTemplateInstances(template = {}) {
  const templateId = template?.id || "";
  if (!templateId) return [];
  return getInstances().filter((instance) => {
    const instanceTemplateId = instance?.templateId || instance?.metadata?.templateId || instance?.marketplace?.templateId;
    return instanceTemplateId === templateId;
  });
}

function getMarketplaceLocalInstallRecord(template = {}) {
  const templateId = template?.id || "";
  if (!templateId) return null;
  return marketplaceLocalDownloadEntries.find((entry) => entry.templateId === templateId) || null;
}

function getMarketplaceStateForTemplate(template = {}) {
  const instances = getMarketplaceTemplateInstances(template);
  const activeOperation = activeMarketplaceOperationId ? operationsState.items.get(activeMarketplaceOperationId) : null;
  const localRecord = getMarketplaceLocalInstallRecord(template);
  if (template.comingSoon || template.disabled) {
    return { label: "Unsupported", tone: "planned", action: "Unavailable", disabled: true, instances };
  }
  if (activeOperation && marketplaceSelectedTemplateId === template.id) {
    if (activeOperation.status === "waiting") return { label: "Recovery available", tone: "warning", action: "Resume", instances, operation: activeOperation };
    if (activeOperation.status === "failed") return { label: "Failed", tone: "critical", action: "Retry", instances, operation: activeOperation };
    return { label: String(activeOperation.step || "").toLowerCase().includes("dependencies") ? "Preparing dependencies" : "Installing", tone: "planned", action: "Installing", disabled: true, instances, operation: activeOperation };
  }
  if (localRecord?.status === "waiting") {
    return { label: "Recovery available", tone: "warning", action: "Review recovery", instances };
  }
  if (localRecord?.status === "failed") {
    return { label: "Failed", tone: "critical", action: "Retry", instances };
  }
  if (instances.some((instance) => getInstanceStateClass(instance.state) === "failed")) {
    return { label: "Failed", tone: "critical", action: "Open instance", instances };
  }
  if (instances.some(isInstanceRunning)) {
    return { label: "Running", tone: "ok", action: "Open instance", instances };
  }
  if (instances.length > 0) {
    return { label: "Installed", tone: "ok", action: "Open instance", instances };
  }
  return { label: "Available", tone: "planned", action: "Install", instances };
}

function formatMarketplaceSelectedNodeLabel() {
  const selected = getSelectedNode();
  return selected?.displayName || selected?.hostname || getSelectedNodeId() || "Selected node";
}

function getMarketplaceCompatibilityItems(template = {}) {
  const compatibility = template.compatibility && typeof template.compatibility === "object" ? template.compatibility : {};
  const items = [];
  if (template.comingSoon || template.disabled) {
    items.push({ label: "Availability", value: template.comingSoonMessage || template.unavailableReason || "This template is not installable yet.", state: "unsupported" });
  } else {
    items.push({ label: "Compatibility", value: Object.keys(compatibility).length ? "Declared by template metadata" : "Compatibility unknown", state: Object.keys(compatibility).length ? "ready" : "unknown" });
  }
  const platforms = uniqueMarketplaceValues([
    ...(Array.isArray(compatibility.platforms) ? compatibility.platforms : []),
    ...(Array.isArray(compatibility.operatingSystems) ? compatibility.operatingSystems : []),
    ...(Array.isArray(compatibility.os) ? compatibility.os : []),
  ]);
  if (platforms.length) items.push({ label: "Operating systems", value: platforms.join(", "), state: "ready" });
  const architectures = uniqueMarketplaceValues([
    ...(Array.isArray(compatibility.architectures) ? compatibility.architectures : []),
    ...(Array.isArray(compatibility.arch) ? compatibility.arch : []),
  ]);
  if (architectures.length) items.push({ label: "Architectures", value: architectures.join(", "), state: "ready" });
  if (Array.isArray(compatibility.requires) && compatibility.requires.length) {
    items.push({ label: "Required services", value: compatibility.requires.join(", "), state: "ready" });
  }
  if (template.manualStartRequired) {
    items.push({ label: "Start behavior", value: template.manualStartMessage || "Manual configuration is required before startup.", state: "warning" });
  }
  if (template.installMetadata?.notes) {
    items.push({ label: "Known limitation", value: template.installMetadata.notes, state: "warning" });
  }
  if (template.verified === true) items.push({ label: "Verification", value: "Verified AnxOS template metadata", state: "ready" });
  if (template.experimental === true) items.push({ label: "Release channel", value: "Experimental", state: "warning" });
  return items;
}

function getMarketplaceRequirementItems(template = {}) {
  const items = getMarketplaceTemplateDependencyIds(template).map((id) => ({
    label: MARKETPLACE_DEPENDENCY_LABELS[id] || id,
    value: MARKETPLACE_DEPENDENCY_REASONS[id] || "Required by this Marketplace template.",
    state: "unknown",
    meta: id,
  }));
  if (template.runtime || template.startupType || template.instanceType) {
    items.unshift({
      label: "Runtime",
      value: [template.runtime, template.startupType, template.instanceType].filter(Boolean).join(" · "),
      state: "ready",
    });
  }
  if (Array.isArray(template.defaultPorts) && template.defaultPorts.length > 0) {
    items.push({ label: "Default ports", value: template.defaultPorts.join(", "), state: "ready" });
  }
  if (template.defaultRam) {
    items.push({ label: "Memory default", value: template.defaultRam, state: "ready" });
  }
  if (template.installMetadata?.source) {
    items.push({ label: "Install source", value: template.installMetadata.source, state: "ready" });
  }
  if (template.updateCheck?.type) {
    items.push({ label: "Update metadata", value: `${template.updateCheck.type} check declared. Updates are handled by the instance workflow when supported.`, state: "unknown" });
  }
  if (template.installerType) {
    items.push({ label: "Installer", value: template.installerType, state: template.installerType === "no-install" ? "unsupported" : "ready" });
  }
  return items;
}

function createMarketplaceSummarySection(titleText, items = []) {
  const section = document.createElement("section");
  section.className = "marketplace-summary-section";
  const title = createTextElement("strong", titleText);
  section.append(title);
  const list = document.createElement("div");
  list.className = "marketplace-summary-list";
  if (!items.length) {
    list.append(createTextElement("span", "No declared metadata.", "marketplace-summary-empty"));
  }
  items.forEach((item) => {
    const row = document.createElement("div");
    row.className = "marketplace-summary-item";
    row.dataset.state = item.state || "unknown";
    const label = createTextElement("span", item.label || "Item");
    const value = createTextElement("small", item.value || "Unavailable");
    row.append(label, value);
    if (item.meta) {
      const meta = createTextElement("code", item.meta);
      row.append(meta);
    }
    list.append(row);
  });
  section.append(list);
  return section;
}

function renderMarketplaceInstallSummary(template) {
  if (!marketplaceInstallSummary) return;
  marketplaceInstallSummary.replaceChildren();
  if (!template) return;

  const state = getMarketplaceStateForTemplate(template);
  const overview = document.createElement("section");
  overview.className = "marketplace-summary-section";
  overview.append(createTextElement("strong", "Install review"));
  const details = document.createElement("div");
  details.className = "marketplace-summary-details";
  [
    ["Template", template.displayName || template.id || "Unknown"],
    ["Selected node", formatMarketplaceSelectedNodeLabel()],
    ["Version", template.version ? `Template v${template.version}` : "Version metadata unavailable"],
    ["Instance state", state.instances.length ? `${state.instances.length} installed · ${state.label}` : state.label],
    ["Install path", "Managed by the selected Agent instance data root"],
    ["Data preservation", "Uninstall and backup behavior are managed from the Instances and Backups workspaces."],
  ].forEach(([label, value]) => appendDetailPair(details, label, value, { valueTag: "small" }));
  overview.append(details);
  marketplaceInstallSummary.append(
    overview,
    createMarketplaceSummarySection("Runtime requirements", getMarketplaceRequirementItems(template)),
    createMarketplaceSummarySection("Compatibility", getMarketplaceCompatibilityItems(template)),
  );
}

function openMarketplaceInstance(instanceId) {
  if (!instanceId) return;
  showPage("instances");
  selectInstance(instanceId, { refreshMetrics: true });
}

function reviewMarketplaceRecovery(template) {
  marketplaceSelectedTemplateId = template?.id || marketplaceSelectedTemplateId;
  renderMarketplaceRecoveryActions(template);
  setMarketplaceMessage("Review the recovery actions and Download Manager entry for this Marketplace install.", "warning");
  marketplaceManualRecovery?.scrollIntoView?.({ block: "nearest" });
}

function renderMarketplaceRecoveryActions(template, normalizedError = null) {
  if (!marketplaceRecoveryActions) return;
  marketplaceRecoveryActions.replaceChildren();
  const state = template ? getMarketplaceStateForTemplate(template) : null;
  const canShow = Boolean(template && (normalizedError || state?.instances?.length || activeMarketplaceOperationId));
  marketplaceRecoveryActions.hidden = !canShow;
  if (!canShow) return;

  const heading = createTextElement("strong", normalizedError ? "Recovery actions" : "Related actions");
  marketplaceRecoveryActions.append(heading);
  const actions = document.createElement("div");
  actions.className = "ssh-connection-actions";

  const firstInstance = state.instances?.[0] || null;
  if (firstInstance) {
    const openInstance = document.createElement("button");
    openInstance.type = "button";
    openInstance.className = "inline-action";
    openInstance.textContent = "Open Instance";
    openInstance.addEventListener("click", () => openMarketplaceInstance(firstInstance.id));
    actions.append(openInstance);
  }

  const relatedOperationId = activeMarketplaceOperationId || state?.operation?.id || null;
  if (relatedOperationId) {
    const openOperations = document.createElement("button");
    openOperations.type = "button";
    openOperations.className = "inline-action";
    openOperations.textContent = "Open Operations";
    openOperations.addEventListener("click", () => {
      operationsState.selectedId = relatedOperationId;
      renderOperationsCenter();
      showPage("operations");
    });
    actions.append(openOperations);
  }

  if (normalizedError?.code === "DEPENDENCIES_REQUIRED" && getDesktopApiState().hasDependencies) {
    const recheck = document.createElement("button");
    recheck.type = "button";
    recheck.className = "inline-action";
    recheck.textContent = "Open Dependency Check";
    recheck.addEventListener("click", () => showPage("agent-control"));
    actions.append(recheck);
  }

  if (normalizedError?.details?.retryable !== false && !marketplaceInstallInFlight && template && !template.disabled && !template.comingSoon) {
    const retry = document.createElement("button");
    retry.type = "button";
    retry.className = "inline-action";
    retry.textContent = "Retry Install";
    retry.addEventListener("click", () => openMarketplaceWizard(template.id));
    actions.append(retry);
  }

  if (!actions.children.length) {
    actions.append(createTextElement("span", "No safe recovery action is available for this state.", "settings-note"));
  }
  marketplaceRecoveryActions.append(actions);
}

const MARKETPLACE_SERVER_RUNTIME_OPTIONS = [
  { value: "Vanilla", aliases: ["vanilla", "minecraft", "mojang"] },
  { value: "Paper", aliases: ["paper", "papermc", "minecraft-paper"] },
  { value: "Purpur", aliases: ["purpur", "minecraft-purpur"] },
  { value: "Fabric", aliases: ["fabric", "fabric-loader", "minecraft-fabric", "4"] },
  { value: "Quilt", aliases: ["quilt", "quilt-loader", "minecraft-quilt", "5"] },
  { value: "Forge", aliases: ["forge", "minecraft-forge", "1"] },
  { value: "NeoForge", aliases: ["neoforge", "neo forge", "neo-forge", "minecraft-neoforge", "6"] },
];

function normalizeMarketplaceServerRuntime(value) {
  const target = String(value || "").trim().toLowerCase();
  if (!target) return "";
  return MARKETPLACE_SERVER_RUNTIME_OPTIONS.find((runtime) => (
    runtime.value.toLowerCase() === target ||
    runtime.aliases.includes(target)
  ))?.value || "";
}

function getMarketplaceServerTypeOptionValue(value, fallback = "Vanilla") {
  const normalized = normalizeMarketplaceServerRuntime(value);
  const options = [...getMarketplaceField("serverType")?.options || []];
  return options.find((option) => option.value === normalized)?.value || fallback;
}

function collectMarketplaceRuntimeCandidates(source = {}) {
  const candidates = [];
  const push = (value) => {
    if (Array.isArray(value)) {
      value.forEach(push);
      return;
    }
    if (value !== undefined && value !== null && value !== "") {
      candidates.push(value);
    }
  };
  push(source.serverRuntime);
  push(source.serverRuntimes);
  push(source.runtime);
  push(source.runtimes);
  push(source.loader);
  push(source.loaders);
  push(source.modLoader);
  push(source.modLoaders);
  push(source.serverType);
  push(source.categories);
  push(source.gameVersions);
  if (source.id && String(source.id).startsWith("minecraft-")) {
    push(String(source.id).replace(/^minecraft-/, ""));
  }
  return candidates;
}

function getMarketplaceRuntimeOptions(source = {}) {
  const seen = new Set();
  const runtimes = collectMarketplaceRuntimeCandidates(source)
    .map(normalizeMarketplaceServerRuntime)
    .filter(Boolean)
    .filter((runtime) => {
      if (seen.has(runtime)) return false;
      seen.add(runtime);
      return true;
    });
  if (runtimes.length) {
    return { detected: true, runtimes };
  }
  return { detected: false, runtimes: MARKETPLACE_SERVER_RUNTIME_OPTIONS.map((runtime) => runtime.value) };
}

function configureMarketplaceRuntimeField(template, source = template) {
  const serverTypeField = getMarketplaceField("serverType");
  if (!serverTypeField) return { detected: false, runtimes: ["Vanilla"] };
  const { detected, runtimes } = getMarketplaceRuntimeOptions(source);
  serverTypeField.replaceChildren(...runtimes.map((runtime) => {
    const option = document.createElement("option");
    option.value = runtime;
    option.textContent = runtime;
    return option;
  }));
  serverTypeField.value = runtimes[0] || "Vanilla";
  serverTypeField.disabled = !isMinecraftMarketplaceTemplate(template) || (detected && runtimes.length <= 1);
  serverTypeField.dataset.runtimeDetected = detected ? "true" : "false";
  return { detected, runtimes };
}

function normalizeProviderLoader(project = {}) {
  const loaders = Array.isArray(project.loaders) ? project.loaders : [];
  return loaders.map(normalizeMarketplaceServerRuntime).find((loader) => ["Fabric", "Forge", "NeoForge", "Quilt"].includes(loader))?.toLowerCase() || "";
}

function normalizeProviderMinecraftVersion(project = {}) {
  const versions = Array.isArray(project.minecraftVersions) ? project.minecraftVersions : [];
  return versions.find((version) => /^1\.\d+(?:\.\d+)?$/.test(String(version))) || versions[0] || "";
}

function buildProviderMarketplaceTemplate(project = {}) {
  const provider = getMarketplaceProvider(project);
  const providerProjectId = project.providerProjectId || project.id || project.slug;
  const id = `${provider}-${providerProjectId}`;
  return {
    id,
    displayName: project.name || project.title || project.slug || providerProjectId,
    description: project.description || "Provider modpack.",
    icon: project.iconUrl ? "" : provider === "curseforge" ? "CF" : "MR",
    iconUrl: project.iconUrl || "",
    author: project.author || project.authors || provider,
    version: "provider",
    category: "Modpacks",
    type: "modpack",
    game: "minecraft",
    provider,
    providerProjectId,
    minecraftVersion: normalizeProviderMinecraftVersion(project),
    loader: normalizeProviderLoader(project),
    loaders: Array.isArray(project.loaders) ? project.loaders : [],
    minecraftVersions: Array.isArray(project.minecraftVersions) ? project.minecraftVersions : [],
    downloads: project.downloads || project.downloadCount || 0,
    updatedAt: project.updatedAt || project.dateModified || "",
    serverCapable: true,
    defaultRam: "4G",
    defaultPorts: [25565],
  };
}

function registerProviderMarketplaceTemplate(project = {}) {
  const template = buildProviderMarketplaceTemplate(project);
  marketplaceProviderTemplates.set(template.id, template);
  return template;
}

function formatProviderDownloads(value) {
  const count = Number(value) || 0;
  if (count >= 1000000) return `${(count / 1000000).toFixed(1)}M`;
  if (count >= 1000) return `${Math.round(count / 1000)}K`;
  return count ? String(count) : "0";
}

function setMarketplaceProviderStatus(message, tone = "muted") {
  if (!marketplaceProviderStatus) {
    return;
  }
  marketplaceProviderStatus.textContent = message;
  marketplaceProviderStatus.dataset.tone = tone;
}

function renderMarketplaceProviderControls() {
  marketplaceProviderBrowser?.toggleAttribute("hidden", !isMarketplaceProviderSectionVisible());
  marketplaceLoadMoreButton?.toggleAttribute("hidden", !isMarketplaceProviderBrowserActive() || !marketplaceProviderHasMore);
  marketplaceProviderTabs?.querySelectorAll("[data-marketplace-provider]").forEach((button) => {
    button.classList.toggle("is-active", button.dataset.marketplaceProvider === marketplaceProviderActive);
  });
  marketplaceProviderModes?.querySelectorAll("[data-marketplace-provider-mode]").forEach((button) => {
    button.classList.toggle("is-active", button.dataset.marketplaceProviderMode === marketplaceProviderMode);
  });
  if (marketplaceLoadMoreButton) {
    marketplaceLoadMoreButton.disabled = marketplaceProviderRequestInFlight;
  }
}

function getMarketplaceProviderQueryPayload({ reset = false } = {}) {
  return {
    provider: marketplaceProviderActive,
    mode: marketplaceProviderMode,
    query: marketplaceSearchInput?.value || "",
    minecraftVersion: marketplaceProviderMinecraftVersion?.value || "",
    loader: marketplaceProviderLoader?.value || "",
    offset: reset ? 0 : marketplaceProviderOffset,
    limit: MARKETPLACE_PROVIDER_PAGE_SIZE,
  };
}

function resetMarketplaceVersionPicker() {
  marketplaceVersionCatalog = null;
  marketplaceVersionFilter = "recommended";
  marketplaceVersionQuery = "";
  marketplaceVersionOpen = false;
  marketplaceVersionRenderLimit = 80;
  marketplaceVersionRequestId += 1;
  if (marketplaceVersionPanel) {
    marketplaceVersionPanel.hidden = true;
  }
  if (marketplaceVersionToggle) {
    marketplaceVersionToggle.disabled = false;
    marketplaceVersionToggle.textContent = "Browse";
  }
  if (marketplaceVersionSearch) {
    marketplaceVersionSearch.value = "";
  }
  if (marketplaceVersionStatus) {
    marketplaceVersionStatus.textContent = "Select a Minecraft template to browse versions.";
    marketplaceVersionStatus.dataset.tone = "muted";
  }
  marketplaceVersionTabs?.replaceChildren();
  marketplaceVersionList?.replaceChildren();
}

function setMarketplaceVersionPanelOpen(open) {
  marketplaceVersionOpen = Boolean(open);
  if (marketplaceVersionPanel) {
    marketplaceVersionPanel.hidden = !marketplaceVersionOpen;
  }
  if (marketplaceVersionToggle) {
    marketplaceVersionToggle.textContent = marketplaceVersionOpen ? "Hide" : "Browse";
  }
}

function setMarketplaceVersionStatus(message, tone = "muted") {
  if (!marketplaceVersionStatus) {
    return;
  }
  marketplaceVersionStatus.textContent = message;
  marketplaceVersionStatus.dataset.tone = tone;
}

function getMarketplaceVersionEntries() {
  if (!marketplaceVersionCatalog) {
    return [];
  }
  const latest = marketplaceVersionCatalog.latest?.id
    ? [{
      id: "latest",
      label: `Latest Stable — ${marketplaceVersionCatalog.latest.id}`,
      category: "recommended",
      recommended: true,
      details: "Shortcut that resolves during install",
    }]
    : [{
      id: "latest",
      label: "Latest Stable",
      category: "recommended",
      recommended: true,
      details: "Shortcut that resolves during install",
    }];
  const recommended = Array.isArray(marketplaceVersionCatalog.recommended) ? marketplaceVersionCatalog.recommended : [];
  const versions = Array.isArray(marketplaceVersionCatalog.versions) ? marketplaceVersionCatalog.versions : [];
  const query = marketplaceVersionQuery.trim().toLowerCase();
  const source = marketplaceVersionFilter === "recommended" && !query ? [...latest, ...recommended] : [...latest, ...versions];
  const seen = new Set();
  return source.filter((entry) => {
    const key = entry.id === "latest" ? "latest" : entry.id;
    if (!key || seen.has(key)) return false;
    seen.add(key);
    if (marketplaceVersionFilter !== "all" && marketplaceVersionFilter !== "recommended" && entry.category !== marketplaceVersionFilter) {
      return false;
    }
    if (!query) return true;
    return [
      entry.id,
      entry.label,
      entry.details,
      entry.loaderVersion,
      entry.softwareVersion,
      entry.type,
      entry.category,
    ].some((value) => String(value || "").toLowerCase().includes(query));
  });
}

function renderMarketplaceVersionTabs() {
  if (!marketplaceVersionTabs) {
    return;
  }
  marketplaceVersionTabs.replaceChildren();
  MARKETPLACE_VERSION_FILTERS.forEach((filter) => {
    const button = document.createElement("button");
    button.type = "button";
    button.className = "marketplace-version-tab";
    button.dataset.active = filter === marketplaceVersionFilter ? "true" : "false";
    button.textContent = MARKETPLACE_VERSION_FILTER_LABELS[filter] || filter;
    button.addEventListener("click", () => {
      marketplaceVersionFilter = filter;
      marketplaceVersionRenderLimit = 80;
      renderMarketplaceVersionTabs();
      renderMarketplaceVersionList();
    });
    marketplaceVersionTabs.append(button);
  });
}

function renderMarketplaceVersionList() {
  if (!marketplaceVersionList) {
    return;
  }
  marketplaceVersionList.replaceChildren();
  const entries = getMarketplaceVersionEntries();
  if (!marketplaceVersionCatalog) {
    const empty = document.createElement("div");
    empty.className = "marketplace-version-empty";
    empty.textContent = "Version catalog has not loaded yet.";
    marketplaceVersionList.append(empty);
    return;
  }
  if (!entries.length) {
    const empty = document.createElement("div");
    empty.className = "marketplace-version-empty";
    empty.textContent = "No versions match this filter.";
    marketplaceVersionList.append(empty);
    return;
  }

  const shown = entries.slice(0, marketplaceVersionRenderLimit);
  const template = findMarketplaceTemplate();
  const currentField = getMarketplaceField("version");
  const currentValue = String(isProviderMarketplaceTemplate(template)
    ? currentField?.dataset?.providerVersionId || ""
    : currentField?.value || "").trim();
  shown.forEach((entry) => {
    const option = document.createElement("button");
    option.type = "button";
    option.className = "marketplace-version-option";
    option.dataset.selected = currentValue === entry.id ? "true" : "false";
    option.title = entry.id === "latest" && marketplaceVersionCatalog.latest?.id
      ? `Use latest stable (${marketplaceVersionCatalog.latest.id})`
      : `Use ${entry.id}`;

    const main = document.createElement("span");
    main.className = "marketplace-version-option__main";
    main.textContent = entry.label || entry.id;

    const meta = document.createElement("span");
    meta.className = "marketplace-version-option__meta";
    meta.textContent = entry.details || entry.type || MARKETPLACE_VERSION_FILTER_LABELS[entry.category] || "";

    option.append(main, meta);
    option.addEventListener("click", () => {
      const template = findMarketplaceTemplate();
      const versionField = getMarketplaceField("version");
      if (versionField) {
        versionField.value = isProviderMarketplaceTemplate(template)
          ? entry.minecraftVersions?.[0] || template?.minecraftVersion || ""
          : entry.id;
        versionField.dataset.providerVersionId = isProviderMarketplaceTemplate(template) ? entry.id : "";
        versionField.dispatchEvent(new Event("input", { bubbles: true }));
        versionField.focus();
      }
      if (isMinecraftMarketplaceTemplate(template) && Array.isArray(entry.loaders) && entry.loaders.length > 0) {
        configureMarketplaceRuntimeField(template, { ...template, loaders: entry.loaders });
      }
      renderMarketplaceVersionList();
      setMarketplaceVersionPanelOpen(false);
    });
    marketplaceVersionList.append(option);
  });

  if (entries.length > shown.length) {
    const more = document.createElement("div");
    more.className = "marketplace-version-more";
    more.textContent = `Showing ${shown.length} of ${entries.length}. Scroll for more.`;
    marketplaceVersionList.append(more);
  }
}

function renderMarketplaceVersionPicker() {
  renderMarketplaceVersionTabs();
  renderMarketplaceVersionList();
}

async function loadMarketplaceVersions(template) {
  const desktopApiState = getDesktopApiState();
  if (!isMinecraftMarketplaceTemplate(template)) {
    resetMarketplaceVersionPicker();
    return;
  }
  marketplaceVersionRequestId += 1;
  const requestId = marketplaceVersionRequestId;
  marketplaceVersionCatalog = null;
  marketplaceVersionFilter = "recommended";
  marketplaceVersionQuery = "";
  marketplaceVersionRenderLimit = 80;
  if (marketplaceVersionSearch) {
    marketplaceVersionSearch.value = "";
  }
  setMarketplaceVersionPanelOpen(false);
  renderMarketplaceVersionPicker();

  if (!desktopApiState.hasMarketplaceVersions) {
    setMarketplaceVersionStatus("Version browser is unavailable in this build. Manual entry still works.", "warning");
    return;
  }

  setMarketplaceVersionStatus("Loading full provider version list...", "muted");
  if (marketplaceVersionToggle) {
    marketplaceVersionToggle.disabled = true;
  }
  try {
    const catalog = isProviderMarketplaceTemplate(template) && desktopApiState.hasMarketplaceProviderInstall
      ? await desktopApiState.api.marketplace.getProviderPackVersions({
        provider: getMarketplaceProvider(template),
        providerProjectId: template.providerProjectId,
        minecraftVersion: template.minecraftVersion || "",
        loader: template.loader || "",
      })
      : await desktopApiState.api.marketplace.getMinecraftVersions(template.id);
    if (requestId !== marketplaceVersionRequestId) {
      return;
    }
    marketplaceVersionCatalog = isProviderMarketplaceTemplate(template)
      ? {
        templateId: template.id,
        provider: getMarketplaceProvider(template),
        latest: catalog?.versions?.[0] ? { id: String(catalog.versions[0].id), label: catalog.versions[0].name || catalog.versions[0].fileName || String(catalog.versions[0].id) } : null,
        versions: (Array.isArray(catalog?.versions) ? catalog.versions : []).map((version) => ({
          id: String(version.id),
          label: version.name || version.versionNumber || version.fileName || String(version.id),
          details: [version.fileName, Array.isArray(version.minecraftVersions) ? version.minecraftVersions.slice(0, 3).join(", ") : "", Array.isArray(version.loaders) ? version.loaders.join(", ") : ""].filter(Boolean).join(" · "),
          category: "releases",
          minecraftVersions: version.minecraftVersions || [],
          loaders: version.loaders || [],
        })),
        recommended: [],
        filters: ["recommended", "releases", "all"],
      }
      : catalog;
    if (isProviderMarketplaceTemplate(template) && Array.isArray(marketplaceVersionCatalog?.versions) && marketplaceVersionCatalog.versions[0]?.loaders?.length) {
      configureMarketplaceRuntimeField(template, { ...template, loaders: marketplaceVersionCatalog.versions[0].loaders });
    }
    const count = Array.isArray(marketplaceVersionCatalog?.versions) ? marketplaceVersionCatalog.versions.length : 0;
    const latestText = marketplaceVersionCatalog?.latest?.id ? ` Latest Stable — ${marketplaceVersionCatalog.latest.id}.` : "";
    setMarketplaceVersionStatus(`${count} versions loaded.${latestText}`, "success");
    renderMarketplaceVersionPicker();
  } catch (error) {
    if (requestId !== marketplaceVersionRequestId) {
      return;
    }
    setMarketplaceVersionStatus(error?.message || "Could not load provider versions. Manual entry still works.", "warning");
  } finally {
    if (requestId === marketplaceVersionRequestId && marketplaceVersionToggle) {
      marketplaceVersionToggle.disabled = false;
    }
  }
}

function renderMarketplaceWizardSteps(template) {
  if (!marketplaceWizardSteps) {
    return;
  }

  const isMinecraft = isMinecraftMarketplaceTemplate(template);
  const steps = isMinecraft
    ? ["Server Name", "Version", "Server Runtime", "Memory", "Port", "Public Access", "Accept EULA"]
    : ["Name", "Storage Location", "Port", "Memory"];
  marketplaceWizardSteps.replaceChildren();
  steps.forEach((step, index) => {
    const item = document.createElement("span");
    item.textContent = `${index + 1}. ${step}`;
    marketplaceWizardSteps.append(item);
  });
}

function syncMarketplaceWizardFields(template) {
  const isMinecraft = isMinecraftMarketplaceTemplate(template);
  document.querySelectorAll("[data-marketplace-field-wrap]").forEach((wrapper) => {
    const field = wrapper.dataset.marketplaceFieldWrap;
    const shouldShow = isMinecraft
      ? ["version", "serverType", "playitTunnel", "acceptEula"].includes(field)
      : ["storageLocation"].includes(field);
    wrapper.hidden = !shouldShow;
  });
}

function openMarketplaceWizard(templateId) {
  if (marketplaceManualRecoveryState) {
    setMarketplaceMessage("Finish the manual download recovery before starting another Marketplace install.", "warning");
    showToast("Finish the manual download recovery first.");
    return;
  }
  const template = findMarketplaceTemplate(templateId);
  if (!template) {
    showToast("Template not found.");
    return;
  }
  if (template.comingSoon || template.disabled) {
    const message = template.comingSoonMessage || "This template is not ready yet.";
    setMarketplaceMessage(message, "warning");
    showToast(message, "info");
    return;
  }

  marketplaceSelectedTemplateId = template.id;
  if (marketplaceWizard) {
    marketplaceWizard.hidden = false;
  }

  if (marketplaceSelectedName) {
    marketplaceSelectedName.textContent = template.displayName || template.id;
  }
  if (marketplaceSelectedMeta) {
    marketplaceSelectedMeta.textContent = `${template.category || "Template"} · ${template.instanceType || "custom-command"} · ${template.startupType || "runtime"}`;
  }
  renderMarketplaceInstallSummary(template);
  renderMarketplaceRecoveryActions(template);

  const nameField = getMarketplaceField("name");
  const versionField = getMarketplaceField("version");
  const serverTypeField = getMarketplaceField("serverType");
  const storageField = getMarketplaceField("storageLocation");
  const memoryField = getMarketplaceField("memory");
  const portField = getMarketplaceField("port");
  const acceptEulaField = getMarketplaceField("acceptEula");
  const startField = getMarketplaceField("start");

  if (nameField) {
    nameField.value = template.displayName || "";
  }
  if (versionField) {
    versionField.value = template.minecraftVersion || template.gameVersion || "latest";
    versionField.dataset.providerVersionId = "";
  }
  if (serverTypeField) {
    if (isMinecraftMarketplaceTemplate(template)) {
      configureMarketplaceRuntimeField(template);
    } else {
      serverTypeField.replaceChildren();
      serverTypeField.value = "";
      serverTypeField.disabled = false;
      serverTypeField.dataset.runtimeDetected = "false";
    }
  }
  if (storageField) {
    storageField.value = "data";
  }
  if (memoryField) {
    memoryField.value = template.defaultRam || "1G";
  }
  if (portField) {
    portField.value = Array.isArray(template.defaultPorts) && template.defaultPorts.length > 0 ? String(template.defaultPorts[0]) : "";
    portField.title = getMarketplacePortHelpText();
    portField.setAttribute("aria-label", `${template.displayName || "Template"} primary port`);
    syncMarketplacePortValidity();
  }
  if (acceptEulaField) {
    acceptEulaField.checked = false;
  }
  if (startField) {
    startField.checked = !template.manualStartRequired;
  }

  syncMarketplaceWizardFields(template);
  renderMarketplaceWizardSteps(template);
  resetMarketplaceVersionPicker();
  if (template.category === "Minecraft") {
    loadMarketplaceVersions(template);
  }
  renderMarketplaceTemplates();
  if (marketplaceInstallButton) {
    marketplaceInstallButton.disabled = marketplaceInstallInFlight;
  }
  if (!marketplaceInstallInFlight) {
    renderMarketplaceProgress([]);
    setMarketplaceInstallState("Ready", "ready");
    if (isMinecraftMarketplaceTemplate(template) && serverTypeField?.dataset?.runtimeDetected !== "true") {
      setMarketplaceMessage("Server runtime could not be determined. Vanilla is selected; choose the correct runtime if this is a modpack.", "warning");
    } else {
      setMarketplaceMessage("Review the generated settings, then install.");
    }
  } else {
    setMarketplaceInstallState("Installing", "running");
    setMarketplaceMessage("Install already running. You can keep browsing, but wait for it to finish before starting another install.", "warning");
  }
}

function closeMarketplaceWizard() {
  marketplaceSelectedTemplateId = null;
  if (marketplaceWizard) {
    marketplaceWizard.hidden = true;
  }
  if (marketplaceInstallSummary) {
    marketplaceInstallSummary.replaceChildren();
  }
  renderMarketplaceRecoveryActions(null);
  if (marketplaceSelectedName) {
    marketplaceSelectedName.textContent = "Select a template";
  }
  if (marketplaceSelectedMeta) {
    marketplaceSelectedMeta.textContent = "Installable templates appear as cards.";
  }
  const serverTypeField = getMarketplaceField("serverType");
  if (serverTypeField) {
    serverTypeField.disabled = false;
  }
  resetMarketplaceVersionPicker();
  renderMarketplaceTemplates();
}

function collectMarketplaceInstallOptions() {
  const portValue = readMarketplaceWholeNumberField("port", { label: "Server port", min: 1, max: 65535, optional: true });
  const ports = Number.isInteger(portValue) ? [portValue] : [];
  const template = findMarketplaceTemplate();
  const isMinecraft = isMinecraftMarketplaceTemplate(template);
  const providerVersionId = getMarketplaceField("version")?.dataset?.providerVersionId || "";
  return {
    name: getMarketplaceField("name")?.value || "",
    version: getMarketplaceField("version")?.value || "",
    providerVersionId,
    serverType: isMinecraft ? getMarketplaceField("serverType")?.value || "" : "",
    storageLocation: getMarketplaceField("storageLocation")?.value || "data",
    memory: normalizeMemoryLimit(getMarketplaceField("memory")?.value || ""),
    port: ports[0] || undefined,
    serverPort: ports[0] || undefined,
    ports,
    playitTunnel: Boolean(getMarketplaceField("playitTunnel")?.checked),
    acceptEula: Boolean(getMarketplaceField("acceptEula")?.checked),
    start: Boolean(getMarketplaceField("start")?.checked),
  };
}

function renderMarketplaceProgress(steps = []) {
  if (!marketplaceProgress) {
    return;
  }

  marketplaceProgress.replaceChildren();
  if (!steps.length) {
    const empty = document.createElement("div");
    empty.className = "marketplace-progress-empty";
    empty.textContent = "Install progress will appear here.";
    marketplaceProgress.append(empty);
    return;
  }

  steps.forEach((step) => {
    const row = document.createElement("div");
    row.className = "marketplace-progress-step";
    row.dataset.status = step.status || "pending";
    const label = document.createElement("strong");
    label.textContent = step.label || "Step";
    const detail = document.createElement("span");
    detail.textContent = step.detail || step.status || "";
    row.append(label, detail);
    if (step.debug) {
      const debug = document.createElement("details");
      debug.className = "marketplace-progress-debug";
      const summary = document.createElement("summary");
      summary.textContent = "Technical details";
      const pre = document.createElement("pre");
      pre.textContent = step.debug;
      const copy = document.createElement("button");
      copy.type = "button";
      copy.className = "inline-action";
      copy.textContent = "Copy Error Details";
      copy.addEventListener("click", async () => {
        try {
          await navigator.clipboard.writeText(step.debug);
          showToast("Error details copied.");
        } catch {
          showToast("Could not copy error details.", "warning");
        }
      });
      debug.append(summary, copy, pre);
      row.append(debug);
    }
    marketplaceProgress.append(row);
  });
}

function marketplaceProgressEventToStep(event = {}) {
  const stageLabels = {
    resolving: "Resolving dependencies",
    downloading: "Downloading files",
    extracting: "Extracting overrides",
    writing: "Writing instance metadata",
    waiting: "Waiting for Manual Download",
    imported: "File Imported",
    resuming: "Resuming Installation",
    done: "Done",
    error: "Failed",
  };
  const status = event.stage === "done"
    ? "complete"
    : event.stage === "error"
      ? "failed"
      : event.stage === "waiting"
        ? "waiting"
        : event.stage === "imported"
          ? "complete"
          : "running";
  const count = event.total ? ` (${event.current || 0}/${event.total})` : "";
  const percent = event.percent ? ` · ${event.percent}%` : "";
  return {
    key: `${event.stage || "installing"}:${stageLabels[event.stage] || "Installing"}`,
    label: stageLabels[event.stage] || "Installing",
    status,
    detail: `${event.message || event.stage || "Working"}${count}${percent}`,
  };
}

function updateMarketplaceOperationFromEvent(event = {}) {
  if (!activeMarketplaceOperationId) return;
  const status = event.stage === "done"
    ? "completed"
    : event.stage === "error"
      ? "failed"
      : event.stage === "waiting"
        ? "waiting"
        : "running";
  updateOperation(activeMarketplaceOperationId, {
    status,
    percent: clampPercent(event.percent),
    step: event.message || event.stage || "Installing",
    error: status === "failed" ? event.message || "Marketplace install failed." : "",
  });
}

function collapseMarketplaceProgressSteps(steps = []) {
  const collapsed = [];
  const indexes = new Map();
  steps.forEach((step) => {
    const key = step.key || `${step.status || ""}:${step.label || ""}`;
    if (indexes.has(key)) {
      collapsed[indexes.get(key)] = { ...collapsed[indexes.get(key)], ...step };
      return;
    }
    indexes.set(key, collapsed.length);
    collapsed.push(step);
  });
  return collapsed;
}

function startMarketplaceInstallProgressListener() {
  const desktopApiState = getDesktopApiState();
  if (!desktopApiState.hasMarketplaceProviderInstall || unsubscribeMarketplaceInstallProgress) {
    return;
  }
  marketplaceInstallProgressEvents = [];
  unsubscribeMarketplaceInstallProgress = desktopApiState.api.marketplace.onInstallProgress((event) => {
    marketplaceInstallProgressEvents = [...marketplaceInstallProgressEvents, event].slice(-8);
    updateMarketplaceOperationFromEvent(event);
    scheduleMarketplaceProgressRender();
  });
}

function stopMarketplaceInstallProgressListener() {
  if (typeof unsubscribeMarketplaceInstallProgress === "function") {
    unsubscribeMarketplaceInstallProgress();
  }
  unsubscribeMarketplaceInstallProgress = null;
  flushMarketplaceProgressRender();
}

function scheduleMarketplaceProgressRender() {
  marketplacePendingProgressSteps = collapseMarketplaceProgressSteps(marketplaceInstallProgressEvents.map(marketplaceProgressEventToStep));
  if (marketplaceProgressRenderTimer) {
    return;
  }
  marketplaceProgressRenderTimer = window.setTimeout(() => {
    marketplaceProgressRenderTimer = null;
    flushMarketplaceProgressRender();
  }, 180);
}

function flushMarketplaceProgressRender() {
  if (marketplaceProgressRenderTimer) {
    window.clearTimeout(marketplaceProgressRenderTimer);
    marketplaceProgressRenderTimer = null;
  }
  if (!marketplacePendingProgressSteps) {
    return;
  }
  renderMarketplaceProgress(marketplacePendingProgressSteps);
  marketplacePendingProgressSteps = null;
}

function formatDownloadSpeed(bytesPerSecond) {
  return Number.isFinite(bytesPerSecond) && bytesPerSecond > 0 ? `${formatBytes(bytesPerSecond)}/s` : "Idle";
}

function normalizeMarketplaceError(error, fallback = "Template install failed.") {
  const helper = window.marketplaceErrorHelper;
  if (typeof helper?.normalizeMarketplaceError === "function") {
    return helper.normalizeMarketplaceError(error, { fallback });
  }

  const cleanMessage = getAgentErrorMessage(error, fallback);
  return {
    code: error?.payload?.error?.code || error?.code || "MARKETPLACE_INSTALL_FAILED",
    title: cleanMessage,
    body: cleanMessage,
    action: "Review the technical details, fix the reported install stage, then retry.",
    file: null,
    projectId: null,
    fileId: null,
    rawMessage: error?.message || "",
    cleanMessage,
    debug: error?.message || cleanMessage,
  };
}

function formatMarketplaceErrorMetadata(normalizedError) {
  return [
    normalizedError.file ? `File: ${normalizedError.file}` : "",
    normalizedError.projectId ? `projectId: ${normalizedError.projectId}` : "",
    normalizedError.fileId ? `fileId: ${normalizedError.fileId}` : "",
  ].filter(Boolean).join(" · ");
}

function formatMarketplaceManualRecoveryMetadata(manualDownload = {}) {
  return [
    manualDownload.fileName ? `Missing file: ${manualDownload.fileName}` : "",
    manualDownload.projectName ? `Mod: ${manualDownload.projectName}` : "",
    manualDownload.versionId ? `Version: ${manualDownload.versionId}` : "",
    manualDownload.providerName ? `Provider: ${manualDownload.providerName}` : "",
    manualDownload.projectId ? `projectId: ${manualDownload.projectId}` : "",
    manualDownload.fileId ? `fileId: ${manualDownload.fileId}` : "",
  ].filter(Boolean).join(" · ");
}

function buildMarketplaceManualRecoveryState(template, manualDownload = {}, options = {}) {
  const providerName = manualDownload.providerName || "Provider";
  return {
    templateName: template?.displayName || template?.name || template?.id || "Marketplace install",
    title: "Manual Download Required",
    subtitle: `Waiting for a required file from ${providerName}.`,
    body: "A required modpack file needs manual download.",
    reason: manualDownload.reason || manualDownload.suggestion || "This provider does not allow AnxOS to download one required file automatically.",
    fileText: manualDownload.fileName || "Unknown file",
    modText: manualDownload.projectName || "Unknown mod",
    versionText: manualDownload.versionId || "Unknown version",
    providerText: providerName,
    detailText: formatMarketplaceManualRecoveryMetadata(manualDownload),
    openLabel: manualDownload.providerName ? `Download from ${manualDownload.providerName}` : "Open Provider Page",
    importLabel: "Import Downloaded File",
    resumeLabel: manualDownload.canResume ? "Resume Installation" : "Resume Installation",
    badgeText: "Waiting",
    canOpenProviderPage: Boolean(manualDownload.downloadPageUrl || manualDownload.projectUrl || manualDownload.sessionId),
    canImportFile: Boolean(manualDownload.sessionId),
    canResumeManualInstall: Boolean(manualDownload.canResume),
    sessionId: manualDownload.sessionId || "",
    logs: [
      {
        at: new Date().toISOString(),
        level: "warning",
        step: options.code || "MANUAL_DOWNLOAD_REQUIRED",
        message: "Waiting for manual download.",
        body: JSON.stringify(manualDownload, null, 2),
      },
    ],
  };
}

function setMarketplaceManualRecoveryState(state = null) {
  marketplaceManualRecoveryState = state;
  if (marketplaceWizard) {
    marketplaceWizard.hidden = Boolean(state);
  }
  if (!marketplaceManualRecovery) {
    return;
  }
  marketplaceManualRecovery.hidden = !state;
  if (!state) {
    return;
  }

  if (marketplaceManualRecoveryTitle) {
    marketplaceManualRecoveryTitle.textContent = state.title || "Manual Download Required";
  }
  if (marketplaceManualRecoverySubtitle) {
    marketplaceManualRecoverySubtitle.textContent = state.subtitle || "";
  }
  if (marketplaceManualRecoveryBadge) {
    marketplaceManualRecoveryBadge.textContent = state.badgeText || "Waiting";
  }
  if (marketplaceManualRecoveryBody) {
    marketplaceManualRecoveryBody.textContent = state.body || "";
  }
  if (marketplaceManualRecoveryReason) {
    marketplaceManualRecoveryReason.textContent = state.reason ? `Reason: ${state.reason}` : "";
  }
  if (marketplaceManualRecoveryFile) {
    marketplaceManualRecoveryFile.textContent = state.fileText || "";
  }
  if (marketplaceManualRecoveryMod) {
    marketplaceManualRecoveryMod.textContent = state.modText || "";
  }
  if (marketplaceManualRecoveryVersion) {
    marketplaceManualRecoveryVersion.textContent = state.versionText || "";
  }
  if (marketplaceManualRecoveryProvider) {
    marketplaceManualRecoveryProvider.textContent = state.providerText || "";
  }
  if (marketplaceManualRecoveryDetail) {
    marketplaceManualRecoveryDetail.textContent = state.detailText || "";
  }
  if (marketplaceManualRecoveryLogs) {
    marketplaceManualRecoveryLogs.replaceChildren();
    (Array.isArray(state.logs) ? state.logs : []).forEach((entry) => {
      const line = document.createElement("pre");
      line.textContent = [
        entry.at,
        entry.level || "warning",
        entry.step,
        entry.message,
        entry.body ? `body=${entry.body}` : "",
      ].filter(Boolean).join(" | ");
      marketplaceManualRecoveryLogs.append(line);
    });
  }
  if (marketplaceManualRecoveryOpen) {
    marketplaceManualRecoveryOpen.hidden = !state.canOpenProviderPage;
    marketplaceManualRecoveryOpen.textContent = state.openLabel || "Open Provider Page";
    marketplaceManualRecoveryOpen.disabled = !state.canOpenProviderPage;
  }
  if (marketplaceManualRecoveryImport) {
    marketplaceManualRecoveryImport.hidden = !state.canImportFile;
    marketplaceManualRecoveryImport.textContent = state.importLabel || "Import Downloaded File";
    marketplaceManualRecoveryImport.disabled = !state.canImportFile;
  }
  if (marketplaceManualRecoveryResume) {
    marketplaceManualRecoveryResume.hidden = !state.canResumeManualInstall;
    marketplaceManualRecoveryResume.textContent = state.resumeLabel || "Resume Installation";
    marketplaceManualRecoveryResume.disabled = !state.canResumeManualInstall;
  }
}

function rememberFailedMarketplaceDownload(template, normalizedError) {
  marketplaceLocalDownloadEntries = [{
    id: `failed-${Date.now()}`,
    templateId: template?.id || "",
    name: template?.displayName || template?.name || template?.id || "Marketplace install",
    status: "failed",
    progress: 0,
    speedBytesPerSecond: 0,
    canCancel: false,
    canRetry: false,
    body: normalizedError.body,
    metadataText: formatMarketplaceErrorMetadata(normalizedError),
    actionText: normalizedError.action,
    logs: [
      {
        at: new Date().toISOString(),
        level: "error",
        step: normalizedError.code || "MARKETPLACE_INSTALL_FAILED",
        message: normalizedError.cleanMessage || normalizedError.title,
        body: normalizedError.debug || normalizedError.rawMessage || "",
      },
    ],
  }];
}

function rememberWaitingMarketplaceDownload(template, manualDownload = {}, options = {}) {
  const state = buildMarketplaceManualRecoveryState(template, manualDownload, options);
  setMarketplaceManualRecoveryState(state);
  marketplaceLocalDownloadEntries = [{
    id: manualDownload.sessionId || `waiting-${Date.now()}`,
    templateId: template?.id || "",
    name: state.templateName,
    status: "waiting",
    progress: 100,
    speedBytesPerSecond: 0,
    canCancel: false,
    canRetry: false,
    sessionId: manualDownload.sessionId || "",
    providerName: state.providerText,
    body: state.body,
    metadataText: state.detailText,
    actionText: "Download the required file from the official provider page, then import it to continue the installation.",
    canOpenProviderPage: state.canOpenProviderPage,
    canImportFile: state.canImportFile,
    canResumeManualInstall: state.canResumeManualInstall,
    logs: state.logs,
  }];
}

function rememberImportedMarketplaceDownload(template, manualDownload = {}, options = {}) {
  const state = buildMarketplaceManualRecoveryState(template, manualDownload, options);
  state.title = "File Imported";
  state.subtitle = "The required file is in place. Resume the installation to continue.";
  state.body = "File imported. Resume the installation to continue.";
  state.reason = manualDownload.suggestion || "The required file has been copied into the install directory.";
  state.badgeText = "Imported";
  state.canResumeManualInstall = true;
  state.logs = [
    {
      at: new Date().toISOString(),
      level: "info",
      step: "MANUAL_FILE_IMPORTED",
      message: "Manual file imported.",
      body: JSON.stringify(manualDownload, null, 2),
    },
  ];
  setMarketplaceManualRecoveryState(state);
  marketplaceLocalDownloadEntries = [{
    id: manualDownload.sessionId || `imported-${Date.now()}`,
    templateId: template?.id || "",
    name: state.templateName,
    status: "waiting",
    progress: 100,
    speedBytesPerSecond: 0,
    canCancel: false,
    canRetry: false,
    sessionId: manualDownload.sessionId || "",
    providerName: state.providerText,
    body: state.body,
    metadataText: state.detailText,
    actionText: "Resume the installation to continue.",
    canOpenProviderPage: state.canOpenProviderPage,
    canImportFile: false,
    canResumeManualInstall: true,
    logs: state.logs,
  }];
}

function renderMarketplaceDownloads(downloads = []) {
  if (!downloadList) {
    return;
  }

  const visibleDownloads = [...marketplaceLocalDownloadEntries, ...downloads]
    .filter((download) => !download.parentTaskId);
  downloadList.replaceChildren();
  if (!visibleDownloads.length) {
    const empty = document.createElement("div");
    empty.className = "docker-empty-state";
    const title = document.createElement("strong");
    title.textContent = "No downloads queued";
    const detail = document.createElement("span");
    detail.textContent = "Marketplace install progress, manual download prompts, and installer logs will appear here after you start an install.";
    empty.append(title, detail);
    downloadList.append(empty);
    return;
  }

  visibleDownloads.forEach((download) => {
    const item = document.createElement("article");
    item.className = "download-item";
    item.dataset.status = download.status || "queued";
    const header = document.createElement("div");
    header.className = "download-item__header";
    const name = document.createElement("strong");
    name.textContent = download.name || download.id;
    const status = document.createElement("span");
    status.className = "status-pill";
    status.textContent = download.status || "queued";
    header.append(name, status);

    const bar = document.createElement("div");
    bar.className = "download-progress";
    const fill = document.createElement("span");
    const rawProgress = Math.max(0, Math.min(Number(download.progress) || 0, 100));
    const renderedProgress = download.status === "failed" ? Math.min(rawProgress, 96) : rawProgress;
    fill.style.width = `${renderedProgress}%`;
    bar.append(fill);

    const meta = document.createElement("small");
    const eta = Number.isFinite(download.etaSeconds) && download.status !== "failed" ? ` · ETA ${formatDuration(download.etaSeconds)}` : "";
    const url = download.url ? ` · ${download.url}` : "";
    const stage = download.stage || "Preparing";
    const installer = download.installerType ? ` · ${download.installerType}` : "";
    const terminalState = ["failed", "cancelled", "complete"].includes(download.status) ? download.status : "";
    const speedText = terminalState ? "" : ` · ${formatDownloadSpeed(download.speedBytesPerSecond)}`;
    meta.textContent = download.body || `${stage}${installer} · ${download.progress || 0}%${speedText}${eta}${url}`;

    const metadata = document.createElement("small");
    metadata.textContent = download.metadataText || "";
    metadata.hidden = !download.metadataText;

    const actionText = document.createElement("small");
    actionText.textContent = download.actionText || "";
    actionText.hidden = !download.actionText;

    const logs = document.createElement("details");
    logs.className = "download-item__logs";
    const summary = document.createElement("summary");
    summary.textContent = download.installerType === "steamcmd-native" || /steamcmd/i.test(String(download.error || download.body || ""))
      ? "View installer logs"
      : "Logs";
    logs.append(summary);
    (Array.isArray(download.logs) ? download.logs : []).forEach((entry) => {
      const line = document.createElement("pre");
      line.textContent = [
        entry.at,
        entry.level || "info",
        entry.step,
        entry.message,
        entry.url ? `url=${entry.url}` : "",
        entry.responseUrl ? `responseUrl=${entry.responseUrl}` : "",
        entry.status ? `status=${entry.status}` : "",
        entry.causeCode ? `causeCode=${entry.causeCode}` : "",
        entry.networkCode ? `networkCode=${entry.networkCode}` : "",
        entry.exitCode !== null && entry.exitCode !== undefined ? `exitCode=${entry.exitCode}` : "",
        entry.failureReason ? `failureReason=${entry.failureReason}` : "",
        entry.workingDirectory ? `workingDirectory=${entry.workingDirectory}` : "",
        entry.resolvedInstallDirectory ? `installDirectory=${entry.resolvedInstallDirectory}` : "",
        entry.executablePath ? `executable=${entry.executablePath}` : "",
        entry.diskSpaceCheck ? `disk=${entry.diskSpaceCheck.status || "unknown"}` : "",
        entry.writePermissionCheck ? `write=${entry.writePermissionCheck.status || "unknown"}` : "",
        Array.isArray(entry.finalStdoutLines) && entry.finalStdoutLines.length ? `stdout=${entry.finalStdoutLines.join(" / ")}` : "",
        Array.isArray(entry.finalStderrLines) && entry.finalStderrLines.length ? `stderr=${entry.finalStderrLines.join(" / ")}` : "",
        entry.body ? `body=${entry.body}` : "",
      ].filter(Boolean).join(" | ");
      logs.append(line);
    });

    const actions = document.createElement("div");
    actions.className = "download-item__actions";
    if (download.canOpenProviderPage) {
      const openProvider = document.createElement("button");
      openProvider.type = "button";
      openProvider.className = "inline-action";
      openProvider.textContent = download.providerName ? `Open ${download.providerName}` : "Open Provider Page";
      openProvider.addEventListener("click", () => openMarketplaceManualDownloadPage(download.sessionId));
      actions.append(openProvider);
    }
    if (download.canImportFile) {
      const importFile = document.createElement("button");
      importFile.type = "button";
      importFile.className = "inline-action";
      importFile.textContent = "Import File";
      importFile.addEventListener("click", () => importMarketplaceManualDownloadFile(download.sessionId));
      actions.append(importFile);
    }
    if (download.canResumeManualInstall) {
      const resume = document.createElement("button");
      resume.type = "button";
      resume.className = "inline-action";
      resume.textContent = "Resume Installation";
      resume.addEventListener("click", () => resumeMarketplaceManualInstall(download.sessionId));
      actions.append(resume);
    }
    const cancel = document.createElement("button");
    cancel.type = "button";
    cancel.className = "inline-action";
    cancel.textContent = "Cancel";
    cancel.disabled = !download.canCancel;
    cancel.addEventListener("click", () => cancelMarketplaceDownload(download.id));
    const retry = document.createElement("button");
    retry.type = "button";
    retry.className = "inline-action";
    retry.textContent = "Retry";
    retry.disabled = !download.canRetry;
    retry.addEventListener("click", () => retryMarketplaceDownload(download.id));
    actions.append(cancel, retry);

    item.append(header, bar, meta, metadata, actionText, logs, actions);
    downloadList.append(item);
  });
}

async function refreshMarketplaceDownloads() {
  const desktopApiState = getDesktopApiState();
  if (!desktopApiState.hasMarketplace) {
    renderMarketplaceDownloads([]);
    return;
  }

  try {
    const payload = await desktopApiState.api.marketplace.getDownloads();
    renderMarketplaceDownloads(Array.isArray(payload?.downloads) ? payload.downloads : []);
  } catch {
    renderMarketplaceDownloads([]);
  }
}

async function cancelMarketplaceDownload(downloadId) {
  try {
    await getDesktopApiState().api.marketplace.cancelDownload(downloadId);
    await refreshMarketplaceDownloads();
  } catch (error) {
    showToast(error?.message || "Download cancel failed.");
  }
}

async function retryMarketplaceDownload(downloadId) {
  try {
    await getDesktopApiState().api.marketplace.retryDownload(downloadId);
    await refreshMarketplaceDownloads();
  } catch (error) {
    showToast(error?.message || "Download retry failed.");
  }
}

async function openMarketplaceManualDownloadPage(sessionId) {
  if (!sessionId) {
    return;
  }
  try {
    await getDesktopApiState().api.marketplace.openManualDownloadPage(sessionId);
  } catch (error) {
    const normalizedError = normalizeMarketplaceError(error, "Provider page could not be opened.");
    showToast(normalizedError.title);
  }
}

async function importMarketplaceManualDownloadFile(sessionId) {
  if (!sessionId) {
    return;
  }
  try {
    const result = await getDesktopApiState().api.marketplace.importManualDownloadFile(sessionId);
    if (result?.canceled) {
      return;
    }
    rememberImportedMarketplaceDownload(findMarketplaceTemplate(), result.manualDownload || {}, { code: "MANUAL_FILE_IMPORTED" });
    renderMarketplaceDownloads([]);
    setMarketplaceInstallState("Paused", "waiting");
    setMarketplaceMessage("File imported. Resume the installation from Download Manager.", "warning");
    showToast("File imported.");
  } catch (error) {
    const normalizedError = normalizeMarketplaceError(error, "File import failed.");
    showToast(normalizedError.title);
  }
}

async function resumeMarketplaceManualInstall(sessionId) {
  if (!sessionId) {
    return;
  }
  try {
    setMarketplaceInstallState("Installing", "running");
    setMarketplaceMessage("Resuming Marketplace install...");
    const result = await getDesktopApiState().api.marketplace.resumeManualInstall(sessionId);
    marketplaceLocalDownloadEntries = [];
    renderMarketplaceProgress(result?.progress || []);
    renderMarketplaceDownloads(result?.downloads || []);
    selectedInstanceId = result?.instance?.id || selectedInstanceId;
    forgetStaleInstanceId(selectedInstanceId);
    setMarketplaceManualRecoveryState(null);
    setMarketplaceInstallState("Complete", "complete");
    setMarketplaceMessage("Install complete. Opening the new instance.");
    showToast("Template installed.");
    showPage("instances");
    await refreshInstances();
  } catch (error) {
    const normalizedError = normalizeMarketplaceError(error, "Resume install failed.");
    setMarketplaceInstallState("Paused", "waiting");
    setMarketplaceMessage("Install is still waiting. See Download Manager.", "warning");
    showToast(normalizedError.title);
  }
}

function handleInstanceBackupAction(action) {
  const selectedInstance = findInstance();

  if (!selectedInstance) {
    showToast("Select an instance first.");
    return;
  }

  if (action === "backup-now") {
    createBackupForInstance(selectedInstance.id);
    return;
  } else if (action === "schedule") {
    configureBackupSchedule(selectedInstance.id);
    return;
  } else if (action === "history") {
    showToast("Opening shared backup history.");
  } else {
    showToast("This backup action is not available yet.");
    return;
  }

  showPage("backups");
}

function getSelectedBackup() {
  return backupsState.backups.find((backup) => backup.id === backupsState.selectedBackupId) || null;
}

function setBackupSummaryField(name, value) {
  backupSummaryFields.forEach((field) => {
    if (field.dataset.backupSummary === name) {
      field.textContent = value;
    }
  });
}

function setBackupStatusField(name, value) {
  backupStatusFields.forEach((field) => {
    if (field.dataset.backupStatus === name) {
      field.textContent = value;
    }
  });
}

function setBackupScheduleField(name, value) {
  backupScheduleFields.forEach((field) => {
    if (field.dataset.backupSchedule === name) {
      field.textContent = value;
    }
  });
}

function setBackupRestoreField(name, value) {
  backupRestoreFields.forEach((field) => {
    if (field.dataset.backupRestore === name) {
      field.textContent = value;
    }
  });
}

function getBackupsConnected() {
  return getDesktopApiState().hasBackups && (backupsState.connected || agentConnectionState === "connected");
}

function getBackupRootLabel() {
  return backupsState.root || backupsState.roots?.[0] || backupsState.summary?.root || "No backup root reported";
}

function getMostRecentBackup() {
  return backupsState.backups
    .slice()
    .sort((left, right) => String(right.createdAt || "").localeCompare(String(left.createdAt || "")))[0] || null;
}

function getRelevantBackupSchedule() {
  const schedules = Array.isArray(backupsState.schedules) ? backupsState.schedules : [];
  const selectedBackup = getSelectedBackup();
  const targetInstanceId = selectedBackup?.instanceId || selectedInstanceId || "";
  return schedules.find((schedule) => schedule.instanceId === targetInstanceId)
    || schedules.find((schedule) => schedule.enabled !== false)
    || schedules[0]
    || null;
}

function formatBackupScheduleSummary() {
  if (backupsState.scheduleSupported === false || !backupsState.schedules.length) {
    return "No schedule configured";
  }
  const enabledCount = backupsState.schedules.filter((schedule) => schedule.enabled !== false).length;
  if (enabledCount === 0) {
    return "No schedule configured";
  }
  return enabledCount === 1 ? "1 schedule configured" : `${enabledCount} schedules configured`;
}

function renderBackupSummary() {
  const connected = getBackupsConnected();
  const mostRecent = getMostRecentBackup();
  const totalBackups = Number.isFinite(backupsState.summary?.totalBackups)
    ? backupsState.summary.totalBackups
    : backupsState.backups.length;

  setBackupSummaryField("total", connected ? String(totalBackups) : "Unavailable");
  setBackupSummaryField("last", connected ? (mostRecent?.createdAt ? formatDateTime(mostRecent.createdAt) : "No backups yet") : "Unavailable");
  setBackupSummaryField("destination", connected ? getBackupRootLabel() : "Unavailable");
  setBackupSummaryField("schedule", connected ? formatBackupScheduleSummary() : "Unavailable");
}

function renderBackupSchedulePanel() {
  const connected = getBackupsConnected();
  const schedule = getRelevantBackupSchedule();
  const noScheduleText = connected ? "No schedule configured" : "Unavailable";

  setBackupStatusField("schedule", connected && schedule ? "Configured" : noScheduleText);
  setBackupScheduleField("frequency", schedule ? `Every ${schedule.intervalHours} hour(s) · ${schedule.type || "full"}` : noScheduleText);
  setBackupScheduleField("nextRun", schedule?.nextRunAt ? formatDateTime(schedule.nextRunAt) : noScheduleText);
  setBackupScheduleField(
    "retention",
    schedule ? `Keep last ${schedule.keepLast || "default"} · ${schedule.maxAgeDays || "default"} day max age` : noScheduleText,
  );
  setBackupScheduleField("targetPath", connected ? getBackupRootLabel() : "Unavailable");
}

function renderBackupRestorePanel() {
  const connected = getBackupsConnected();
  const selected = getSelectedBackup();

  setBackupStatusField("restore", connected ? (selected ? "Ready" : "Select a backup") : "Unavailable");
  if (!connected) {
    setBackupRestoreField("title", "Backup service unavailable");
    setBackupRestoreField("message", backupsState.error || "Agent backup state is unavailable.");
    return;
  }
  if (!selected) {
    setBackupRestoreField("title", "No backup selected");
    setBackupRestoreField("message", "Select a backup from Backup History to restore it.");
    return;
  }

  setBackupRestoreField("title", selected.name || selected.id);
  setBackupRestoreField(
    "message",
    `${selected.instanceId || "Unknown instance"} · ${selected.type || "full"} · ${formatBytes(Number(selected.size) || 0)} · ${formatDateTime(selected.createdAt)}`,
  );
}

function renderBackups() {
  if (!backupTableBody) {
    return;
  }

  const connected = getBackupsConnected();

  backupTableBody.replaceChildren();
  if (backupEmptyState) {
    backupEmptyState.hidden = backupRequestInFlight || backupsState.backups.length > 0;
  }
  if (backupEmptyMessage) {
    backupEmptyMessage.textContent = connected
      ? "Create a backup from an instance or configure backup paths to begin protecting server data."
      : backupsState.error || "Select a node with backup support, then refresh backup state.";
  }
  if (backupLoadingState) {
    backupLoadingState.hidden = !backupRequestInFlight;
  }

  backupsState.backups.forEach((backup) => {
    const row = document.createElement("tr");
    row.classList.toggle("is-selected", backup.id === backupsState.selectedBackupId);
    row.addEventListener("click", () => {
      backupsState.selectedBackupId = backup.id;
      renderBackups();
    });
    [backup.name || backup.id, backup.instanceId || "Unknown", formatBytes(Number(backup.size) || 0), formatDateTime(backup.createdAt), backup.status || backup.type || "complete"].forEach((value) => {
      const cell = document.createElement("td");
      cell.textContent = value;
      row.append(cell);
    });
    backupTableBody.append(row);
  });

  const selected = getSelectedBackup();
  setBackupStatusField("history", backupRequestInFlight ? "Loading" : connected ? "Connected" : "Unavailable");
  renderBackupSummary();
  renderBackupSchedulePanel();
  renderBackupRestorePanel();
  backupActionButtons.forEach((button) => {
    const action = button.dataset.backupAction;
    button.disabled = isNodeSwitching() || backupRequestInFlight || !getDesktopApiState().hasBackups || (["restore", "delete", "download"].includes(action) && !selected);
  });
}

async function refreshBackups() {
  const desktopApiState = getDesktopApiState();
  if (!desktopApiState.hasBackups) {
    backupsState = {
      ...backupsState,
      backups: [],
      selectedBackupId: null,
      root: null,
      roots: [],
      summary: null,
      schedules: [],
      scheduleSupported: false,
      connected: false,
      error: desktopApiState.hasBridge ? "Backup IPC bridge unavailable." : "Desktop preload bridge unavailable.",
    };
    renderBackups();
    return;
  }

  backupRequestInFlight = true;
  const requestContext = getNodeRequestContext("backups");
  renderBackups();
  try {
    const result = await desktopApiState.api.backups.list(getNodeScopedPayload(requestContext));
    let scheduleResult = { schedules: [] };
    let scheduleSupported = desktopApiState.hasBackupSchedules;
    if (desktopApiState.hasBackupSchedules) {
      try {
        scheduleResult = await desktopApiState.api.backups.listSchedules(getNodeScopedPayload(requestContext));
      } catch {
        scheduleSupported = false;
      }
    }
    if (!isNodeRequestCurrent(requestContext)) {
      return;
    }
    backupsState.backups = Array.isArray(result?.backups) ? result.backups : [];
    backupsState.root = result?.root || result?.diagnostics?.roots?.[0]?.path || null;
    backupsState.roots = Array.isArray(result?.roots) ? result.roots : [];
    backupsState.summary = result?.summary || null;
    backupsState.schedules = Array.isArray(scheduleResult?.schedules) ? scheduleResult.schedules : [];
    backupsState.scheduleSupported = scheduleSupported;
    backupsState.connected = true;
    backupsState.error = null;
    if (!getSelectedBackup()) {
      backupsState.selectedBackupId = backupsState.backups[0]?.id || null;
    }
  } catch (error) {
    if (!isNodeRequestCurrent(requestContext)) {
      return;
    }
    showToast(error?.message || "Backups could not be loaded.");
    backupsState = {
      ...backupsState,
      backups: [],
      selectedBackupId: null,
      root: null,
      roots: [],
      summary: null,
      schedules: [],
      connected: false,
      error: error?.message || "Backups could not be loaded.",
    };
  } finally {
    if (isNodeRequestCurrent(requestContext)) {
      backupRequestInFlight = false;
      renderBackups();
    }
  }
}

async function createBackupForInstance(instanceId = null) {
  const desktopApiState = getDesktopApiState();
  const requestContext = createNodeActionContext("backup-create");
  if (!desktopApiState.hasBackups) {
    showToast("Backup service is unavailable.");
    return;
  }

  const selectedInstance = instanceId ? findInstance(instanceId) : findInstance();
  const targetInstanceId = instanceId || selectedInstance?.id || window.prompt("Instance ID to back up", selectedInstanceId || "");
  if (!targetInstanceId) {
    return;
  }
  const type = window.confirm("Create a world-only backup? Choose Cancel for a full instance backup.") ? "world" : "full";
  backupRequestInFlight = true;
  renderBackups();
  try {
    if (!isNodeActionStillCurrent(requestContext)) return;
    await desktopApiState.api.backups.create({
      nodeId: requestContext.nodeId,
      instanceId: targetInstanceId,
      name: `${targetInstanceId} ${type} backup`,
      type,
      createdBy: securityState.user?.username || "local-user",
    });
    showToast("Backup created.");
    await refreshBackups();
  } catch (error) {
    showToast(error?.message || "Backup could not be created.");
  } finally {
    backupRequestInFlight = false;
    renderBackups();
  }
}

async function restoreSelectedBackup() {
  const selected = getSelectedBackup();
  const desktopApiState = getDesktopApiState();
  const requestContext = createNodeActionContext("backup-restore");
  if (!selected || !desktopApiState.hasBackups) {
    return;
  }
  if (!window.confirm(`Restore ${selected.name || selected.id}? The instance will be stopped and a safety snapshot will be created first.`)) {
    return;
  }
  try {
    const restart = window.confirm("Restart after restore?");
    if (!isNodeActionStillCurrent(requestContext)) return;
    await desktopApiState.api.backups.restore({ nodeId: requestContext.nodeId, backupId: selected.id, restart });
    showToast("Backup restored.");
    await refreshInstances();
    await refreshBackups();
  } catch (error) {
    showToast(error?.message || "Backup restore failed.");
  }
}

async function deleteSelectedBackup() {
  const selected = getSelectedBackup();
  const desktopApiState = getDesktopApiState();
  const requestContext = createNodeActionContext("backup-delete");
  if (!selected || !desktopApiState.hasBackups || !window.confirm(`Delete backup ${selected.name || selected.id}?`)) {
    return;
  }
  try {
    if (!isNodeActionStillCurrent(requestContext)) return;
    await desktopApiState.api.backups.delete(selected.id, getNodeScopedPayload(requestContext));
    showToast("Backup deleted.");
    backupsState.selectedBackupId = null;
    await refreshBackups();
  } catch (error) {
    if (/BACKUP_NOT_FOUND|already.*deleted|not found/i.test(String(error?.message || error || ""))) {
      showToast("Backup was already removed. Refreshed backup list.", "info");
      backupsState.selectedBackupId = null;
      await refreshBackups();
      return;
    }
    showToast(error?.message || "Backup delete failed.");
  }
}

async function downloadSelectedBackup() {
  const selected = getSelectedBackup();
  const desktopApiState = getDesktopApiState();
  const requestContext = createNodeActionContext("backup-download");
  if (!selected || !desktopApiState.hasBackups) {
    return;
  }
  try {
    if (!isNodeActionStillCurrent(requestContext)) return;
    const result = await desktopApiState.api.backups.download(selected.id, getNodeScopedPayload(requestContext));
    showToast(result?.canceled ? "Download canceled." : "Backup downloaded.");
  } catch (error) {
    showToast(error?.message || "Backup download failed.");
  }
}

async function importBackupForInstance() {
  const desktopApiState = getDesktopApiState();
  const requestContext = createNodeActionContext("backup-import");
  if (!desktopApiState.hasBackups) {
    return;
  }
  const instanceId = window.prompt("Instance ID for imported backup", selectedInstanceId || "");
  if (!instanceId) {
    return;
  }
  try {
    if (!isNodeActionStillCurrent(requestContext)) return;
    const result = await desktopApiState.api.backups.import({ nodeId: requestContext.nodeId, instanceId, createdBy: securityState.user?.username || "local-user" });
    showToast(result?.canceled ? "Import canceled." : "Backup imported.");
    await refreshBackups();
  } catch (error) {
    showToast(error?.message || "Backup import failed.");
  }
}

async function configureBackupSchedule(instanceId) {
  const desktopApiState = getDesktopApiState();
  const requestContext = createNodeActionContext("backup-schedule");
  if (!desktopApiState.hasBackupSchedules || !instanceId) {
    showToast("Backup scheduling is unavailable.");
    return;
  }
  const interval = window.prompt("Run backup every how many hours?", "24");
  if (!interval) {
    return;
  }
  const keepLast = window.prompt("Keep last how many backups?", "10") || "10";
  const maxAgeDays = window.prompt("Delete backups older than how many days?", "30") || "30";
  const type = window.confirm("Schedule world-only backups? Choose Cancel for full instance backups.") ? "world" : "full";
  try {
    if (!isNodeActionStillCurrent(requestContext)) return;
    await desktopApiState.api.backups.saveSchedule({
      nodeId: requestContext.nodeId,
      instanceId,
      intervalHours: Number.parseInt(interval, 10),
      keepLast: Number.parseInt(keepLast, 10),
      maxAgeDays: Number.parseInt(maxAgeDays, 10),
      type,
      enabled: true,
    });
    showToast("Backup schedule saved.");
    await refreshBackups();
  } catch (error) {
    showToast(error?.message || "Backup schedule could not be saved.");
  }
}

async function refreshMarketplace() {
  const desktopApiState = getDesktopApiState();
  if (!desktopApiState.hasMarketplace || marketplaceRequestInFlight) {
    if (!desktopApiState.hasMarketplace) {
      marketplaceCatalog = { categories: [], templates: [] };
      renderMarketplaceCategories();
      renderMarketplaceTemplates();
      setMarketplaceMessage("Marketplace bridge is unavailable in this build.", "error");
    }
    return;
  }

  setMarketplaceLoading(true);
  try {
    marketplaceCatalog = await desktopApiState.api.marketplace.listTemplates();
    renderMarketplaceCategories();
    renderMarketplaceTemplates();
    if (isMarketplaceProviderBrowserActive()) {
      loadMarketplaceProviderPacks({ reset: true });
    }
    setMarketplaceMessage("Template catalog loaded.");
  } catch (error) {
    marketplaceCatalog = { categories: [], templates: [] };
    renderMarketplaceCategories();
    renderMarketplaceTemplates();
    setMarketplaceMessage(error?.message || "Marketplace could not be loaded.", "error");
  } finally {
    setMarketplaceLoading(false);
  }
}

async function completeMarketplaceInstallResult(result, template, providerInstall) {
  setMarketplaceManualRecoveryState(null);
  renderMarketplaceProgress(result?.progress || []);
  renderMarketplaceDownloads(result?.downloads || []);
  if (providerInstall) {
    await refreshMarketplaceDownloads();
  }
  selectedInstanceId = result?.instance?.id || selectedInstanceId;
  forgetStaleInstanceId(selectedInstanceId);
  setMarketplaceInstallState("Complete", "complete");
  setMarketplaceMessage("Install complete. Opening the new instance.");
  renderMarketplaceRecoveryActions(template);
  finishOperation(activeMarketplaceOperationId, true, `Installed ${template.displayName || template.id || "template"}.`);
  showToast("Template installed.");
  showPage("instances");
  await refreshInstances();
}

function formatMissingDependencyList(dependencies = []) {
  return dependencies
    .map((dependency) => {
      const packages = Array.isArray(dependency.packages) && dependency.packages.length > 0
        ? ` (${dependency.packages.join(", ")})`
        : "";
      return `${dependency.displayName || dependency.id}${packages}`;
    })
    .join(", ");
}

function formatDependencyPreparationPlan(plan = {}) {
  const installable = Array.isArray(plan.installableActions) ? plan.installableActions : [];
  const manual = Array.isArray(plan.manualActions) ? plan.manualActions : [];
  const commandLines = installable
    .flatMap((action) => Array.isArray(action.commands) ? action.commands.map((command) => command.display || `${command.command} ${(command.args || []).join(" ")}`.trim()) : [])
    .filter(Boolean);
  const packageLines = installable
    .map((action) => {
      const packages = Array.isArray(action.packages) && action.packages.length ? action.packages.join(", ") : "no package mapping";
      return `${action.displayName || action.id}: ${packages}`;
    });
  const manualLines = manual.map((action) => `${action.displayName || action.id}: ${action.reason || "manual installation required"}`);
  const parts = [];
  if (packageLines.length) parts.push(`Packages:\n${packageLines.join("\n")}`);
  if (commandLines.length) parts.push(`Commands:\n${commandLines.join("\n")}`);
  if (manualLines.length) parts.push(`Manual steps still required:\n${manualLines.join("\n")}`);
  return parts.join("\n\n") || "No dependency changes are planned.";
}

async function getDependencyPreparationPlan(payload = {}) {
  const desktopApiState = getDesktopApiState();
  if (typeof desktopApiState.api?.dependencies?.plan !== "function") {
    throw new Error("Dependency planning is unavailable in this build.");
  }
  const plan = await desktopApiState.api.dependencies.plan(payload);
  if (plan?.ok === false && plan.error) {
    throw Object.assign(new Error(plan.error.message || "Dependency planning failed."), {
      code: plan.error.code,
      details: plan.error.details,
    });
  }
  return plan;
}

async function maybePrepareMarketplaceDependencies(normalizedError, template, options, requestContext, providerInstall = false) {
  const desktopApiState = getDesktopApiState();
  const details = normalizedError?.details || {};
  const missingDependencies = Array.isArray(details.missingDependencies) ? details.missingDependencies : [];
  const dependencyIds = missingDependencies.map((dependency) => dependency.id).filter(Boolean);
  if (normalizedError?.code !== "DEPENDENCIES_REQUIRED" || dependencyIds.length === 0 || !desktopApiState.hasDependencies) {
    return false;
  }

  const dependencyList = formatMissingDependencyList(missingDependencies);
  const plan = await getDependencyPreparationPlan({
    dependencyIds,
    nodeId: requestContext.nodeId,
  });
  const planText = formatDependencyPreparationPlan(plan);
  if (!plan.installableActions?.length) {
    setMarketplaceMessage(`Install blocked until dependencies are prepared manually: ${dependencyList}.`, "warning");
    renderMarketplaceProgress([
      { label: "Prepare node", status: "failed", detail: planText },
    ]);
    return true;
  }
  const confirmed = await createSecurityConfirmation({
    title: "Prepare Node Dependencies",
    message: `${template.displayName || template.id} requires missing node dependencies: ${dependencyList}.\n\n${planText}\n\nAnxOS will verify the dependencies after installation before retrying the Marketplace install.`,
    confirmLabel: "Install Missing",
  });
  if (!confirmed) {
    setMarketplaceMessage(`Install blocked until dependencies are ready: ${dependencyList}.`, "warning");
    return true;
  }

  setMarketplaceInstallState("Preparing", "running");
  setMarketplaceMessage(`Installing node dependencies: ${dependencyList}.`, "warning");
  updateOperation(activeMarketplaceOperationId, {
    type: "Marketplace",
    status: "running",
    step: `Preparing dependencies: ${dependencyList}.`,
  });
  renderMarketplaceProgress([
    { label: "Prepare node", status: "running", detail: `Installing ${dependencyList}.` },
  ]);
  const installResult = await desktopApiState.api.dependencies.install({
    dependencyIds,
    nodeId: requestContext.nodeId,
  });
  if (installResult?.ok === false || (Array.isArray(installResult?.missingDependencyIds) && installResult.missingDependencyIds.length > 0)) {
    throw new Error(installResult?.error?.message || "Dependency installation failed.");
  }
  setMarketplaceMessage("Dependencies installed. Retrying template install.");
  updateOperation(activeMarketplaceOperationId, {
    status: "running",
    step: "Dependencies installed. Retrying install.",
  });
  const retryResult = providerInstall
    ? await desktopApiState.api.marketplace.installPack({
      templateId: template.id,
      template,
      provider: getMarketplaceProvider(template),
      providerProjectId: template.providerProjectId || template.projectId,
      providerVersionId: options.providerVersionId || "",
      minecraftVersion: options.version === "latest" ? template.minecraftVersion || template.gameVersion || "latest" : options.version,
      loader: options.serverType || template.loader || "vanilla",
      loaderVersion: options.loaderVersion || template.loaderVersion || "",
      nodeId: requestContext.nodeId,
      options: {
        ...options,
        autoInstallDependencies: true,
      },
    })
    : await desktopApiState.api.marketplace.installTemplate({
      templateId: template.id,
      nodeId: requestContext.nodeId,
      options: {
        ...options,
        autoInstallDependencies: true,
      },
    });
  await completeMarketplaceInstallResult(retryResult, template, providerInstall);
  return true;
}

async function installMarketplaceTemplate(event) {
  event?.preventDefault();
  const desktopApiState = getDesktopApiState();
  const template = findMarketplaceTemplate();

  if (!desktopApiState.hasMarketplace || !template || marketplaceInstallInFlight) {
    return;
  }
  if (!syncMarketplacePortValidity({ report: true })) {
    getMarketplaceField("port")?.focus();
    return;
  }
  if (!syncMarketplaceMemoryValidity({ report: true })) {
    getMarketplaceField("memory")?.focus();
    return;
  }

  let options;
  try {
    options = collectMarketplaceInstallOptions();
    if (!isMinecraftMarketplaceTemplate(template)) {
      delete options.serverType;
    }
  } catch (error) {
    setMarketplaceMessage(error?.message || "Check install settings.", "error");
    showToast(error?.message || "Check install settings.", "warning");
    return;
  }
  if (!options.name.trim()) {
    setMarketplaceMessage("Enter a name before installing.", "error");
    getMarketplaceField("name")?.focus();
    return;
  }

  if (isMinecraftMarketplaceTemplate(template) && !options.acceptEula) {
    setMarketplaceMessage("Accept the Minecraft EULA to generate eula.txt.", "error");
    return;
  }

  const requestContext = createNodeActionContext("marketplace-install");
  marketplaceInstallInFlight = true;
  activeMarketplaceOperationId = startOperation({
    type: "Marketplace",
    title: `Install ${template.displayName || template.id || "template"}`,
    target: requestContext.nodeLabel || requestContext.nodeId || "Selected node",
    step: `Sending install request for ${template.id}.`,
  });
  marketplaceLocalDownloadEntries = [];
  setMarketplaceManualRecoveryState(null);
  if (marketplaceInstallButton) {
    marketplaceInstallButton.disabled = true;
  }
  setMarketplaceInstallState("Installing", "running");
  renderMarketplaceRecoveryActions(template);
  renderMarketplaceProgress([
    { label: "Validate template", status: "running", detail: `Sending install request for ${template.id}.` },
  ]);
  startMarketplaceInstallProgressListener();
  const providerInstall = isProviderMarketplaceTemplate(template) && desktopApiState.hasMarketplaceProviderInstall;
  const downloadPoll = providerInstall ? null : window.setInterval(refreshMarketplaceDownloads, 1000);

  try {
    if (!isNodeActionStillCurrent(requestContext)) return;
    const result = providerInstall
      ? await desktopApiState.api.marketplace.installPack({
        templateId: template.id,
        template,
        provider: getMarketplaceProvider(template),
        providerProjectId: template.providerProjectId || template.projectId,
        providerVersionId: options.providerVersionId || "",
        minecraftVersion: options.version === "latest" ? template.minecraftVersion || template.gameVersion || "latest" : options.version,
        loader: options.serverType || template.loader || "vanilla",
        loaderVersion: options.loaderVersion || template.loaderVersion || "",
        nodeId: requestContext.nodeId,
        options,
      })
      : await desktopApiState.api.marketplace.installTemplate({
        templateId: template.id,
        nodeId: requestContext.nodeId,
        options,
      });
    if (result?.status === "waiting-manual-download") {
      rememberWaitingMarketplaceDownload(template, result.manualDownload || {}, { code: "PROVIDER_MANUAL_DOWNLOAD_REQUIRED" });
      renderMarketplaceProgress(result?.progress || [
        { label: "Waiting for Manual Download", status: "waiting", detail: "A required modpack file needs manual download." },
      ]);
      renderMarketplaceDownloads([]);
      selectedInstanceId = result?.instance?.id || selectedInstanceId;
      forgetStaleInstanceId(selectedInstanceId);
      setMarketplaceInstallState("Paused", "waiting");
      setMarketplaceMessage("Install paused. See Download Manager.", "warning");
      updateOperation(activeMarketplaceOperationId, {
        status: "waiting",
        step: "Waiting for a required manual download.",
      });
      renderMarketplaceRecoveryActions(template);
      showToast("A required modpack file needs manual download.");
      return;
    }
    await completeMarketplaceInstallResult(result, template, providerInstall);
  } catch (error) {
    const normalizedError = normalizeMarketplaceError(error, "Template install failed.");
    try {
      if (await maybePrepareMarketplaceDependencies(normalizedError, template, options, requestContext, providerInstall)) {
        return;
      }
    } catch (prepareError) {
      const preparedError = normalizeMarketplaceError(prepareError, "Dependency preparation failed.");
      setMarketplaceInstallState("Failed", "failed");
      updateOperation(activeMarketplaceOperationId, {
        status: "failed",
        step: preparedError.title,
        error: preparedError.body,
      });
      renderMarketplaceProgress([
        {
          label: preparedError.title,
          status: "failed",
          detail: preparedError.body,
          debug: preparedError.debug,
        },
      ]);
      setMarketplaceMessage(preparedError.title, "error");
      showToast(preparedError.title);
      return;
    }
    const failureDownloads = Array.isArray(normalizedError.details?.childTaskState)
      ? normalizedError.details.childTaskState
      : [];
    setMarketplaceInstallState("Failed", "failed");
    updateOperation(activeMarketplaceOperationId, {
      status: "failed",
      step: normalizedError.title,
      error: normalizedError.body,
    });
    setMarketplaceManualRecoveryState(null);
    if (failureDownloads.length > 0) {
      marketplaceLocalDownloadEntries = [];
    } else {
      rememberFailedMarketplaceDownload(template, normalizedError);
    }
    renderMarketplaceRecoveryActions(template, normalizedError);
    renderMarketplaceProgress([
      {
        label: normalizedError.title,
        status: "failed",
        detail: normalizedError.body,
        debug: normalizedError.debug,
      },
    ]);
    marketplaceInstallProgressEvents = [];
    marketplacePendingProgressSteps = null;
    renderMarketplaceDownloads(failureDownloads);
    setMarketplaceMessage("Install failed. See Download Manager.", "error");
    showToast(normalizedError.title);
  } finally {
    if (downloadPoll) {
      window.clearInterval(downloadPoll);
    }
    stopMarketplaceInstallProgressListener();
    marketplaceInstallInFlight = false;
    activeMarketplaceOperationId = null;
    if (marketplaceInstallButton) {
      marketplaceInstallButton.disabled = false;
    }
    renderMarketplaceTemplates();
    refreshMarketplaceDownloads();
  }
}

function parseCsv(value) {
  return String(value || "")
    .split(",")
    .map((part) => part.trim())
    .filter(Boolean);
}

function parseArgs(value) {
  const raw = String(value || "").trim();

  if (!raw) {
    return [];
  }

  try {
    const parsed = JSON.parse(raw);
    if (Array.isArray(parsed)) {
      return parsed.map((entry) => String(entry));
    }
  } catch {}

  return raw.match(/(?:[^\s"]+|"[^"]*")+/g)?.map((part) => part.replace(/^"|"$/g, "")) || [];
}

function normalizeMemoryLimit(value) {
  const memory = String(value || "").trim();

  if (!memory) {
    return "";
  }

  const match = memory.match(/^([1-9][0-9]{0,5})([kKmMgG]?)$/);
  if (!match) {
    throw new Error("Use memory like 512M, 2G, or 2048M.");
  }

  return `${match[1]}${match[2] ? match[2].toUpperCase() : ""}`;
}

function parseEnvironment(value) {
  return parseCsv(value).reduce((environment, entry) => {
    const separatorIndex = entry.indexOf("=");
    if (separatorIndex <= 0) {
      return environment;
    }

    const key = entry.slice(0, separatorIndex).trim();
    const envValue = entry.slice(separatorIndex + 1).trim();
    if (key) {
      environment[key] = envValue;
    }
    return environment;
  }, {});
}

function getInstanceFormValue(name) {
  return document.querySelector(`[data-instance-form="${name}"]`)?.value?.trim() || "";
}

function setInstanceFormMessage(message) {
  if (instanceFormMessage) {
    instanceFormMessage.textContent = message;
  }
}

function syncInstanceCreateTypeFields() {
  const type = instanceTypeSelect?.value || "custom-command";
  const executableInput = document.querySelector('[data-instance-form="executable"]');
  const entrypointInput = document.querySelector('[data-instance-form="entrypoint"]');

  if (instanceEntrypointField) {
    instanceEntrypointField.hidden = type === "custom-command";
  }

  instanceCustomFields.forEach((field) => {
    field.hidden = type !== "custom-command";
  });

  instanceTemplateButtons.forEach((button) => {
    button.classList.toggle("is-active", button.dataset.instanceTemplate === type);
  });

  if (executableInput && !executableInput.value.trim()) {
    executableInput.placeholder =
      type === "custom-command" ? "node" :
        type === "node-app" ? "node" :
          type === "python-app" ? "python3" :
            "java";
  }

  if (entrypointInput) {
    entrypointInput.placeholder =
      type === "node-app" ? "index.js" :
        type === "python-app" ? "app.py" :
          type === "java-app" ? "app.jar" :
            type === "minecraft-paper" ? "paper.jar" :
              "";
  }
}

function buildInstanceCreatePayload() {
  const id = getInstanceFormValue("id");
  const displayName = getInstanceFormValue("displayName");
  const type = getInstanceFormValue("type") || "custom-command";
  const executable = getInstanceFormValue("executable");
  const entrypoint = getInstanceFormValue("entrypoint");
  const workingDirectory = getInstanceFormValue("workingDirectory");
  const args = parseArgs(getInstanceFormValue("args"));
  const memoryLimit = normalizeMemoryLimit(getInstanceFormValue("memoryLimit"));
  const ports = parseCsv(getInstanceFormValue("ports")).map((port) => Number.parseInt(port, 10)).filter(Number.isFinite);
  const tags = parseCsv(getInstanceFormValue("tags"));
  const environment = parseEnvironment(getInstanceFormValue("environment"));

  if (!/^[a-zA-Z0-9][a-zA-Z0-9_-]{1,63}$/.test(id)) {
    throw new Error("Use an ID with 2-64 letters, numbers, underscores, or dashes.");
  }

  const payload = {
    id,
    displayName: displayName || id,
    type,
    args,
    ports,
    tags,
    environment,
  };

  if (memoryLimit) {
    payload.memoryLimit = memoryLimit;
  }

  if (type === "minecraft-paper" && !payload.tags.includes("minecraft")) {
    payload.tags.push("minecraft");
  }

  if (executable) {
    payload.executable = executable;
  }

  if (workingDirectory) {
    payload.workingDirectory = workingDirectory;
  }

  if (entrypoint && type !== "custom-command") {
    if (type === "java-app" || type === "minecraft-paper") {
      payload.jar = entrypoint;
    } else {
      payload.entrypoint = entrypoint;
    }
  }

  return payload;
}

function setInstanceCreateFormVisible(visible) {
  instanceCreateFormVisible = Boolean(visible);

  if (instanceCreateForm) {
    instanceCreateForm.hidden = !instanceCreateFormVisible;
  }

  if (instancesDetailsPanel) {
    instancesDetailsPanel.hidden = instanceCreateFormVisible;
  }

  if (instancesCreateToggleButton) {
    instancesCreateToggleButton.textContent = instanceCreateFormVisible ? "Hide Form" : "Create Instance";
  }

  syncInstanceCreateTypeFields();
}

async function refreshInstances(options = {}) {
  if (instancesRequestInFlight) {
    return getInstances();
  }

  const desktopApiState = getDesktopApiState();

  if (!desktopApiState.hasInstances) {
    renderInstancesUnavailable(desktopApiState.hasBridge ? "Instances IPC bridge unavailable." : "Desktop preload bridge unavailable.");
    return getInstances();
  }

  instancesRequestInFlight = true;
  const requestContext = getNodeRequestContext("instances");
  setInstancesLoading(true);
  updateInstanceActionButtons();

  try {
    const snapshot = await desktopApiState.api.instances.list(getNodeScopedPayload(requestContext));
    if (!isNodeRequestCurrent(requestContext)) {
      return getInstances();
    }
    renderInstancesSnapshot(snapshot);
    if (options.refreshMetrics !== false) {
      await refreshSelectedInstanceMetrics();
    }
  } catch (error) {
    if (!isNodeRequestCurrent(requestContext)) {
      return getInstances();
    }
    console.warn("[Instances] List refresh failed; keeping previous renderer state.", error);
    if (latestInstancesSnapshot) {
      setInstancesLoading(false);
      setInstancesEmpty(getInstances().length === 0, "Instance list refresh failed. Keeping the last known list.");
      showToast(getAgentErrorMessage(error, "Instance list refresh failed."), "warning");
    } else {
      renderInstancesUnavailable(`Instance request failed: ${getAgentErrorMessage(error)}`);
    }
  } finally {
    if (isNodeRequestCurrent(requestContext)) {
      instancesRequestInFlight = false;
      updateInstanceActionButtons();
    }
  }

  return getInstances();
}

async function refreshSelectedInstanceMetrics() {
  if (!selectedInstanceId || instanceActionRequestInFlight) {
    return;
  }

  const requestInstanceId = selectedInstanceId;
  const requestContext = getNodeRequestContext("instance-metrics");

  if (!findInstance(requestInstanceId)) {
    await handleMissingSelectedInstance(null, requestInstanceId);
    return;
  }

  const desktopApiState = getDesktopApiState();

  if (!desktopApiState.hasInstances) {
    return;
  }

  try {
    const metrics = await desktopApiState.api.instances.getMetrics(requestInstanceId, getNodeScopedPayload(requestContext));
    if (!isNodeRequestCurrent(requestContext) || requestInstanceId !== selectedInstanceId) {
      return;
    }
    latestInstanceMetrics = normalizeMetricsResponse(metrics);
    const instances = getInstances();
    renderInstanceSummary(instances);
    renderInstanceRows(instances);
    selectInstance(requestInstanceId, { refreshMetrics: false });
  } catch (error) {
    if (!isNodeRequestCurrent(requestContext)) {
      return;
    }
    latestInstanceMetrics = null;
    if (isInstanceNotFoundError(error)) {
      await handleMissingSelectedInstance(error, requestInstanceId);
      return;
    }
    console.warn("[Instances] Metrics request failed.", error);
    setInstanceDetails(findInstance());
  }
}

async function refreshInstanceLogs(options = {}) {
  if (!selectedInstanceId || instanceLogsRequestInFlight) {
    return;
  }

  const requestInstanceId = selectedInstanceId;

  if (!findInstance(requestInstanceId)) {
    await handleMissingSelectedInstance(null, requestInstanceId);
    return;
  }

  const desktopApiState = getDesktopApiState();

  if (!desktopApiState.hasInstances) {
    clearInstanceLogs("Instances IPC bridge unavailable.");
    return;
  }

  instanceLogsRequestInFlight = true;
  const requestContext = getNodeRequestContext("instance-logs");
  updateInstanceActionButtons();

  try {
    const stream = instancesLogStreamSelect?.value || "all";
    const limit = Number.parseInt(instancesLogLimitSelect?.value || "200", 10);
    const logs = await desktopApiState.api.instances.getLogs(requestInstanceId, {
      nodeId: requestContext.nodeId,
      stream,
      limit: Number.isFinite(limit) ? limit : 200,
    });
    if (!isNodeRequestCurrent(requestContext) || requestInstanceId !== selectedInstanceId) {
      return;
    }
    renderInstanceLogs(logs);
  } catch (error) {
    if (!isNodeRequestCurrent(requestContext)) {
      return;
    }
    if (isInstanceNotFoundError(error)) {
      await handleMissingSelectedInstance(error, requestInstanceId);
    } else if (!options.silent) {
      console.warn("[Instances] Log request failed.", error);
      showToast(getAgentErrorMessage(error, "Log request failed."));
    } else {
      console.warn("[Instances] Silent log request failed.", error);
    }
  } finally {
    if (isNodeRequestCurrent(requestContext)) {
      instanceLogsRequestInFlight = false;
      updateInstanceActionButtons();
    }
  }
}

function shouldPollInstanceConsole() {
  return getActivePageName() === "instances" &&
    activeInstanceTab === "console" &&
    Boolean(selectedInstanceId) &&
    !instanceConsolePauseInput?.checked;
}

function startInstanceConsolePolling() {
  if (instanceConsolePollTimerId) {
    return;
  }
  instanceConsolePollTimerId = window.setInterval(() => {
    if (!shouldPollInstanceConsole()) {
      return;
    }
    refreshInstanceLogs({ silent: true });
  }, CONSOLE_LOG_REFRESH_INTERVAL_MS);
}

function stopInstanceConsolePolling() {
  if (!instanceConsolePollTimerId) {
    return;
  }
  window.clearInterval(instanceConsolePollTimerId);
  instanceConsolePollTimerId = null;
}

function syncInstanceConsolePolling() {
  if (shouldPollInstanceConsole()) {
    startInstanceConsolePolling();
    refreshInstanceLogs({ silent: true });
    return;
  }
  stopInstanceConsolePolling();
}

async function createInstanceFromForm(event) {
  event?.preventDefault();

  const desktopApiState = getDesktopApiState();
  const requestContext = createNodeActionContext("instance-create");

  if (!desktopApiState.hasInstances || instanceActionRequestInFlight) {
    return;
  }

  let payload;

  try {
    payload = buildInstanceCreatePayload();
  } catch (error) {
    setInstanceFormMessage(error?.message || "Check instance form values.");
    return;
  }

  instanceActionRequestInFlight = true;
  updateInstanceActionButtons();
  setInstanceFormMessage("Creating instance...");
  let createdInstanceId = null;
  let createdInstanceAccepted = false;

  try {
    logInstanceCreateFlow("submitting create request", {
      requestedId: payload.id,
      type: payload.type,
      memoryLimit: payload.memoryLimit || null,
    });
    if (!isNodeActionStillCurrent(requestContext)) return;
    payload.nodeId = requestContext.nodeId;
    const response = await desktopApiState.api.instances.create(payload);
    const instance = normalizeInstanceResponse(response);
    createdInstanceId = instance?.id || payload.id;
    selectedInstanceId = createdInstanceId;
    forgetStaleInstanceId(createdInstanceId);
    logInstanceCreateFlow("created instance", {
      createdId: createdInstanceId,
      responseId: instance?.id || null,
    });

    const refreshedInstances = await refreshInstances({ refreshMetrics: false });
    const refreshedInstanceIds = refreshedInstances.map((candidate) => candidate.id);
    logInstanceCreateFlow("refreshed after create", {
      createdId: createdInstanceId,
      refreshedInstanceIds,
    });

    if (!refreshedInstanceIds.includes(createdInstanceId)) {
      await handleMissingSelectedInstance(null, createdInstanceId, "create-refresh-missing");
      setInstanceFormMessage("Created instance was not returned by the agent refresh. Removed stale entry from the list.");
      return;
    }

    createdInstanceAccepted = true;
    selectInstance(createdInstanceId, { refreshMetrics: false });

    if (payload.type === "minecraft-paper") {
      const acceptEula = document.querySelector('[data-instance-form="acceptEula"]')?.checked === true;
      if (acceptEula) {
        if (!isNodeActionStillCurrent(requestContext)) return;
        await desktopApiState.api.instances.writeFile(createdInstanceId, "eula.txt", "eula=true\n", getNodeScopedPayload(requestContext));
      }
      if (!isNodeActionStillCurrent(requestContext)) return;
      await desktopApiState.api.instances.saveMinecraftProperties(createdInstanceId, {
        "server-port": payload.ports?.[0] ? String(payload.ports[0]) : "25565",
        motd: payload.displayName || payload.id,
        "max-players": "20",
        difficulty: "easy",
        gamemode: "survival",
        "view-distance": "10",
        "simulation-distance": "10",
        "online-mode": "true",
        "allow-flight": "false",
        "spawn-protection": "16",
        pvp: "true",
        "white-list": "false",
        "generate-structures": "true",
        "level-seed": "",
      }, getNodeScopedPayload(requestContext));
    }

    setInstanceCreateFormVisible(false);
    instanceCreateForm?.reset();
    setInstanceFormMessage("Commands run without a shell. Secrets are not accepted in environment variable names.");
    showToast("Instance created.");
    await refreshInstances();
  } catch (error) {
    if (isInstanceNotFoundError(error)) {
      const candidateId = createdInstanceId || selectedInstanceId || payload.id;
      const refreshedInstances = await refreshInstances({ refreshMetrics: false });
      const refreshedInstanceIds = refreshedInstances.map((candidate) => candidate.id);
      logInstanceCreateFlow("not-found during create follow-up", {
        createdId: candidateId,
        createdInstanceAccepted,
        refreshedInstanceIds,
        errorCode: getAgentErrorCode(error),
      });

      if (!refreshedInstanceIds.includes(candidateId)) {
        await handleMissingSelectedInstance(error, candidateId, "create-follow-up-not-found-and-missing-after-refresh");
        setInstanceFormMessage("Created instance was not available. Removed stale entry from the list.");
      } else {
        console.warn("[Instances] Create follow-up request returned not found, but the created instance is present after refresh.", {
          createdId: candidateId,
          refreshedInstanceIds,
          error,
        });
        selectedInstanceId = candidateId;
        selectInstance(candidateId, { refreshMetrics: false });
        setInstanceCreateFormVisible(false);
        instanceCreateForm?.reset();
        setInstanceFormMessage("Instance created. A follow-up configuration step was not available yet; refresh or open Settings to retry.");
        showToast("Instance created. Some setup could not be applied yet.", "warning");
      }
    } else {
      setInstanceFormMessage(getAgentErrorMessage(error, "Create instance failed."));
    }
  } finally {
    instanceActionRequestInFlight = false;
    updateInstanceActionButtons();
  }
}

async function runInstanceAction(actionName) {
  const selectedInstance = findInstance();
  const desktopApiState = getDesktopApiState();
  const requestContext = createNodeActionContext(`instance-${actionName}`);

  if (!selectedInstance || !desktopApiState.hasInstances || instanceActionRequestInFlight) {
    updateInstanceActionButtons();
    return;
  }

  const label = selectedInstance.displayName || selectedInstance.id;
  const targetInstanceId = selectedInstance.id;

  if ((actionName === "start" || actionName === "restart") && isFiveMSetupRequired(selectedInstance)) {
    await openFiveMSetup(selectedInstance, {
      message: "FiveM setup is required before this server can start.",
    });
    updateInstanceActionButtons();
    return;
  }

  if (actionName === "configure-fivem") {
    await openFiveMSetup(selectedInstance);
    updateInstanceActionButtons();
    return;
  }

  if (actionName === "forceKill" && !canStopInstance(selectedInstance)) {
    showToast("Instance is already stopped. Use Delete or Forget to remove it.", "warning");
    updateInstanceActionButtons();
    return;
  }

  if (actionName === "delete") {
    if (!window.confirm(`Delete ${label}? This cannot be undone.`)) {
      showToast("Delete canceled.");
      return;
    }
  } else if (actionName === "forget") {
    if (!window.confirm(`Forget ${label}? This only removes the saved instance record from AnxOS Control Center. Server files may remain on disk.`)) {
      showToast("Forget canceled.");
      return;
    }
  } else if (!window.confirm(`${actionName[0].toUpperCase()}${actionName.slice(1)} ${label}?`)) {
    return;
  }

  if (!isNodeActionStillCurrent(requestContext)) return;
  if ((actionName === "start" || actionName === "restart") && !(await verifyJavaJarBeforeLaunch(selectedInstance, requestContext))) {
    return;
  }

  instanceActionRequestInFlight = true;
  updateInstanceActionButtons();

  try {
    if (actionName === "delete") {
      showToast(`Deleting ${label}...`);
    } else if (actionName === "forget") {
      showToast(`Removing ${label} from the instance list...`);
    } else if (actionName === "start") {
      logInstanceLifecycle("start requested", { instanceId: targetInstanceId });
    }

    if (!isNodeActionStillCurrent(requestContext)) return;
    const actionResult = await desktopApiState.api.instances[actionName](targetInstanceId, getNodeScopedPayload(requestContext));
    if (actionName === "start") {
      logInstanceLifecycle("start result", {
        instanceId: targetInstanceId,
        state: actionResult?.instance?.state || actionResult?.state || null,
        pid: actionResult?.instance?.pid || actionResult?.pid || null,
      });
    }
    forgetStaleInstanceId(targetInstanceId);
    showToast(actionName === "delete" ? formatInstanceDeletionResult(actionResult, "Instance deleted.") : actionName === "forget" ? formatInstanceDeletionResult(actionResult, "Instance removed from list.") : `Instance ${actionName} request completed.`);

    if (actionName === "delete" || actionName === "forget") {
      selectedInstanceId = null;
      latestInstanceMetrics = null;
      clearInstanceLogs();
      setInstanceDetails(null);
      instanceRemovalAllowedIds.add(targetInstanceId);
      removeInstanceFromSnapshot(targetInstanceId);
    }

    const refreshedInstances = await refreshInstances();
    if (actionName === "start") {
      logInstanceLifecycle("list result after start", {
        instanceId: targetInstanceId,
        count: refreshedInstances.length,
        containsInstance: refreshedInstances.some((instance) => instance.id === targetInstanceId),
      });
    }
  } catch (error) {
    if (isInstanceNotFoundError(error)) {
      if (actionName === "delete" || actionName === "forget") {
        instanceRemovalAllowedIds.add(targetInstanceId);
        selectedInstanceId = null;
        latestInstanceMetrics = null;
        storeLastInstanceId(null);
        clearInstanceLogs();
        setInstanceDetails(null);
        removeInstanceFromSnapshot(targetInstanceId);
        showToast("Instance was already deleted. Refreshed the list.", "warning");
        await refreshInstances();
      } else {
        await handleMissingSelectedInstance(error, targetInstanceId, `${actionName}-not-found`);
      }
    } else {
      console.warn(`[Instances] ${actionName} failed.`, error);
      if ((actionName === "start" || actionName === "restart") && getAgentErrorCode(error) === "FIVEM_SETUP_REQUIRED") {
        await openFiveMSetup(selectedInstance, {
          message: "FiveM setup is required before this server can start.",
        });
        await refreshInstances({ refreshMetrics: false });
        return;
      }
      if (actionName === "delete" && isInstanceRunningError(error)) {
        const stopThenDelete = window.confirm(`${label} is still running. Stop it and delete it after it stops? This cannot be undone.`);
        if (stopThenDelete && isNodeActionStillCurrent(requestContext)) {
          try {
            showToast(`Stopping ${label} before delete...`);
            await desktopApiState.api.instances.stop(targetInstanceId, getNodeScopedPayload(requestContext));
            if (!isNodeActionStillCurrent(requestContext)) return;
            showToast(`Deleting ${label}...`);
            await desktopApiState.api.instances.delete(targetInstanceId, getNodeScopedPayload(requestContext));
            instanceRemovalAllowedIds.add(targetInstanceId);
            selectedInstanceId = null;
            latestInstanceMetrics = null;
            storeLastInstanceId(null);
            clearInstanceLogs();
            setInstanceDetails(null);
            removeInstanceFromSnapshot(targetInstanceId);
            showToast("Instance stopped and deleted.");
            await refreshInstances();
            return;
          } catch (retryError) {
            console.warn("[Instances] stop-then-delete failed.", retryError);
            showToast(getAgentErrorMessage(retryError, "Instance could not be stopped and deleted."));
          }
        } else {
          showToast("Delete canceled. Stop the instance before deleting it.", "warning");
        }
      } else if (actionName === "delete" && desktopApiState.api.instances.forget && window.confirm(`Could not delete all files for ${label}. Remove the saved instance record from AnxOS Control Center anyway? Files may remain on disk.`)) {
        try {
          const forgetResult = await desktopApiState.api.instances.forget(targetInstanceId, getNodeScopedPayload(requestContext));
          instanceRemovalAllowedIds.add(targetInstanceId);
          selectedInstanceId = null;
          latestInstanceMetrics = null;
          storeLastInstanceId(null);
          clearInstanceLogs();
          setInstanceDetails(null);
          removeInstanceFromSnapshot(targetInstanceId);
          showToast(formatInstanceDeletionResult(forgetResult, "Instance removed from list."));
          await refreshInstances();
          return;
        } catch (forgetError) {
          console.warn("[Instances] forget after delete failure failed.", forgetError);
          showToast(getAgentErrorMessage(forgetError, "Instance record could not be removed."));
        }
      } else {
        showToast(getAgentErrorMessage(error, `Instance ${actionName} failed.`));
      }
      if ((actionName === "start" || actionName === "restart") && getAgentErrorCode(error) !== "FIVEM_SETUP_REQUIRED") {
        updateInstanceSnapshot(targetInstanceId, {
          state: "Failed",
          failureReason: getAgentErrorMessage(error, `Instance ${actionName} failed.`),
        });
      }
      const refreshedInstances = await refreshInstances();
      if (actionName === "start") {
        logInstanceLifecycle("list result after failed start", {
          instanceId: targetInstanceId,
          count: refreshedInstances.length,
          containsInstance: refreshedInstances.some((instance) => instance.id === targetInstanceId),
          errorCode: getAgentErrorCode(error),
        });
      }
    }
  } finally {
    instanceActionRequestInFlight = false;
    updateInstanceActionButtons();
  }
}

function setFileDetail(name, value) {
  fileDetailFields.forEach((field) => {
    if (field.dataset.fileDetail === name) {
      field.textContent = value;
      field.title = value;
    }
  });
}

function setFileDetails(entry = null) {
  if (!entry) {
    if (filesDetailsStatus) {
      filesDetailsStatus.textContent = "None";
    }

    setFileDetail("name", "None selected");
    setFileDetail("type", "Unavailable");
    setFileDetail("size", "Unavailable");
    setFileDetail("modified", "Unavailable");
    setFileDetail("permissions", "Not reported");
    setFileDetail("path", "Unavailable");
    return;
  }

  if (filesDetailsStatus) {
    filesDetailsStatus.textContent = entry.isDirectory ? "Folder" : "Selected";
  }

  setFileDetail("name", formatFileValue(entry.name));
  setFileDetail("type", formatFileType(entry));
  setFileDetail("size", entry.isDirectory ? "Folder" : formatBytes(entry.size));
  setFileDetail("modified", formatDateTime(entry.modifiedAt));
  setFileDetail("permissions", entry.permissions ? `${entry.permissions}` : "Not reported");
  setFileDetail("path", formatFileValue(entry.path));
}

function setFileEditorMessage(message) {
  if (fileEditorMessage) {
    fileEditorMessage.textContent = message;
  }
}

function setFileEditorPath(value) {
  setFileEditorName(value ? getFileNameFromPath(value) : null);

  if (fileEditorPath) {
    fileEditorPath.textContent = value || "No file opened";
  }
}

function setFileEditorDirtyIndicator(isDirty) {
  if (fileEditorDirtyIndicator) {
    fileEditorDirtyIndicator.hidden = !isDirty;
  }
}

function getFileEditorLineCount(value) {
  return Math.max(1, String(value || "").split("\n").length);
}

function renderFileEditorLines(value = "") {
  if (!fileEditorLines) {
    return;
  }

  const lineCount = getFileEditorLineCount(value);
  fileEditorLines.replaceChildren();

  for (let index = 1; index <= lineCount; index += 1) {
    const item = document.createElement("li");
    item.textContent = `${index}`;
    fileEditorLines.appendChild(item);
  }
}

function syncFileEditorLineScroll() {
  if (!fileEditor || !fileEditorLines) {
    return;
  }

  fileEditorLines.style.transform = `translateY(${-fileEditor.scrollTop}px)`;
}

function setFileEditorHeight(value) {
  const nextHeight = Math.max(360, Math.min(1100, Number(value) || 560));
  fileEditorHeight = nextHeight;

  if (fileEditorSurface) {
    fileEditorSurface.style.setProperty("--file-editor-height", `${nextHeight}px`);
  }

  if (fileEditorHeightInput) {
    fileEditorHeightInput.value = `${nextHeight}`;
  }

  window.requestAnimationFrame(() => {
    monacoEditorInstance?.layout?.();
  });
}

function hasOpenFileEditorDocument() {
  return Boolean(latestFileDocument?.path);
}

function setFilesViewMode(mode) {
  const nextMode = mode === "edit" && hasOpenFileEditorDocument() ? "edit" : "browse";

  if (nextMode === "browse" && filesViewMode === "edit" && hasOpenFileEditorDocument()) {
    if (!confirmDiscardFileEditor("return to Browse Mode")) {
      renderFilesView();
      return;
    }

    resetFileEditor("Select a file to preview or edit.");
  }

  filesViewMode = nextMode;

  if (nextMode !== "edit" && fileEditorPanel) {
    fileEditorPanel.classList.remove("is-fullscreen");
  }

  renderFilesView();
}

function toggleFileEditorFullscreen() {
  if (!fileEditorPanel) {
    return;
  }

  if (!fileEditorPanel.classList.contains("is-fullscreen") && hasOpenFileEditorDocument()) {
    filesViewMode = "edit";
  }

  fileEditorPanel.classList.toggle("is-fullscreen");

  if (fileEditorFullscreenButton) {
    fileEditorFullscreenButton.textContent = fileEditorPanel.classList.contains("is-fullscreen")
      ? "Exit Fullscreen"
      : "Fullscreen Editor";
  }

  renderFilesView();
}

async function copyActiveFilePath() {
  const value = latestFileDocument?.path || selectedFileEntryPath || filesConnectionState.currentPath || "";

  if (!value) {
    return;
  }

  try {
    await navigator.clipboard.writeText(value);
    showToast("Remote path copied.");
  } catch {
    showToast(value);
  }
}

function toggleFileEditorWordWrap() {
  if (!latestFileDocument?.supported) {
    return;
  }

  fileEditorWordWrapEnabled = !fileEditorWordWrapEnabled;
  persistFileEditorPreferences();
  updateMonacoEditorOptions();
}

function toggleFileEditorMinimap() {
  if (!latestFileDocument?.supported) {
    return;
  }

  fileEditorMinimapEnabled = !fileEditorMinimapEnabled;
  persistFileEditorPreferences();
  updateMonacoEditorOptions();
  window.requestAnimationFrame(() => {
    monacoEditorInstance?.layout?.();
  });
}

function resetFileEditor(message = "Select a file to preview or edit.") {
  disposeMonacoModel();
  latestFileDocument = null;
  filesViewMode = "browse";

  if (fileEditor) {
    fileEditor.value = "";
    fileEditor.disabled = true;
    fileEditor.scrollTop = 0;
  }

  if (fileEditorStatus) {
    fileEditorStatus.textContent = "Read Only";
  }

  setFileEditorDirtyIndicator(false);
  setFileEditorPath(null);
  setMonacoEditorVisibility(false);
  renderFileEditorLines("");
  syncFileEditorLineScroll();
  if (fileEditorPanel) {
    fileEditorPanel.classList.remove("is-fullscreen");
  }
  setFileEditorMessage(message);
  syncFileEditorButtons();
}

function applyFileEditorDocument(documentState) {
  latestFileDocument = documentState;

  if (fileEditor) {
    fileEditor.disabled = !documentState?.supported;
    fileEditor.value = documentState?.supported ? documentState.content || "" : "";
    fileEditor.scrollTop = 0;
  }

  if (fileEditorStatus) {
    fileEditorStatus.textContent = !documentState?.supported
      ? "Unsupported"
      : documentState?.dirty
        ? "Unsaved"
        : "Ready";
  }

  setFileEditorDirtyIndicator(Boolean(documentState?.dirty));
  setFileEditorPath(documentState?.path || selectedFileEntryPath || null);
  renderFileEditorLines(documentState?.supported ? documentState.content || "" : "");
  syncFileEditorLineScroll();
  setFileEditorMessage(documentState?.message || "Open a text file to view and edit it here.");
  setMonacoEditorVisibility(Boolean(documentState?.supported && monacoEditorInstance));
  syncFileEditorButtons();
}

function syncFileEditorDirtyState() {
  if (!latestFileDocument?.supported) {
    return;
  }

  latestFileDocument.content = getFileEditorValue();
  latestFileDocument.dirty = latestFileDocument.content !== latestFileDocument.savedContent;

  if (fileEditorStatus) {
    fileEditorStatus.textContent = latestFileDocument.dirty ? "Unsaved" : "Ready";
  }

  setFileEditorDirtyIndicator(latestFileDocument.dirty);
  setFileEditorPath(latestFileDocument.path || selectedFileEntryPath || null);
  if (!monacoEditorInstance || fileEditorCodeLayer?.hidden) {
    renderFileEditorLines(getFileEditorValue());
    syncFileEditorLineScroll();
  }
  syncFileEditorButtons();
}

function syncFileEditorButtons() {
  const selectedEntry = getSelectedFileEntry(latestFilesListing?.entries || []);
  const canOpenSelectedText = Boolean(filesConnectionState.connected && selectedEntry && !selectedEntry.isDirectory);
  const hasEditableDocument = Boolean(latestFileDocument?.supported && latestFileDocument?.path);
  const isDirty = Boolean(latestFileDocument?.dirty);
  const isBusy = filesRequestInFlight || filesActionRequestInFlight;

  if (fileEditorOpenButton) {
    fileEditorOpenButton.disabled = !canOpenSelectedText || isBusy;
  }

  if (fileEditorSaveButton) {
    fileEditorSaveButton.disabled = !hasEditableDocument || !isDirty || isBusy;
  }

  if (fileEditorRevertButton) {
    fileEditorRevertButton.disabled = !hasEditableDocument || !isDirty || isBusy;
  }

  if (fileEditorCopyPathButton) {
    fileEditorCopyPathButton.disabled = !(latestFileDocument?.path || selectedFileEntryPath);
  }

  if (fileEditorWrapButton) {
    fileEditorWrapButton.disabled = !hasEditableDocument;
  }

  if (fileEditorMinimapButton) {
    fileEditorMinimapButton.disabled = !hasEditableDocument;
  }

  if (fileEditorFullscreenButton) {
    fileEditorFullscreenButton.disabled = !hasEditableDocument && !fileEditorPanel?.classList.contains("is-fullscreen");
  }

  updateFileEditorToggleButtons();
}

function updateFileActionButtons() {
  const selectedEntry = getSelectedFileEntry(latestFilesListing?.entries || []);
  const connected = filesConnectionState.connected;
  const busy = isNodeSwitching() || filesRequestInFlight || filesActionRequestInFlight;
  const canBrowse = connected && !busy;
  const canMutate = connected && !busy;
  const canDownload = connected && selectedEntry && !selectedEntry.isDirectory && !busy;
  const hasOpenDocument = hasOpenFileEditorDocument();
  const target = getFilesConnectionTarget();

  if (filesConnectButton) {
    filesConnectButton.disabled = !target || busy || (connected && filesConnectionState.targetKey === target.key);
  }

  if (filesDisconnectButton) {
    filesDisconnectButton.disabled = !connected || busy;
  }

  if (filesServerSelect) {
    filesServerSelect.disabled = sshProfilesState.servers.length === 0 || busy;
  }

  if (filesProfileSelect) {
    filesProfileSelect.disabled = (!isSingleDeviceMode() && getFilesFilteredProfiles().length === 0) || busy;
  }

  if (filesPathInput) {
    filesPathInput.disabled = !connected || busy;
  }

  if (filesSearchInput) {
    filesSearchInput.disabled = !connected;
  }

  if (filesGoButton) {
    filesGoButton.disabled = !canBrowse;
  }

  if (filesHomeButton) {
    filesHomeButton.disabled = !canBrowse;
  }

  filesModeButtons.forEach((button) => {
    const mode = button.dataset.filesMode || "browse";
    button.disabled = mode === "edit" && !hasOpenDocument;
    button.classList.toggle("is-active", mode === filesViewMode);
    button.setAttribute("aria-selected", mode === filesViewMode ? "true" : "false");
  });

  fileActionButtons.forEach((button) => {
    if (button === filesGoButton || button === filesHomeButton) {
      return;
    }

    const action = button.dataset.fileAction;

    if (action === "refresh") {
      button.disabled = !connected || busy;
      return;
    }

    if (action === "upload" || action === "new-folder" || action === "new-file") {
      button.disabled = !canMutate;
      return;
    }

    if (action === "download") {
      button.disabled = !canDownload;
      return;
    }

    button.disabled = !(connected && selectedEntry) || busy;
  });

  syncFileEditorButtons();
}

function setFilesLoading(isLoading, message = "Loading files...") {
  if (filesLoading) {
    filesLoading.hidden = !isLoading;
    filesLoading.setAttribute("aria-busy", isLoading ? "true" : "false");
    const statusText = filesLoading.querySelector("span:last-child");

    if (statusText) {
      statusText.textContent = message;
    }
  }
  document.querySelector('[data-page="files"]')?.setAttribute("aria-busy", isLoading ? "true" : "false");
}

function setFilesEmpty(isVisible, title, message) {
  if (filesEmpty) {
    filesEmpty.hidden = !isVisible;

    const titleTarget = filesEmpty.querySelector("strong");
    const messageTarget = filesEmpty.querySelector("span:last-child");

    if (titleTarget && title) {
      titleTarget.textContent = title;
    }

    if (messageTarget && message) {
      messageTarget.textContent = message;
    }
  }
}

function clearFileRows() {
  if (filesList) {
    filesList.replaceChildren();
  }
}

function normalizeFilesArray(value) {
  return Array.isArray(value) ? value : [];
}

function formatFileValue(value) {
  return value === null || value === undefined || value === "" ? "Unavailable" : String(value);
}

function formatFileType(entry) {
  if (!entry) {
    return "Unavailable";
  }

  if (entry.isDirectory) {
    return getFileTypeInfo(entry).label;
  }

  if (entry.type && entry.type !== "file") {
    return formatFileValue(entry.type);
  }

  return getFileTypeInfo(entry).label;
}

function normalizeRemotePathValue(value, fallback = "/") {
  const rawValue = String(value || "").trim();
  const fallbackValue = String(fallback || "/").trim() || "/";
  const sourceValue = rawValue || fallbackValue;
  const absoluteValue = sourceValue.startsWith("/") ? sourceValue : `${fallbackValue.replace(/\/+$/, "")}/${sourceValue}`;
  const segments = absoluteValue.split("/").filter(Boolean);
  const normalizedSegments = [];

  segments.forEach((segment) => {
    if (segment === ".") {
      return;
    }

    if (segment === "..") {
      normalizedSegments.pop();
      return;
    }

    normalizedSegments.push(segment);
  });

  return `/${normalizedSegments.join("/")}` || "/";
}

function joinRemotePath(basePath, childName) {
  return normalizeRemotePathValue(`${normalizeRemotePathValue(basePath).replace(/\/+$/, "")}/${String(childName || "").trim()}`);
}

function getRemoteParentPath(remotePath) {
  const normalizedPath = normalizeRemotePathValue(remotePath);

  if (normalizedPath === "/") {
    return "/";
  }

  const parts = normalizedPath.split("/").filter(Boolean);
  parts.pop();
  return parts.length > 0 ? `/${parts.join("/")}` : "/";
}

function isProtectedRemotePathForConfirm(remotePath) {
  const normalizedPath = normalizeRemotePathValue(remotePath);
  return normalizedPath === "/" || ["/etc", "/usr", "/bin"].some((candidate) => normalizedPath === candidate || normalizedPath.startsWith(`${candidate}/`));
}

function isConfiguredStorageRootPath(remotePath) {
  const normalizedPath = normalizeRemotePathValue(remotePath);
  const roots = normalizeFilesArray(latestFilesListing?.roots);
  return roots.some((root) => normalizeRemotePathValue(root?.path || root?.root || root?.directory || "") === normalizedPath);
}

function normalizeFileNameInput(value) {
  const name = String(value || "").trim();
  if (!name) return "";
  if (name.includes("\0") || name.includes("/") || name.includes("\\")) return "";
  if (name === "." || name === "..") return "";
  return name;
}

function findFileEntryByName(name, entries = latestFilesListing?.entries || []) {
  const normalized = String(name || "");
  return entries.find((entry) => String(entry.name || "") === normalized) || null;
}

function getFileConflictSummary(existing, incomingName, destinationPath) {
  const existingSize = existing?.isDirectory ? "Folder" : formatBytes(existing?.size);
  const modified = existing?.modifiedAt ? formatDateTime(existing.modifiedAt) : "Modified time unavailable";
  return [
    `Existing: ${existing?.name || incomingName} (${formatFileType(existing)}, ${existingSize}, ${modified})`,
    `Incoming: ${incomingName}`,
    `Destination: ${destinationPath}`,
    "Replacing is permanent for this location unless the backing filesystem provides its own recovery.",
  ].join("\n");
}

function resolveNameConflict({ incomingName, destinationPath, existing, allowReplace = true, allowRename = true } = {}) {
  if (!existing) return { action: "none", name: incomingName, path: destinationPath, replace: false };
  const choices = [];
  if (allowReplace) choices.push("Replace");
  if (allowRename) choices.push("Rename");
  choices.push("Cancel");
  const choice = window.prompt(
    `An item named "${incomingName}" already exists.\n\n${getFileConflictSummary(existing, incomingName, destinationPath)}\n\nChoose: ${choices.join(", ")}`,
    allowRename ? "Rename" : allowReplace ? "Replace" : "Cancel",
  );
  const normalizedChoice = String(choice || "").trim().toLowerCase();
  if (allowReplace && normalizedChoice === "replace") {
    return { action: "replace", name: incomingName, path: destinationPath, replace: true };
  }
  if (allowRename && normalizedChoice === "rename") {
    const renamed = normalizeFileNameInput(window.prompt("New destination name", `${incomingName}.copy`));
    if (!renamed) return { action: "cancel" };
    const renamedConflict = findFileEntryByName(renamed);
    if (renamedConflict) {
      showToast("That destination name already exists. Operation canceled.", "warning");
      return { action: "cancel" };
    }
    return {
      action: "rename",
      name: renamed,
      path: joinFilesPath(filesConnectionState.currentPath || filesConnectionState.homePath || "/", renamed),
      replace: false,
    };
  }
  return { action: "cancel" };
}

function shouldWarnLargeFile(entry, actionLabel) {
  return !entry?.isDirectory && Number(entry?.size || 0) >= FILE_LARGE_TRANSFER_WARN_BYTES
    ? window.confirm(`${actionLabel} ${entry.name}? This file is ${formatBytes(entry.size)}. Progress is shown only when the provider reports real bytes.`)
    : true;
}

function supportsFilesDirectoryCopy() {
  return Boolean(latestFilesListing?.local || getFilesConnectionTarget()?.providerType === "agent-native");
}

function canCopyFileEntry(entry) {
  return Boolean(entry && (!entry.isDirectory || supportsFilesDirectoryCopy()));
}

function compareFileEntries(left, right) {
  if (left.isDirectory !== right.isDirectory) {
    return left.isDirectory ? -1 : 1;
  }

  return String(left.name || "").localeCompare(String(right.name || ""), undefined, { sensitivity: "base" });
}

function getSelectedFileEntry(entries) {
  if (!selectedFileEntryPath) {
    return entries[0] || null;
  }

  return entries.find((entry) => entry.path && entry.path === selectedFileEntryPath) || entries[0] || null;
}

function selectFileEntry(entry) {
  const nextPath = entry?.path || null;
  const shouldClearEditor = !entry || entry.isDirectory || (latestFileDocument?.path && latestFileDocument.path !== nextPath);

  if (shouldClearEditor && hasDirtyFileEditor() && !confirmDiscardFileEditor(entry?.isDirectory ? `select ${entry.name}` : "select another item")) {
    renderFileRows(latestFilesListing?.entries || []);
    selectFileEntry(getSelectedFileEntry(latestFilesListing?.entries || []));
    return;
  }

  selectedFileEntryPath = entry?.path || null;
  getFilesProfileState().selectedFileEntryPath = selectedFileEntryPath;
  setFileDetails(entry);

  if (shouldClearEditor) {
    resetFileEditor("Select a file to preview or edit.");
  } else if (!latestFileDocument?.path || latestFileDocument?.path === selectedFileEntryPath) {
    setFileEditorPath(selectedFileEntryPath || null);
  }

  if (!filesList) {
    return;
  }

  [...filesList.querySelectorAll("tr")].forEach((row) => {
    row.classList.toggle("is-selected", row.dataset.filePath === selectedFileEntryPath);
    row.setAttribute("aria-selected", row.dataset.filePath === selectedFileEntryPath ? "true" : "false");
  });

  syncFileEditorButtons();
}

function getFileEntryBadge(entry) {
  return getFileTypeInfo(entry).badge;
}

function buildFileNameCell(entry) {
  const wrapper = document.createElement("div");
  wrapper.className = "file-entry-name";
  wrapper.title = entry.path || entry.name || "";

  const icon = document.createElement("span");
  icon.className = "file-entry-icon";
  icon.textContent = getFileEntryBadge(entry);
  wrapper.appendChild(icon);

  const text = document.createElement("div");
  text.className = "file-entry-name-text";

  const title = document.createElement("strong");
  title.textContent = formatFileValue(entry.name);
  title.title = formatFileValue(entry.name);
  text.appendChild(title);

  const meta = document.createElement("span");
  meta.textContent = getFileTypeInfo(entry).label;
  text.appendChild(meta);

  wrapper.appendChild(text);
  return wrapper;
}

function addFileCell(row, value) {
  const cell = document.createElement("td");

  if (value instanceof Node) {
    cell.appendChild(value);
  } else {
    cell.textContent = value;
  }

  row.appendChild(cell);
}

function filterFileRows() {
  const query = (filesSearchInput?.value || "").trim().toLowerCase();

  if (!filesList) {
    return;
  }

  [...filesList.querySelectorAll("tr")].forEach((row) => {
    row.hidden = query.length > 0 && !row.textContent.toLowerCase().includes(query);
  });
}

function renderFileRows(entries) {
  clearFileRows();

  if (!filesList) {
    return;
  }

  entries.forEach((entry) => {
    const row = document.createElement("tr");
    row.dataset.filePath = entry.path || entry.name || "";
    row.tabIndex = 0;
    row.setAttribute("role", "row");
    row.setAttribute("aria-selected", entry.path === selectedFileEntryPath ? "true" : "false");
    row.title = entry.path || entry.name || "";
    row.addEventListener("click", () => selectFileEntry(entry));
    row.addEventListener("dblclick", () => {
      handleFileEntryActivation(entry);
    });
    row.addEventListener("contextmenu", (event) => {
      event.preventDefault();
      selectFileEntry(entry);
      openFilesContextMenu(event.clientX, event.clientY, entry);
    });
    row.addEventListener("keydown", (event) => {
      if (event.key === "Enter") {
        event.preventDefault();
        handleFileEntryActivation(entry);
      }

      if (event.key === " ") {
        event.preventDefault();
        selectFileEntry(entry);
      }

      if ((event.shiftKey && event.key === "F10") || event.key === "ContextMenu") {
        event.preventDefault();
        const rect = row.getBoundingClientRect();
        selectFileEntry(entry);
        openFilesContextMenu(rect.left + 18, rect.top + 18, entry);
      }
    });
    addFileCell(row, buildFileNameCell(entry));
    addFileCell(row, formatFileType(entry));
    addFileCell(row, entry.isDirectory ? "Folder" : formatBytes(entry.size));
    addFileCell(row, formatDateTime(entry.modifiedAt));
    filesList.appendChild(row);
  });

  filterFileRows();
}

function getVisibleFileEntries() {
  const entries = latestFilesListing?.entries || [];
  const query = (filesSearchInput?.value || "").trim().toLowerCase();
  if (!query) return entries;
  return entries.filter((entry) => {
    const text = [entry.name, entry.path, formatFileType(entry), entry.isDirectory ? "Folder" : formatBytes(entry.size)].join(" ").toLowerCase();
    return text.includes(query);
  });
}

function focusSelectedFileRow() {
  if (!filesList || !selectedFileEntryPath) return;
  const row = filesList.querySelector(`tr[data-file-path="${CSS.escape(selectedFileEntryPath)}"]`);
  row?.focus?.();
}

function moveFileSelection(delta) {
  const entries = getVisibleFileEntries();
  if (entries.length === 0) return;
  const currentIndex = Math.max(0, entries.findIndex((entry) => entry.path === selectedFileEntryPath));
  const nextIndex = Math.min(Math.max(currentIndex + delta, 0), entries.length - 1);
  selectFileEntry(entries[nextIndex]);
  focusSelectedFileRow();
}

function closeFilesContextMenu({ restoreFocus = false } = {}) {
  if (filesContextMenuState.element) {
    filesContextMenuState.element.remove();
    filesContextMenuState.element = null;
  }
  if (restoreFocus) {
    filesContextMenuState.previousFocus?.focus?.();
  }
  filesContextMenuState.previousFocus = null;
}

function createFilesContextMenuItem({ label, action, disabled = false, reason = "" }) {
  const button = document.createElement("button");
  button.type = "button";
  button.className = "files-context-menu__item";
  button.role = "menuitem";
  button.disabled = disabled;
  button.textContent = label;
  if (disabled && reason) {
    button.title = reason;
    button.setAttribute("aria-label", `${label}. ${reason}`);
  }
  button.addEventListener("click", async () => {
    if (disabled) {
      if (reason) showToast(reason, "warning");
      return;
    }
    closeFilesContextMenu();
    await action?.();
  });
  return button;
}

function openFilesContextMenu(x, y, entry = getSelectedFileEntry(latestFilesListing?.entries || [])) {
  closeFilesContextMenu();
  if (!filesConnectionState.connected) return;
  filesContextMenuState.previousFocus = document.activeElement instanceof HTMLElement ? document.activeElement : null;
  const menu = document.createElement("div");
  menu.className = "files-context-menu";
  menu.role = "menu";
  menu.tabIndex = -1;
  menu.setAttribute("aria-label", entry ? `Actions for ${entry.name}` : "Files actions");
  const hasEntry = Boolean(entry);
  const isFile = hasEntry && !entry.isDirectory;
  const canMutate = filesConnectionState.connected && !filesActionRequestInFlight && !filesRequestInFlight;
  const canCopy = hasEntry && canCopyFileEntry(entry);
  const isStorageRoot = hasEntry && isConfiguredStorageRootPath(entry.path);
  const canPaste = filesClipboardState.action === "copy"
    && filesClipboardState.entry
    && (!filesClipboardState.targetKey || filesClipboardState.targetKey === (filesConnectionState.targetKey || getFilesConnectionTarget()?.key));
  const items = [
    { label: entry?.isDirectory ? "Open Folder" : "Open Text", action: () => handleFileEntryActivation(entry), disabled: !hasEntry, reason: "Select an item first." },
    { label: "Download", action: () => downloadRemoteFile(), disabled: !isFile, reason: entry?.isDirectory ? "Folders cannot be downloaded from this view." : "Select a file first." },
    { label: "Rename", action: () => renameRemoteEntry(), disabled: !hasEntry || !canMutate, reason: canMutate ? "Select an item first." : "A file operation is already running." },
    { label: "Copy", action: () => copyRemoteEntry(), disabled: !canCopy || !canMutate, reason: canCopy ? "A file operation is already running." : "Folder copy is not supported for this storage provider." },
    { label: "Paste", action: () => pasteFilesClipboard(), disabled: !canPaste || !canMutate, reason: canPaste ? "A file operation is already running." : "No compatible copied item is staged." },
    { label: "Copy Path", action: () => copyActiveFilePath(), disabled: !hasEntry, reason: "Select an item first." },
    {
      label: "Delete",
      action: () => deleteRemoteEntry(),
      disabled: !hasEntry || !canMutate || isStorageRoot,
      reason: isStorageRoot
        ? "Configured storage roots cannot be deleted from AnxOS."
        : (canMutate ? "Select an item first." : "A file operation is already running."),
    },
    { label: "Upload Here", action: () => uploadRemoteFile(), disabled: !canMutate, reason: "Connect a writable filesystem first." },
    { label: "New Folder", action: () => createRemoteFolder(), disabled: !canMutate, reason: "Connect a writable filesystem first." },
    { label: "New File", action: () => createRemoteFile(), disabled: !canMutate, reason: "Connect a writable filesystem first." },
    { label: "Refresh", action: () => refreshCurrentFilesDirectory(), disabled: filesRequestInFlight, reason: "Files are already refreshing." },
  ];
  items.forEach((item) => menu.appendChild(createFilesContextMenuItem(item)));
  document.body.appendChild(menu);
  const rect = menu.getBoundingClientRect();
  const left = Math.max(8, Math.min(x, window.innerWidth - rect.width - 8));
  const top = Math.max(8, Math.min(y, window.innerHeight - rect.height - 8));
  menu.style.left = `${left}px`;
  menu.style.top = `${top}px`;
  filesContextMenuState.element = menu;
  menu.focus();
}

function navigateFilesParentDirectory() {
  const current = filesConnectionState.currentPath || filesConnectionState.homePath || "/";
  const normalized = normalizeRemotePathValue(current);
  if (normalized === "/") return;
  const parent = normalized.split("/").filter(Boolean).slice(0, -1).join("/");
  navigateRemoteDirectory(parent ? `/${parent}` : "/");
}

function renderFileBreadcrumbs(listing) {
  if (!filesBreadcrumbBar) {
    return;
  }

  const breadcrumbs = normalizeFilesArray(listing?.breadcrumbs);

  filesBreadcrumbBar.replaceChildren();

  const root = document.createElement(filesConnectionState.connected ? "button" : "span");
  root.className = "breadcrumb-root";
  root.textContent = "Files";

  if (filesConnectionState.connected) {
    root.type = "button";
    root.addEventListener("click", () => navigateRemoteDirectory(filesConnectionState.homePath || "/"));
  }

  filesBreadcrumbBar.appendChild(root);

  if (breadcrumbs.length === 0) {
    const separator = document.createElement("span");
    separator.className = "breadcrumb-separator";
    separator.textContent = "/";
    filesBreadcrumbBar.appendChild(separator);

    const fallback = document.createElement("span");
    fallback.textContent = listing?.currentPath || listing?.message || "Unavailable";
    filesBreadcrumbBar.appendChild(fallback);
    return;
  }

  breadcrumbs.forEach((crumb) => {
    const separator = document.createElement("span");
    separator.className = "breadcrumb-separator";
    separator.textContent = "/";
    filesBreadcrumbBar.appendChild(separator);

    const segment = document.createElement(filesConnectionState.connected ? "button" : "span");
    segment.textContent = crumb?.name || crumb?.path || "Folder";

    if (filesConnectionState.connected) {
      segment.type = "button";
      segment.addEventListener("click", () => navigateRemoteDirectory(crumb?.path || filesConnectionState.currentPath));
    }

    filesBreadcrumbBar.appendChild(segment);
  });
}

function renderFolderRoots(listing) {
  if (!filesFolderPanel) {
    return;
  }

  const existingList = filesFolderPanel.querySelector(".folder-tree-list");

  if (existingList) {
    existingList.remove();
  }

  const roots = normalizeFilesArray(listing?.roots);

  if (filesFolderStatus) {
    filesFolderStatus.textContent = listing?.connected ? "Connected" : "Disconnected";
  }

  if (filesFolderEmpty) {
    filesFolderEmpty.hidden = roots.length > 0;

    const titleTarget = filesFolderEmpty.querySelector("strong");
    const messageTarget = filesFolderEmpty.querySelector("span:last-child");

    if (titleTarget) {
      titleTarget.textContent = listing?.connected ? "No folder roots available" : "No filesystem connected";
    }

    if (messageTarget) {
      messageTarget.textContent = listing?.connected
        ? "The file service did not return folder roots. Refresh the profile or check the Agent filesystem root."
        : (listing?.message || "Choose a server and storage profile, then connect to browse local files or an Agent filesystem.");
    }
  }

  if (roots.length === 0) {
    return;
  }

  const list = document.createElement("ul");
  list.className = "folder-tree-list";

  roots.forEach((root) => {
    const item = document.createElement("li");
    const label = document.createElement("button");
    label.type = "button";
    label.className = "inline-action";
    label.disabled = !filesConnectionState.connected;
    label.textContent = root?.name || root?.path || "Root";
    label.addEventListener("click", () => navigateRemoteDirectory(root?.path || filesConnectionState.homePath || "/"));
    item.appendChild(label);
    list.appendChild(item);
  });

  filesFolderPanel.appendChild(list);
}

function getStorageConnectionById(storageId = selectedStorageId) {
  return (storageConnectionsState.connections || []).find((connection) => connection.id === storageId) || null;
}

function getSelectedStorageConnection() {
  if (!selectedStorageId) {
    return null;
  }
  return getStorageConnectionById(selectedStorageId);
}

function storageConnectionLabel(connection) {
  return connection?.name || connection?.displayName || connection?.id || "Storage";
}

function getFilesNodeById(nodeId) {
  return (nodesState.nodes || []).find((node) => node.id === nodeId) || null;
}

function isGenericFilesNodeLabel(value) {
  return /^(owner machine|application host|default|remote node)$/i.test(String(value || "").trim());
}

function getFilesNodeUrlHost(node) {
  try {
    return new URL(String(node?.agentUrl || "")).host;
  } catch {
    return "";
  }
}

function getFilesLocalNodeLabel(node) {
  const platform = String(node?.applicationHost?.platform || node?.platform || "").toLowerCase();
  if (platform === "win32" || /windows/i.test(node?.applicationHost?.operatingSystem || node?.operatingSystem || "")) {
    return "This Windows PC";
  }
  return "This Device";
}

function getFilesNodeLabel(node) {
  if (!node) {
    return "Unknown node";
  }
  if (node.kind === "application-host" || node.local || node.id === "application-host") {
    return getFilesLocalNodeLabel(node);
  }
  const hostname = String(node.agentIdentity?.hostname || "").trim();
  if (hostname && !isGenericFilesNodeLabel(hostname)) {
    return hostname;
  }
  const displayName = String(node.displayName || node.name || "").trim();
  if (displayName && !isGenericFilesNodeLabel(displayName)) {
    return displayName;
  }
  return getFilesNodeUrlHost(node) || node.id || "Agent node";
}

function getFilesNodeServerId(nodeId) {
  return `${FILES_NODE_SERVER_PREFIX}${nodeId}`;
}

function getFilesLocalProfileId(nodeId) {
  return `${FILES_LOCAL_PROFILE_PREFIX}${nodeId}`;
}

function getFilesAgentProfileId(nodeId) {
  return `${FILES_AGENT_PROFILE_PREFIX}${nodeId}`;
}

function getFilesNodeProfileForNode(node) {
  if (!node) {
    return null;
  }
  const local = node.kind === "application-host" || node.local || node.id === "application-host";
  const label = getFilesNodeLabel(node);
  return {
    id: local ? getFilesLocalProfileId(node.id) : getFilesAgentProfileId(node.id),
    serverId: getFilesNodeServerId(node.id),
    type: local ? "local-node" : "agent-node",
    providerType: local ? "renderer-local" : "agent-native",
    nodeId: node.id,
    node,
    displayName: local ? "Local Filesystem" : `${label} Agent Filesystem`,
    detail: local ? `Local filesystem on ${label}` : `${node.agentIdentity?.operatingSystem || "Agent node"} · ${node.agentUrl || getFilesNodeUrlHost(node) || node.id}`,
  };
}

function getFilesNodeServers() {
  return (nodesState.nodes || [])
    .filter((node) => node?.id)
    .map((node) => ({
      id: getFilesNodeServerId(node.id),
      type: "node",
      nodeId: node.id,
      node,
      displayName: getFilesNodeLabel(node),
    }));
}

function getFilesProfileOptionById(profileId) {
  const id = String(profileId || "");
  if (id.startsWith(FILES_LOCAL_PROFILE_PREFIX) || id.startsWith(FILES_AGENT_PROFILE_PREFIX)) {
    const nodeId = id.startsWith(FILES_LOCAL_PROFILE_PREFIX)
      ? id.slice(FILES_LOCAL_PROFILE_PREFIX.length)
      : id.slice(FILES_AGENT_PROFILE_PREFIX.length);
    const profile = getFilesNodeProfileForNode(getFilesNodeById(nodeId));
    return profile?.id === id ? profile : null;
  }
  return getFilesProfileById(id);
}

function getFilesServerOptions() {
  return [
    ...getFilesNodeServers(),
    ...sshProfilesState.servers.map((server) => ({ ...server, type: "ssh" })),
  ];
}

function getFilesProfileOptionsForServer(serverId = filesSelectedServerId) {
  const id = String(serverId || "");
  if (id.startsWith(FILES_NODE_SERVER_PREFIX)) {
    return [getFilesNodeProfileForNode(getFilesNodeById(id.slice(FILES_NODE_SERVER_PREFIX.length)))].filter(Boolean);
  }
  return sshProfilesState.profiles.filter((profile) => {
    if (profile.nodeId && !getFilesNodeById(profile.nodeId)) return false;
    return !id || profile.serverId === id;
  }).map((profile) => ({ ...profile, type: "ssh" }));
}

function clampPercent(value) {
  const number = Number(value);
  return Number.isFinite(number) ? Math.max(0, Math.min(100, number)) : null;
}

function redactOperationText(value) {
  return String(value ?? "")
    .replace(/(Bearer|token|password|api[_-]?key|secret)=?\s*[^\s,;]+/gi, "$1=[redacted]")
    .replace(/(Authorization:\s*)[^\n]+/gi, "$1[redacted]")
    .replace(/([A-Za-z]:\\Users\\)[^\\\n]+/g, "$1[redacted]")
    .replace(/\/home\/[^/\n]+/g, "/home/[redacted]")
    .slice(0, 1200);
}

function operationStatusLabel(status) {
  return {
    queued: "Queued",
    running: "Running",
    waiting: "Waiting",
    completed: "Completed",
    failed: "Failed",
    canceled: "Canceled",
  }[status] || "Running";
}

function normalizeOperationStatus(status) {
  if (["queued", "running", "waiting", "completed", "failed", "canceled"].includes(status)) {
    return status;
  }
  if (status === "complete" || status === "done" || status === "success") return "completed";
  if (status === "cancelled") return "canceled";
  if (status === "error") return "failed";
  return "running";
}

function operationStatusTone(status) {
  if (status === "completed") return "status-pill--ok";
  if (status === "failed") return "status-pill--critical";
  if (status === "canceled" || status === "waiting") return "status-pill--warning";
  return "status-pill--planned";
}

function createOperationId(type = "operation") {
  return `${type}:${Date.now()}:${Math.random().toString(16).slice(2)}`;
}

function serializeOperation(operation) {
  return {
    id: operation.id,
    type: operation.type,
    title: operation.title,
    target: operation.target,
    status: operation.status,
    step: operation.step,
    percent: operation.percent,
    startedAt: operation.startedAt,
    updatedAt: operation.updatedAt,
    completedAt: operation.completedAt,
    error: operation.error,
    logs: Array.isArray(operation.logs) ? operation.logs.slice(-12) : [],
  };
}

function persistOperationHistory() {
  if (!operationsState.loaded) return;
  try {
    const history = [...operationsState.items.values()]
      .sort((a, b) => (b.updatedAt || 0) - (a.updatedAt || 0))
      .slice(0, 80)
      .map(serializeOperation);
    window.localStorage.setItem(OPERATIONS_STORAGE_KEY, JSON.stringify(history));
  } catch {
    // Operation history is non-critical and should never block runtime actions.
  }
}

function loadOperationHistory() {
  if (operationsState.loaded) return;
  operationsState.loaded = true;
  try {
    const parsed = JSON.parse(window.localStorage.getItem(OPERATIONS_STORAGE_KEY) || "[]");
    if (!Array.isArray(parsed)) return;
    parsed.slice(0, 80).forEach((entry) => {
      if (!entry?.id || !entry?.title) return;
      operationsState.items.set(entry.id, {
        id: String(entry.id),
        type: redactOperationText(entry.type || "Operation"),
        title: redactOperationText(entry.title),
        target: redactOperationText(entry.target || ""),
        status: normalizeOperationStatus(entry.status),
        step: redactOperationText(entry.step || ""),
        percent: clampPercent(entry.percent),
        startedAt: Number(entry.startedAt) || Date.now(),
        updatedAt: Number(entry.updatedAt) || Date.now(),
        completedAt: Number(entry.completedAt) || null,
        error: entry.error ? redactOperationText(entry.error) : "",
        logs: Array.isArray(entry.logs) ? entry.logs.slice(-12).map(redactOperationText) : [],
      });
    });
  } catch {
    window.localStorage.removeItem(OPERATIONS_STORAGE_KEY);
  }
}

const NOTIFICATION_ACTIONS = {
  openOperations: { label: "Open Operations", run: (notification) => openNotificationRelatedOperation(notification) },
  openDiagnostics: { label: "Open Diagnostics", run: (notification) => openNotificationDiagnostics(notification) },
  openMarketplace: { label: "Open Marketplace", run: () => showPage("marketplace") },
  openFiles: { label: "Open Files", run: () => showPage("files") },
  openMaintenance: { label: "Open Maintenance", run: () => showPage("maintenance") },
  openSecurity: { label: "Open Security", run: () => showPage("security") },
  openAccount: { label: "Open Account", run: () => showPage("security") },
  openUpdates: { label: "Open Updates", run: () => { showPage("settings"); setActiveSettingsCategory("updates", '[data-settings-category="updates"]'); } },
  reconnectAgent: { label: "Reconnect Agent", run: () => refreshAgentControl({ includeConfig: true }) },
  recheckDependencies: { label: "Recheck Dependencies", run: () => runDependencyAction("check") },
  checkUpdates: { label: "Check Updates", run: () => checkForUpdates({ silent: false }) },
  copyMessage: { label: "Copy Details", run: (notification) => copyNotificationDetails(notification) },
};

function sanitizeNotificationText(value = "", limit = NOTIFICATION_MAX_MESSAGE_LENGTH) {
  return redactOperationText(value)
    .replace(/\b[A-Za-z0-9+/]{180,}={0,2}\b/g, "[redacted-base64]")
    .replace(/\s+/g, " ")
    .trim()
    .slice(0, limit);
}

function normalizeNotificationSeverity(severity = "info") {
  const normalized = String(severity || "info").toLowerCase();
  if (normalized === "fatal") return "critical";
  if (normalized === "warn") return "warning";
  return NOTIFICATION_SEVERITIES.includes(normalized) ? normalized : "info";
}

function normalizeNotificationCategory(category = "Application") {
  const normalized = String(category || "Application").trim();
  return NOTIFICATION_CATEGORIES.find((entry) => entry.toLowerCase() === normalized.toLowerCase()) || "Application";
}

function notificationSeverityLabel(severity = "info") {
  return {
    info: "Info",
    success: "Success",
    warning: "Warning",
    error: "Error",
    critical: "Critical",
  }[normalizeNotificationSeverity(severity)] || "Info";
}

function notificationSeverityTone(severity = "info") {
  return {
    info: "status-pill--planned",
    success: "status-pill--ok",
    warning: "status-pill--warning",
    error: "status-pill--critical",
    critical: "status-pill--critical",
  }[normalizeNotificationSeverity(severity)] || "status-pill--planned";
}

function isNotificationExpired(notification, now = Date.now()) {
  if (notification.pinned || notification.resolved === false || notification.severity === "critical") return false;
  const age = now - Number(notification.lastSeen || notification.createdAt || now);
  const retention = notification.severity === "info"
    ? NOTIFICATION_INFO_RETENTION_MS
    : notification.severity === "success"
      ? NOTIFICATION_DEFAULT_RETENTION_MS
      : NOTIFICATION_CRITICAL_RETENTION_MS;
  return age > retention;
}

function serializeNotification(notification) {
  return {
    id: String(notification.id),
    dedupKey: String(notification.dedupKey || notification.id),
    category: normalizeNotificationCategory(notification.category),
    severity: normalizeNotificationSeverity(notification.severity),
    title: sanitizeNotificationText(notification.title || "Notification", 120),
    message: sanitizeNotificationText(notification.message || "", NOTIFICATION_MAX_MESSAGE_LENGTH),
    createdAt: Number(notification.createdAt) || Date.now(),
    firstSeen: Number(notification.firstSeen) || Number(notification.createdAt) || Date.now(),
    lastSeen: Number(notification.lastSeen) || Date.now(),
    read: notification.read === true,
    pinned: notification.pinned === true,
    resolved: notification.resolved !== false,
    occurrenceCount: Math.max(1, Number(notification.occurrenceCount) || 1),
    relatedOperationId: notification.relatedOperationId ? sanitizeNotificationText(notification.relatedOperationId, 160) : "",
    relatedDiagnosticCode: notification.relatedDiagnosticCode ? sanitizeNotificationText(notification.relatedDiagnosticCode, 80) : "",
    relatedWorkspace: notification.relatedWorkspace ? sanitizeNotificationText(notification.relatedWorkspace, 80) : "",
    actions: Array.isArray(notification.actions) ? notification.actions.filter((action) => NOTIFICATION_ACTIONS[action]).slice(0, 4) : [],
    occurrences: Array.isArray(notification.occurrences)
      ? notification.occurrences.slice(-NOTIFICATION_OCCURRENCE_LIMIT).map((entry) => ({
        timestamp: Number(entry.timestamp) || Date.now(),
        message: sanitizeNotificationText(entry.message || "", 220),
      }))
      : [],
  };
}

function persistNotificationHistory() {
  if (!notificationState.loaded || getCurrentSettings()["notifications.persistHistory"] === false) return;
  try {
    const history = notificationState.items
      .filter((item) => !isNotificationExpired(item))
      .sort((a, b) => (b.lastSeen || 0) - (a.lastSeen || 0))
      .slice(0, NOTIFICATION_HISTORY_LIMIT)
      .map(serializeNotification);
    window.localStorage.setItem(NOTIFICATIONS_STORAGE_KEY, JSON.stringify(history));
  } catch {
    if (notificationStatus) notificationStatus.textContent = "Notification history could not be persisted.";
  }
}

function loadNotificationHistory() {
  if (notificationState.loaded) return;
  notificationState.loaded = true;
  try {
    const parsed = JSON.parse(window.localStorage.getItem(NOTIFICATIONS_STORAGE_KEY) || "[]");
    if (!Array.isArray(parsed)) return;
    notificationState.items = parsed
      .map((entry) => {
        if (!entry?.id || !entry?.title) return null;
        return serializeNotification(entry);
      })
      .filter(Boolean)
      .filter((entry) => !isNotificationExpired(entry))
      .slice(0, NOTIFICATION_HISTORY_LIMIT);
  } catch {
    notificationState.items = [];
    window.localStorage.removeItem(NOTIFICATIONS_STORAGE_KEY);
  }
}

function inferNotificationCategoryFromText(message = "") {
  const text = String(message || "").toLowerCase();
  if (/\bmarketplace|template|install|modpack\b/.test(text)) return "Marketplace";
  if (/\bdependency|runtime|java|steamcmd|docker\b/.test(text)) return "Dependencies";
  if (/\bfile|folder|upload|download|storage\b/.test(text)) return "Files";
  if (/\bagent|node|connection\b/.test(text)) return "Agent";
  if (/\bdiagnostic|log\b/.test(text)) return "Diagnostics";
  if (/\bmaintenance|cache|cleanup\b/.test(text)) return "Maintenance";
  if (/\bsecurity|token|session|owner\b/.test(text)) return "Security";
  if (/\baccount|sign in|signed out\b/.test(text)) return "Account";
  if (/\bupdate|release\b/.test(text)) return "Updates";
  if (/\bbackup|restore\b/.test(text)) return "Backups";
  return "Application";
}

function getOperationNotificationCategory(operation = {}) {
  const type = String(operation.type || operation.title || "").toLowerCase();
  if (type.includes("marketplace")) return "Marketplace";
  if (type.includes("dependency")) return "Dependencies";
  if (type.includes("file")) return "Files";
  if (type.includes("diagnostic")) return "Diagnostics";
  if (type.includes("maintenance")) return "Maintenance";
  if (type.includes("security")) return "Security";
  if (type.includes("account")) return "Account";
  if (type.includes("update")) return "Updates";
  if (type.includes("backup")) return "Backups";
  if (type.includes("agent")) return "Agent";
  return "Operations";
}

function shouldPersistToastNotification(message, severity) {
  if (getCurrentSettings()["notifications.persistHistory"] === false) return false;
  const text = String(message || "");
  if (!text.trim()) return false;
  if (/\b(copied|copy|opened|selected|filter|search cleared|toast test|test notification)\b/i.test(text)) return false;
  return ["warning", "error", "critical"].includes(normalizeNotificationSeverity(severity));
}

function createNotification(input = {}) {
  loadNotificationHistory();
  if (getCurrentSettings()["notifications.persistHistory"] === false) return null;
  const now = Date.now();
  const severity = normalizeNotificationSeverity(input.severity);
  const category = normalizeNotificationCategory(input.category || inferNotificationCategoryFromText(`${input.title || ""} ${input.message || ""}`));
  const title = sanitizeNotificationText(input.title || notificationSeverityLabel(severity), 120);
  const message = sanitizeNotificationText(input.message || title, NOTIFICATION_MAX_MESSAGE_LENGTH);
  const dedupKey = sanitizeNotificationText(input.dedupKey || `${category}:${severity}:${input.eventType || title}:${input.relatedOperationId || input.relatedDiagnosticCode || ""}`, 220);
  const existing = notificationState.items.find((item) => item.dedupKey === dedupKey && now - Number(item.lastSeen || now) <= NOTIFICATION_DEDUP_WINDOW_MS);
  if (existing) {
    existing.message = message;
    existing.lastSeen = now;
    existing.read = false;
    existing.resolved = input.resolved !== false;
    existing.occurrenceCount = Math.max(1, Number(existing.occurrenceCount || 1) + 1);
    existing.occurrences = [...(existing.occurrences || []), { timestamp: now, message }].slice(-NOTIFICATION_OCCURRENCE_LIMIT);
    if (severity === "critical") existing.pinned = true;
  } else {
    notificationState.items.unshift(serializeNotification({
      id: input.id || `notification:${now}:${Math.random().toString(16).slice(2)}`,
      dedupKey,
      category,
      severity,
      title,
      message,
      createdAt: now,
      firstSeen: now,
      lastSeen: now,
      read: false,
      pinned: severity === "critical" || input.pinned === true,
      resolved: input.resolved !== false,
      occurrenceCount: 1,
      relatedOperationId: input.relatedOperationId || "",
      relatedDiagnosticCode: input.relatedDiagnosticCode || "",
      relatedWorkspace: input.relatedWorkspace || "",
      actions: input.actions || [],
      occurrences: [{ timestamp: now, message }],
    }));
  }
  notificationState.items = notificationState.items
    .filter((item) => !isNotificationExpired(item))
    .sort((a, b) => (b.pinned === true) - (a.pinned === true) || (b.lastSeen || 0) - (a.lastSeen || 0))
    .slice(0, NOTIFICATION_HISTORY_LIMIT);
  persistNotificationHistory();
  renderNotificationCenter();
  return notificationState.items.find((item) => item.dedupKey === dedupKey) || null;
}

function createOperationNotification(operation = {}) {
  const status = normalizeOperationStatus(operation.status);
  if (!["completed", "failed", "canceled"].includes(status)) return;
  const failed = status === "failed";
  createNotification({
    category: getOperationNotificationCategory(operation),
    severity: failed ? "error" : status === "canceled" ? "warning" : "success",
    title: failed ? `${operation.title || "Operation"} failed` : `${operation.title || "Operation"} ${status}`,
    message: failed ? operation.error || operation.step || "Operation failed." : operation.step || operationStatusLabel(status),
    dedupKey: `operation:${operation.id}:${status}`,
    relatedOperationId: operation.id,
    relatedWorkspace: "operations",
    actions: failed ? ["openOperations", "openDiagnostics", "copyMessage"] : ["openOperations"],
    resolved: !failed,
  });
}

function getFilteredNotifications() {
  loadNotificationHistory();
  const filter = notificationState.filter;
  return notificationState.items.filter((notification) => {
    const matchesFilter =
      filter === "all" ||
      (filter === "unread" && !notification.read) ||
      (filter === "pinned" && notification.pinned) ||
      (filter === "critical" && notification.severity === "critical");
    const matchesCategory = notificationState.category === "all" || notification.category === notificationState.category;
    const matchesSeverity = notificationState.severity === "all" || notification.severity === notificationState.severity;
    return matchesFilter && matchesCategory && matchesSeverity;
  });
}

function updateNotificationCategoryOptions() {
  if (!notificationCategorySelect) return;
  const current = notificationCategorySelect.value || "all";
  const categories = [...new Set(notificationState.items.map((item) => item.category))].sort();
  notificationCategorySelect.replaceChildren();
  const all = document.createElement("option");
  all.value = "all";
  all.textContent = "All categories";
  notificationCategorySelect.append(all);
  categories.forEach((category) => {
    const option = document.createElement("option");
    option.value = category;
    option.textContent = category;
    notificationCategorySelect.append(option);
  });
  notificationCategorySelect.value = categories.includes(current) ? current : "all";
  notificationState.category = notificationCategorySelect.value;
}

function updateNotificationSummaries() {
  const unread = notificationState.items.filter((item) => !item.read).length;
  const pinned = notificationState.items.filter((item) => item.pinned).length;
  const critical = notificationState.items.filter((item) => item.severity === "critical").length;
  const values = { unread, pinned, critical, total: notificationState.items.length };
  notificationSummaryFields.forEach((field) => {
    const key = field.dataset.notificationSummary;
    field.textContent = String(values[key] ?? 0);
  });
  if (notificationNavCount) {
    notificationNavCount.hidden = unread === 0;
    notificationNavCount.textContent = String(Math.min(unread, 99));
    notificationNavCount.setAttribute("aria-label", `${unread} unread notification${unread === 1 ? "" : "s"}`);
  }
}

function createNotificationActionButton(notification, actionId) {
  const action = NOTIFICATION_ACTIONS[actionId];
  if (!action) return null;
  const button = document.createElement("button");
  button.type = "button";
  button.className = "inline-action";
  button.textContent = action.label;
  button.addEventListener("click", async () => {
    try {
      await action.run(notification);
      notification.read = true;
      persistNotificationHistory();
      renderNotificationCenter();
    } catch (error) {
      showToast(normalizeIpcErrorMessage(error, "Notification action failed."), "error");
    }
  });
  return button;
}

function renderNotificationCenter() {
  loadNotificationHistory();
  updateNotificationCategoryOptions();
  updateNotificationSummaries();
  notificationFilterButtons.forEach((button) => {
    const active = button.dataset.notificationFilter === notificationState.filter;
    button.classList.toggle("is-active", active);
    button.setAttribute("aria-pressed", active ? "true" : "false");
  });
  if (notificationSeveritySelect) notificationSeveritySelect.value = notificationState.severity;
  if (!notificationList) return;
  notificationList.replaceChildren();
  const visible = getFilteredNotifications();
  if (notificationStatus) {
    notificationStatus.textContent = `${visible.length} notification${visible.length === 1 ? "" : "s"} shown.`;
  }
  if (!visible.length) {
    const empty = document.createElement("div");
    empty.className = "notification-empty";
    const title = createTextElement("strong", notificationState.items.length ? "No notifications match the current filters." : "No durable notifications yet.");
    const message = createTextElement("span", notificationState.items.length ? "Clear filters or wait for new application events." : "Important warnings, failures, and operation outcomes will appear here.");
    empty.append(title, message);
    notificationList.append(empty);
    return;
  }
  visible.forEach((notification) => {
    const item = document.createElement("article");
    item.className = "notification-item";
    item.dataset.severity = notification.severity;
    item.dataset.read = notification.read ? "true" : "false";
    item.setAttribute("role", "article");
    item.setAttribute("aria-label", `${notificationSeverityLabel(notification.severity)} ${notification.category} notification: ${notification.title}`);

    const header = document.createElement("div");
    header.className = "notification-item__header";
    const titleWrap = document.createElement("div");
    titleWrap.className = "notification-item__title";
    const title = createTextElement("strong", notification.title);
    const meta = createTextElement("small", [
      notification.category,
      notificationSeverityLabel(notification.severity),
      notification.occurrenceCount > 1 ? `${notification.occurrenceCount} occurrences` : "",
      formatDateTime(notification.lastSeen),
    ].filter(Boolean).join(" · "));
    titleWrap.append(title, meta);
    const badges = document.createElement("div");
    badges.className = "notification-item__badges";
    badges.append(createTextElement("span", notification.read ? "Read" : "Unread", `status-pill ${notification.read ? "status-pill--planned" : "status-pill--external"}`));
    badges.append(createTextElement("span", notificationSeverityLabel(notification.severity), `status-pill ${notificationSeverityTone(notification.severity)}`));
    if (notification.pinned) badges.append(createTextElement("span", "Pinned", "status-pill status-pill--manual"));
    header.append(titleWrap, badges);

    const message = createTextElement("p", notification.message || "No message available.");
    message.title = notification.message || "";

    const actions = document.createElement("div");
    actions.className = "notification-item__actions";
    const mark = document.createElement("button");
    mark.type = "button";
    mark.className = "inline-action";
    mark.textContent = notification.read ? "Mark Unread" : "Mark Read";
    mark.addEventListener("click", () => {
      notification.read = !notification.read;
      persistNotificationHistory();
      renderNotificationCenter();
    });
    const pin = document.createElement("button");
    pin.type = "button";
    pin.className = "inline-action";
    pin.textContent = notification.pinned ? "Unpin" : "Pin";
    pin.addEventListener("click", () => {
      notification.pinned = !notification.pinned;
      persistNotificationHistory();
      renderNotificationCenter();
    });
    actions.append(mark, pin);
    (notification.actions || []).forEach((actionId) => {
      const button = createNotificationActionButton(notification, actionId);
      if (button) actions.append(button);
    });
    const clear = document.createElement("button");
    clear.type = "button";
    clear.className = "inline-action";
    clear.textContent = "Clear";
    clear.disabled = notification.severity === "critical" && notification.resolved === false;
    clear.title = clear.disabled ? "Unresolved critical notifications require explicit review and cannot be cleared here." : "";
    clear.addEventListener("click", () => {
      notificationState.items = notificationState.items.filter((item) => item.id !== notification.id);
      persistNotificationHistory();
      renderNotificationCenter();
    });
    actions.append(clear);

    if ((notification.occurrences || []).length > 1) {
      const details = document.createElement("details");
      details.className = "notification-occurrences";
      const summary = createTextElement("summary", "Recent occurrences");
      const list = document.createElement("ol");
      notification.occurrences.forEach((occurrence) => {
        const row = document.createElement("li");
        row.textContent = `${formatDateTime(occurrence.timestamp)} ${occurrence.message}`;
        list.append(row);
      });
      details.append(summary, list);
      item.append(header, message, details, actions);
    } else {
      item.append(header, message, actions);
    }
    notificationList.append(item);
  });
}

function openNotificationRelatedOperation(notification) {
  if (!notification?.relatedOperationId) {
    showToast("This notification has no related operation.", "warning");
    return;
  }
  loadOperationHistory();
  if (!operationsState.items.has(notification.relatedOperationId)) {
    showToast("The related operation is no longer available.", "warning");
    return;
  }
  operationsState.selectedId = notification.relatedOperationId;
  showPage("operations");
  renderOperationsCenter();
}

function openNotificationDiagnostics(notification) {
  showPage("agent-control");
  if (agentLogSearch) {
    agentLogSearch.value = notification.relatedDiagnosticCode || notification.title || "";
    renderAgentLogs();
    agentLogSearch.focus();
  }
}

async function copyNotificationDetails(notification) {
  const text = [
    `Notification: ${notification.title}`,
    `Category: ${notification.category}`,
    `Severity: ${notificationSeverityLabel(notification.severity)}`,
    `Last seen: ${formatDateTime(notification.lastSeen)}`,
    `Occurrences: ${notification.occurrenceCount}`,
    `Message: ${notification.message}`,
  ].join("\n");
  await navigator.clipboard.writeText(text);
  showToast("Notification details copied.", "success");
}

function markAllNotificationsRead() {
  loadNotificationHistory();
  notificationState.items.forEach((item) => { item.read = true; });
  persistNotificationHistory();
  renderNotificationCenter();
}

function clearReadNotifications() {
  loadNotificationHistory();
  notificationState.items = notificationState.items.filter((item) => !item.read || item.pinned || (item.severity === "critical" && item.resolved === false));
  persistNotificationHistory();
  renderNotificationCenter();
}

function clearNoncriticalNotifications() {
  loadNotificationHistory();
  notificationState.items = notificationState.items.filter((item) => item.severity === "critical" || item.pinned);
  persistNotificationHistory();
  renderNotificationCenter();
}

function appendOperationLog(operation, message) {
  if (!operation || !message) return;
  operation.logs = [...(operation.logs || []), `${new Date().toLocaleTimeString()} ${redactOperationText(message)}`].slice(-24);
}

function startOperation({ id, type = "Operation", title = "Operation", target = "", step = "Starting", percent = null, cancel = null } = {}) {
  loadOperationHistory();
  const operationId = id || createOperationId(type.toLowerCase().replace(/[^a-z0-9]+/g, "-") || "operation");
  const now = Date.now();
  const existing = operationsState.items.get(operationId);
  const operation = {
    ...(existing || {}),
    id: operationId,
    type: redactOperationText(type),
    title: redactOperationText(title),
    target: redactOperationText(target),
    status: "running",
    step: redactOperationText(step),
    percent: clampPercent(percent),
    startedAt: existing?.startedAt || now,
    updatedAt: now,
    completedAt: null,
    error: "",
    cancel,
    logs: existing?.logs || [],
  };
  appendOperationLog(operation, step);
  operationsState.items.set(operationId, operation);
  operationsState.selectedId = operationId;
  renderOperationsCenter();
  persistOperationHistory();
  return operationId;
}

function updateOperation(id, patch = {}) {
  loadOperationHistory();
  const operation = operationsState.items.get(id);
  if (!operation) return null;
  if (patch.type) operation.type = redactOperationText(patch.type);
  if (patch.title) operation.title = redactOperationText(patch.title);
  if (patch.target !== undefined) operation.target = redactOperationText(patch.target);
  if (patch.status) operation.status = normalizeOperationStatus(patch.status);
  if (patch.step !== undefined) operation.step = redactOperationText(patch.step);
  if (patch.percent !== undefined) operation.percent = clampPercent(patch.percent);
  if (patch.error !== undefined) operation.error = redactOperationText(patch.error);
  if (patch.cancel !== undefined) operation.cancel = patch.cancel;
  operation.updatedAt = Date.now();
  if (["completed", "failed", "canceled"].includes(operation.status)) {
    operation.completedAt = operation.completedAt || operation.updatedAt;
    operation.percent = operation.percent ?? (operation.status === "completed" ? 100 : null);
    operation.cancel = null;
  }
  if (patch.log || patch.step || patch.error) {
    appendOperationLog(operation, patch.log || patch.error || patch.step);
  }
  renderOperationsCenter();
  persistOperationHistory();
  return operation;
}

function finishOperation(id, ok, message) {
  const operation = updateOperation(id, {
    status: ok ? "completed" : "failed",
    percent: ok ? 100 : undefined,
    step: message || (ok ? "Completed" : "Failed"),
    error: ok ? "" : message || "Operation failed.",
  });
  if (operation) createOperationNotification(operation);
  return operation;
}

function operationMatchesFilter(operation) {
  const filter = operationsState.filter;
  if (filter === "all") return true;
  if (filter === "running") return ["queued", "running", "waiting"].includes(operation.status);
  return operation.status === filter;
}

function createProgressBar(percent, status) {
  const progress = document.createElement("div");
  progress.className = "operation-progress";
  if (percent === null && ["queued", "running", "waiting"].includes(status)) {
    progress.classList.add("is-indeterminate");
  }
  const bar = document.createElement("span");
  if (percent !== null) {
    progress.style.setProperty("--operation-progress", `${percent}%`);
  }
  progress.append(bar);
  return progress;
}

function renderOperationDetail(operation) {
  if (!operationDetail) return;
  operationDetail.replaceChildren();
  if (!operation) {
    if (operationDetailStatus) {
      operationDetailStatus.textContent = "Idle";
      operationDetailStatus.className = "status-pill status-pill--planned";
    }
    const title = document.createElement("strong");
    title.textContent = "No operation selected";
    const message = document.createElement("span");
    message.textContent = "Select an operation to inspect its last known step, error reason, and sanitized log history.";
    operationDetail.append(title, message);
    return;
  }
  if (operationDetailStatus) {
    operationDetailStatus.textContent = operationStatusLabel(operation.status);
    operationDetailStatus.className = `status-pill ${operationStatusTone(operation.status)}`;
  }
  const title = document.createElement("strong");
  title.textContent = operation.title;
  const meta = document.createElement("span");
  meta.textContent = `${operation.type}${operation.target ? ` · ${operation.target}` : ""}`;
  const step = document.createElement("span");
  step.textContent = operation.step || operationStatusLabel(operation.status);
  operationDetail.append(title, meta, step);
  if (operation.error) {
    const error = document.createElement("span");
    error.className = "operation-detail__error";
    error.textContent = operation.error;
    operationDetail.append(error);
  }
  const logs = document.createElement("pre");
  logs.textContent = operation.logs?.length ? operation.logs.join("\n") : "No operation logs captured yet.";
  operationDetail.append(logs);
}

function renderOperationsCenter() {
  if (!operationList && !operationSummaryFields.length) return;
  loadOperationHistory();
  const operations = [...operationsState.items.values()].sort((a, b) => (b.updatedAt || 0) - (a.updatedAt || 0));
  const runningCount = operations.filter((operation) => ["queued", "running", "waiting"].includes(operation.status)).length;
  const completedCount = operations.filter((operation) => operation.status === "completed").length;
  const failedCount = operations.filter((operation) => operation.status === "failed").length;
  const lastOperation = operations[0] || null;
  operationSummaryFields.forEach((field) => {
    const key = field.dataset.operationsSummary;
    if (key === "running") field.textContent = String(runningCount);
    if (key === "completed") field.textContent = String(completedCount);
    if (key === "failed") field.textContent = String(failedCount);
    if (key === "total") field.textContent = `${operations.length} total`;
    if (key === "last") field.textContent = lastOperation ? operationStatusLabel(lastOperation.status) : "No activity";
  });
  operationFilterButtons.forEach((button) => {
    const active = button.dataset.operationFilter === operationsState.filter;
    button.classList.toggle("is-active", active);
    button.setAttribute("aria-pressed", active ? "true" : "false");
  });
  if (!operationList) {
    renderOperationDetail(operationsState.items.get(operationsState.selectedId));
    return;
  }
  operationList.replaceChildren();
  const visible = operations.filter(operationMatchesFilter);
  if (!visible.length) {
    const empty = document.createElement("div");
    empty.className = "operation-empty-state";
    const title = document.createElement("strong");
    title.textContent = operations.length ? "No operations match this filter" : "No operations recorded";
    const message = document.createElement("span");
    message.textContent = operations.length
      ? "Change the filter to inspect other recent activity."
      : "Marketplace installs, file transfers, Agent actions, diagnostics, updates, and backups will appear here when they run.";
    empty.append(title, message);
    operationList.append(empty);
  } else {
    visible.forEach((operation) => {
      const item = document.createElement("article");
      item.className = "operation-item";
      item.classList.toggle("is-selected", operation.id === operationsState.selectedId);
      item.dataset.status = operation.status;
      const button = document.createElement("button");
      button.type = "button";
      button.className = "operation-item__main";
      button.addEventListener("click", () => {
        operationsState.selectedId = operation.id;
        renderOperationsCenter();
      });
      const header = document.createElement("span");
      header.className = "operation-item__header";
      const title = document.createElement("strong");
      title.textContent = operation.title;
      const status = document.createElement("span");
      status.className = `status-pill ${operationStatusTone(operation.status)}`;
      status.textContent = operationStatusLabel(operation.status);
      header.append(title, status);
      const step = document.createElement("small");
      step.textContent = operation.step || operation.target || operation.type;
      button.append(header, step, createProgressBar(operation.percent, operation.status));
      item.append(button);
      if (operation.cancel && ["running", "queued", "waiting"].includes(operation.status)) {
        const cancelButton = document.createElement("button");
        cancelButton.type = "button";
        cancelButton.className = "inline-action";
        cancelButton.textContent = "Cancel";
        cancelButton.addEventListener("click", () => cancelOperation(operation.id));
        item.append(cancelButton);
      }
      operationList.append(item);
    });
  }
  const selected = visible.find((operation) => operation.id === operationsState.selectedId) || visible[0] || null;
  if (selected && selected.id !== operationsState.selectedId) operationsState.selectedId = selected.id;
  renderOperationDetail(selected);
}

async function cancelOperation(id) {
  const operation = operationsState.items.get(id);
  if (!operation?.cancel) return;
  updateOperation(id, { step: "Canceling", log: "Cancel requested by user." });
  try {
    if (operation.cancel.type === "file-transfer") {
      await cancelFileTransfer(operation.cancel.transferId);
    }
  } catch (error) {
    updateOperation(id, {
      status: "failed",
      error: normalizeIpcErrorMessage(error, "Cancel request failed."),
    });
  }
}

function maintenanceStatusLabel(status) {
  return {
    calculating: "Calculating",
    available: "Available",
    empty: "Empty",
    clearing: "Clearing",
    cleared: "Cleared",
    failed: "Failed",
    partial: "Partial",
    unsupported: "Unsupported",
  }[status] || "Unknown";
}

function maintenanceStatusTone(status) {
  if (status === "available" || status === "cleared") return "status-pill--ok";
  if (status === "failed" || status === "partial") return "status-pill--critical";
  if (status === "unsupported" || status === "empty") return "status-pill--warning";
  return "status-pill--planned";
}

function setMaintenanceStatus(message, tone = "neutral") {
  if (maintenanceStatus) {
    maintenanceStatus.textContent = message;
    maintenanceStatus.dataset.tone = tone;
  }
}

function getMaintenanceCategory(id) {
  return maintenanceState.categories.find((category) => category.id === id) || null;
}

function renderMaintenanceDetail(category = getMaintenanceCategory(maintenanceState.activeId)) {
  if (!maintenanceDetail) return;
  maintenanceDetail.replaceChildren();
  if (!category) {
    if (maintenanceDetailStatus) {
      maintenanceDetailStatus.textContent = "Idle";
      maintenanceDetailStatus.className = "status-pill status-pill--planned";
    }
    const title = document.createElement("strong");
    title.textContent = "No category selected";
    const message = document.createElement("span");
    message.textContent = "Select a maintenance category to inspect restart, sign-out, redownload, and support details.";
    maintenanceDetail.append(title, message);
    return;
  }
  if (maintenanceDetailStatus) {
    maintenanceDetailStatus.textContent = maintenanceStatusLabel(category.status);
    maintenanceDetailStatus.className = `status-pill ${maintenanceStatusTone(category.status)}`;
  }
  const title = document.createElement("strong");
  title.textContent = category.displayName || category.id;
  const description = document.createElement("span");
  description.textContent = category.description || "No description available.";
  const pathLabel = document.createElement("span");
  pathLabel.textContent = category.pathLabel ? `Internal location: ${category.pathLabel}` : "Internal location is unavailable.";
  maintenanceDetail.append(title, description, pathLabel);
  const list = document.createElement("dl");
  list.className = "maintenance-detail-list";
  [
    ["Measured size", formatBytes(category.sizeBytes || 0)],
    ["Files", String(category.fileCount || 0)],
    ["Last measured", category.measuredAt ? formatDateTime(category.measuredAt) : "Not measured"],
    ["Last cleared", category.lastClearedAt ? formatDateTime(category.lastClearedAt) : "Never"],
    ["Requires restart", category.restartRequired ? "Yes" : "No"],
    ["Signs out", category.signsOut ? "Yes" : "No"],
    ["Downloads again", category.downloadsAgain ? "Yes" : "No"],
    ["Currently in use", category.inUse ? "Yes" : "No"],
  ].forEach(([label, value]) => {
    const row = document.createElement("div");
    const dt = document.createElement("dt");
    dt.textContent = label;
    const dd = document.createElement("dd");
    dd.textContent = value;
    row.append(dt, dd);
    list.append(row);
  });
  maintenanceDetail.append(list);
  if (Array.isArray(category.errors) && category.errors.length > 0) {
    const errors = document.createElement("pre");
    errors.textContent = category.errors.map((error) => `${error.code || "ERROR"}: ${error.message || "Unknown error"}`).join("\n");
    maintenanceDetail.append(errors);
  }
}

function renderMaintenanceCenter() {
  if (!maintenanceList && !maintenanceSummaryFields.length) return;
  const totalBytes = maintenanceState.categories.reduce((sum, category) => sum + Number(category.sizeBytes || 0), 0);
  const safeCount = maintenanceState.categories.filter((category) => category.supported && !category.signsOut && !category.confirmationRequired).length;
  const warningCount = maintenanceState.categories.filter((category) => category.errorCount > 0 || category.status === "unsupported" || category.signsOut || category.restartRequired).length;
  maintenanceSummaryFields.forEach((field) => {
    const key = field.dataset.maintenanceSummary;
    if (key === "total") field.textContent = maintenanceState.categories.length ? formatBytes(totalBytes) : "Not scanned";
    if (key === "safe") field.textContent = String(safeCount);
    if (key === "warnings") field.textContent = String(warningCount);
    if (key === "lastScan") field.textContent = maintenanceState.lastScanAt ? formatDateTime(maintenanceState.lastScanAt) : "Never";
  });
  if (maintenanceScanState) {
    maintenanceScanState.textContent = maintenanceState.scanning ? "Scanning" : maintenanceState.categories.length ? "Scanned" : "Not scanned";
    maintenanceScanState.className = `status-pill ${maintenanceState.scanning ? "status-pill--planned" : maintenanceState.categories.length ? "status-pill--ok" : "status-pill--planned"}`;
  }
  maintenanceActionButtons.forEach((button) => {
    const action = button.dataset.maintenanceAction;
    const selected = maintenanceState.categories.filter((category) => maintenanceState.selectedIds.has(category.id));
    if (action === "scan") button.disabled = maintenanceState.scanning || maintenanceState.clearing;
    if (action === "clear-selected") button.disabled = maintenanceState.scanning || maintenanceState.clearing || !selected.some((category) => category.supported);
    if (action === "clear-safe") button.disabled = maintenanceState.scanning || maintenanceState.clearing || !maintenanceState.categories.some((category) => category.supported && !category.signsOut && !category.confirmationRequired && Number(category.sizeBytes || 0) > 0);
    if (action === "reset-ui") button.disabled = maintenanceState.scanning || maintenanceState.clearing;
  });
  if (!maintenanceList) {
    renderMaintenanceDetail();
    return;
  }
  maintenanceList.replaceChildren();
  if (!maintenanceState.categories.length) {
    const empty = document.createElement("div");
    empty.className = "maintenance-empty-state";
    const title = document.createElement("strong");
    title.textContent = maintenanceState.scanning ? "Scanning storage" : "No maintenance scan yet";
    const message = document.createElement("span");
    message.textContent = maintenanceState.scanning ? "Measuring trusted AnxOS cache locations." : "Run Scan Storage to find AnxOS-owned cache, diagnostics, and temporary files that are safe to review.";
    empty.append(title, message);
    maintenanceList.append(empty);
    renderMaintenanceDetail();
    return;
  }
  maintenanceState.categories.forEach((category) => {
    const item = document.createElement("article");
    item.className = "maintenance-item";
    item.classList.toggle("is-selected", category.id === maintenanceState.activeId);
    const checkbox = document.createElement("input");
    checkbox.type = "checkbox";
    checkbox.checked = maintenanceState.selectedIds.has(category.id);
    checkbox.disabled = !category.supported || maintenanceState.clearing;
    checkbox.setAttribute("aria-label", `Select ${category.displayName}`);
    checkbox.addEventListener("change", () => {
      if (checkbox.checked) maintenanceState.selectedIds.add(category.id);
      else maintenanceState.selectedIds.delete(category.id);
      renderMaintenanceCenter();
    });
    const main = document.createElement("button");
    main.type = "button";
    main.className = "maintenance-item__main";
    main.addEventListener("click", () => {
      maintenanceState.activeId = category.id;
      renderMaintenanceCenter();
    });
    const header = document.createElement("span");
    header.className = "maintenance-item__header";
    const title = document.createElement("strong");
    title.textContent = category.displayName || category.id;
    const status = document.createElement("span");
    status.className = `status-pill ${maintenanceStatusTone(category.status)}`;
    status.textContent = maintenanceStatusLabel(category.status);
    header.append(title, status);
    const meta = document.createElement("small");
    const flags = [
      category.restartRequired ? "Restart" : "",
      category.signsOut ? "Signs out" : "",
      category.downloadsAgain ? "Redownloads" : "",
      category.inUse ? "In use" : "",
    ].filter(Boolean);
    meta.textContent = `${formatBytes(category.sizeBytes || 0)} · ${category.fileCount || 0} files${flags.length ? ` · ${flags.join(", ")}` : ""}`;
    main.append(header, meta);
    item.append(checkbox, main);
    maintenanceList.append(item);
  });
  renderMaintenanceDetail();
}

function normalizeSearchText(value) {
  return String(value || "").trim().toLowerCase();
}

function getSearchHaystack(...values) {
  return values.flat(Infinity).filter((value) => value !== null && value !== undefined).join(" ").toLowerCase();
}

function matchesSearchQuery(query, ...values) {
  const normalized = normalizeSearchText(query);
  if (!normalized) return true;
  return getSearchHaystack(...values).includes(normalized);
}

function createGlobalSearchResult(provider, result = {}) {
  return {
    providerId: provider.id,
    providerLabel: provider.label,
    type: result.type || provider.type || provider.label,
    id: String(result.id || `${provider.id}:${Math.random().toString(36).slice(2)}`),
    label: String(result.label || "Untitled result"),
    description: result.description ? String(result.description) : "",
    disabled: Boolean(result.disabled),
    disabledReason: result.disabledReason ? String(result.disabledReason) : "",
    action: typeof result.action === "function" ? result.action : null,
  };
}

function limitSearchResults(results, limit = GLOBAL_SEARCH_PROVIDER_LIMIT) {
  return (Array.isArray(results) ? results : []).slice(0, limit);
}

function getWorkspaceSearchEntries() {
  return Array.from(navItems)
    .filter((item) => !item.hidden && item.dataset.pageTarget)
    .map((item) => ({
      id: item.dataset.pageTarget,
      label: item.dataset.pageLabel || item.textContent.trim() || item.dataset.pageTarget,
      description: item.dataset.tooltip || "Open workspace",
    }))
    .concat(shouldShowOwnerWorkspaceNav() ? [{
      id: "owner-workspace",
      label: "Owner Workspace",
      description: isOwnerWorkspaceAuthorized() ? "Open owner-only workspace" : "Owner access required",
      disabled: !isOwnerWorkspaceAuthorized(),
      disabledReason: "Sign in as Owner to open this workspace.",
    }] : [])
    .filter((entry, index, entries) => entries.findIndex((candidate) => candidate.id === entry.id) === index);
}

function getGlobalSearchProviders() {
  const providers = [
    {
      id: "commands",
      label: "Commands",
      type: "Action",
      search(query) {
        return [{ id: "command-palette", label: "Open Command Palette", description: "Run existing AnxOS actions. Shortcut: Ctrl+Shift+P" }]
          .filter((entry) => matchesSearchQuery(query, entry.label, entry.description, "commands actions palette"))
          .map((entry) => createGlobalSearchResult(this, {
            id: entry.id,
            label: entry.label,
            description: entry.description,
            action: () => openCommandPalette(),
          }));
      },
    },
    {
      id: "workspaces",
      label: "Workspaces",
      type: "Workspace",
      search(query) {
        return getWorkspaceSearchEntries()
          .filter((entry) => matchesSearchQuery(query, entry.label, entry.description, entry.id))
          .map((entry) => createGlobalSearchResult(this, {
            id: entry.id,
            label: entry.label,
            description: entry.description,
            disabled: entry.disabled,
            disabledReason: entry.disabledReason,
            action: () => showPage(entry.id),
          }));
      },
    },
    {
      id: "nodes",
      label: "Nodes and Agents",
      type: "Node",
      search(query) {
        const nodes = [nodesState.applicationHost, ...(Array.isArray(nodesState.nodes) ? nodesState.nodes : [])].filter(Boolean);
        const nodeResults = nodes
          .filter((node) => matchesSearchQuery(query, node.displayName, node.name, node.id, node.agentUrl, node.status, node.agentIdentity?.hostname, node.agentIdentity?.operatingSystem, node.agentIdentity?.version))
          .map((node) => createGlobalSearchResult(this, {
            id: node.id || node.name,
            label: node.displayName || node.name || node.id || "Node",
            description: [node.agentIdentity?.hostname, node.status || node.connectionStatus, node.agentIdentity?.operatingSystem].filter(Boolean).join(" · ") || "Managed node",
            action: () => {
              nodesState.selectedNodeId = node.id || nodesState.selectedNodeId;
              showPage("nodes");
              if (node.id && typeof selectNode === "function") {
                const selection = selectNode(node.id);
                selection?.catch?.(() => {});
              }
            },
          }));
        const health = getSharedNodeHealthModel();
        const healthResults = [
          {
            id: "node-health-overall",
            label: `Node Health: ${health.state}`,
            description: health.summary,
            action: () => {
              showPage("nodes");
              openNodeDetails(health.nodeId);
            },
          },
          ...health.categories.map((category) => ({
            id: `node-health-${category.id}`,
            label: `${category.label}: ${category.state}`,
            description: `${category.evidence} · ${category.issueCount} issue${category.issueCount === 1 ? "" : "s"}`,
            action: () => {
              showPage("nodes");
              openNodeDetails(health.nodeId);
            },
          })),
        ]
          .filter((entry) => matchesSearchQuery(query, entry.label, entry.description, "node health agent dependency resource storage diagnostics operations files maintenance updates marketplace"))
          .map((entry) => createGlobalSearchResult(this, {
            id: entry.id,
            label: entry.label,
            description: entry.description,
            action: entry.action,
          }));
        return [...nodeResults, ...healthResults];
      },
    },
    {
      id: "instances",
      label: "Marketplace Instances",
      type: "Instance",
      search(query) {
        return getInstances()
          .filter((instance) => matchesSearchQuery(query, instance.id, instance.displayName, instance.type, instance.state, instance.tags))
          .map((instance) => createGlobalSearchResult(this, {
            id: instance.id,
            label: instance.displayName || instance.id,
            description: [instance.type, instance.state, Array.isArray(instance.tags) ? instance.tags.join(", ") : ""].filter(Boolean).join(" · "),
            action: () => {
              if (!findInstance(instance.id)) {
                showToast("That instance is no longer available.", "warning");
                return;
              }
              showPage("instances");
              selectInstance(instance.id);
            },
          }));
      },
    },
    {
      id: "marketplace",
      label: "Marketplace",
      type: "Template",
      search(query) {
        return getMarketplaceTemplates()
          .filter((template) => matchesSearchQuery(query, template.displayName, template.name, template.description, template.author, template.category, template.tags, template.id, template.runtimeRequirements))
          .map((template) => createGlobalSearchResult(this, {
            id: template.id,
            label: template.displayName || template.name || template.id,
            description: [template.category, template.author || template.maintainer, template.disabled || template.comingSoon ? "Unavailable" : "Installable"].filter(Boolean).join(" · "),
            disabled: Boolean(template.disabled || template.comingSoon),
            disabledReason: template.comingSoonMessage || "This Marketplace template is not ready yet.",
            action: () => {
              showPage("marketplace");
              if (!findMarketplaceTemplate(template.id)) {
                showToast("Marketplace template is no longer loaded.", "warning");
                return;
              }
              openMarketplaceWizard(template.id);
            },
          }));
      },
    },
    {
      id: "files",
      label: "Files",
      type: "File",
      search(query) {
        const entries = (latestFilesListing?.entries || []).map((entry) => ({
          id: entry.path || entry.name,
          label: entry.name || entry.path || "File item",
          description: `${entry.isDirectory ? "Folder" : formatBytes(entry.size)} · Current directory only`,
          entry,
        }));
        const storageEntries = (storageConnectionsState.connections || []).map((connection) => ({
          id: `storage:${connection.id}`,
          label: storageConnectionLabel(connection),
          description: [connection.provider || connection.type || "Storage", connection.rootDirectory || connection.host].filter(Boolean).join(" · "),
          connection,
        }));
        return [...entries, ...storageEntries]
          .filter((entry) => matchesSearchQuery(query, entry.label, entry.description, entry.id))
          .map((entry) => createGlobalSearchResult(this, {
            id: entry.id,
            label: entry.label,
            description: entry.description || "Files workspace",
            action: async () => {
              showPage("files");
              if (entry.entry) {
                if (!filesConnectionState.connected) {
                  showToast("Files are not connected.", "warning");
                  return;
                }
                selectFileEntry(entry.entry);
                if (entry.entry.isDirectory) await navigateRemoteDirectory(entry.entry.path);
              } else if (entry.connection) {
                selectedStorageId = entry.connection.id;
                activateFilesTargetState({ loading: false, message: "Select Connect to browse this filesystem." });
                renderStorageConnections();
                renderFilesView();
              }
            },
          }));
      },
    },
    {
      id: "settings",
      label: "Settings",
      type: "Setting",
      search(query) {
        return getSettingSearchEntries()
          .filter((entry) => matchesSearchQuery(query, entry.title, entry.description, entry.haystack, entry.category))
          .map((entry) => createGlobalSearchResult(this, {
            id: entry.category,
            label: entry.title,
            description: entry.description || "Settings category",
            action: () => {
              showPage("settings");
              setActiveSettingsCategory(entry.category, entry.selector);
            },
          }));
      },
    },
    {
      id: "operations",
      label: "Operations",
      type: "Task",
      search(query) {
        loadOperationHistory();
        return [...operationsState.items.values()]
          .sort((a, b) => (b.updatedAt || 0) - (a.updatedAt || 0))
          .filter((operation) => matchesSearchQuery(query, operation.title, operation.target, operation.type, operation.status, operation.step, operation.error))
          .map((operation) => createGlobalSearchResult(this, {
            id: operation.id,
            label: operation.title || "Operation",
            description: [operationStatusLabel(operation.status), operation.target || operation.step].filter(Boolean).join(" · "),
            action: () => {
              showPage("operations");
              operationsState.selectedId = operation.id;
              renderOperationsCenter();
            },
          }));
      },
    },
    {
      id: "maintenance",
      label: "Maintenance",
      type: "Cache",
      search(query) {
        return (maintenanceState.categories || [])
          .filter((category) => matchesSearchQuery(query, category.displayName, category.description, category.id, category.status, category.pathLabel))
          .map((category) => createGlobalSearchResult(this, {
            id: category.id,
            label: category.displayName || category.id,
            description: [maintenanceStatusLabel(category.status), formatBytes(category.sizeBytes || 0), category.restartRequired ? "Restart required" : ""].filter(Boolean).join(" · "),
            action: () => {
              showPage("maintenance");
              maintenanceState.activeId = category.id;
              renderMaintenanceCenter();
            },
          }));
      },
    },
    {
      id: "security",
      label: "Security",
      type: "Security",
      search(query) {
        const dashboard = securityDashboardState || {};
        const entries = [
          { id: "status", label: "Security status", description: securityState.authenticated ? "Local owner authenticated" : "Authentication required", section: ".settings-section--security-overview" },
          { id: "sessions", label: "Current sessions", description: `${dashboard.overview?.rememberedSessionCount ?? securityState.persistentSessionCount ?? 0} remembered sessions`, section: ".settings-section--security-sessions" },
          { id: "devices", label: "Trusted devices", description: `${dashboard.overview?.trustedDeviceCount ?? 0} trusted devices`, section: ".settings-section--security-devices" },
          { id: "token", label: "Agent token security", description: dashboard.agentToken?.configured ? "Agent token configured" : "Agent token missing or unavailable", section: ".settings-section--security-token" },
          { id: "recommendations", label: "Security recommendations", description: `${(dashboard.recommendations || []).length} deterministic recommendations`, section: ".settings-section--security-recommendations" },
          { id: "events", label: "Security events", description: `${(dashboard.events || []).length} redacted audit events loaded`, section: ".settings-section--security-events" },
          { id: "permissions", label: "Roles and permissions", description: securityState.user?.role || "Role unavailable", section: ".settings-section--security-permissions" },
          { id: "account", label: "Account protection", description: accountState.authenticated ? "AnxOS account signed in" : "No account session", section: ".settings-section--security-account" },
          ...(dashboard.sessions || []).map((session, index) => ({
            id: `session:${index}`,
            label: session.current ? "Current session" : session.deviceName || "Remembered session",
            description: [session.operatingSystem, session.current ? "Current" : session.trusted ? "Trusted" : "Untrusted", formatSecurityTime(session.lastActiveAt)].filter(Boolean).join(" · "),
            section: ".settings-section--security-sessions",
          })),
          ...(dashboard.trustedDevices || []).map((device, index) => ({
            id: `device:${index}`,
            label: device.name || "Trusted device",
            description: [device.platform, device.current ? "Current" : device.trusted ? "Trusted" : "Untrusted", formatSecurityTime(device.lastSeen)].filter(Boolean).join(" · "),
            section: ".settings-section--security-devices",
          })),
          ...(dashboard.events || []).slice(0, 20).map((event) => ({
            id: `event:${event.timestamp}:${event.type}`,
            label: event.type || "Security event",
            description: [event.category, event.result, formatSecurityTime(event.timestamp)].filter(Boolean).join(" · "),
            section: ".settings-section--security-events",
          })),
        ];
        return entries
          .filter((entry) => matchesSearchQuery(query, entry.id, entry.label, entry.description))
          .map((entry) => createGlobalSearchResult(this, {
            id: entry.id,
            label: entry.label,
            description: entry.description,
            action: () => openSecuritySection(entry.section || ".settings-section--security-overview"),
          }));
      },
    },
    {
      id: "diagnostics",
      label: "Diagnostics",
      type: "Diagnostic",
      search(query) {
        const issueResults = (diagnosticsIssueGroups.length ? diagnosticsIssueGroups : groupDiagnosticIssues(agentLogEntries))
          .filter((group) => matchesSearchQuery(query, group.code, group.source, group.operation, group.latest?.message, getDiagnosticExplanation(group.code, group.latest).title))
          .slice(0, 12)
          .map((group) => {
            const explanation = getDiagnosticExplanation(group.code, group.latest);
            return createGlobalSearchResult(this, {
              id: `issue:${group.id}`,
              label: explanation.title,
              description: [group.code || "No code", getDiagnosticSeverityLabel(group.severity), `${group.count} occurrence${group.count === 1 ? "" : "s"}`].join(" · "),
              action: () => {
                showPage("agent-control");
                if (agentLogSearch) {
                  agentLogSearch.value = group.code || group.source || explanation.title;
                  renderAgentLogs();
                  agentLogSearch.focus();
                }
              },
            });
          });
        const entries = agentLogEntries.slice(-80).reverse();
        const logResults = entries
          .filter((entry) => matchesSearchQuery(query, entry.severity, entry.source, entry.operation, entry.message, entry.code))
          .slice(0, 10)
          .map((entry, index) => createGlobalSearchResult(this, {
            id: `${entry.timestamp || "log"}:${index}`,
            label: entry.message || entry.code || "Diagnostic entry",
            description: [entry.severity, entry.source, entry.operation, entry.timestamp ? formatDateTime(entry.timestamp) : ""].filter(Boolean).join(" · "),
            action: () => {
              showPage("agent-control");
              agentLogSearch?.focus();
            },
          }));
        return [...issueResults, ...logResults];
      },
    },
    {
      id: "notifications",
      label: "Notifications",
      type: "Notification",
      search(query) {
        loadNotificationHistory();
        return notificationState.items
          .filter((notification) => matchesSearchQuery(query, notification.title, notification.message, notification.category, notification.severity, notification.relatedDiagnosticCode))
          .slice(0, 16)
          .map((notification) => createGlobalSearchResult(this, {
            id: notification.id,
            label: notification.title,
            description: [notification.category, notificationSeverityLabel(notification.severity), notification.read ? "Read" : "Unread"].join(" · "),
            action: () => {
              showPage("notifications");
              notification.read = true;
              persistNotificationHistory();
              renderNotificationCenter();
            },
          }));
      },
    },
  ];

  if (isOwnerWorkspaceAuthorized()) {
    providers.push({
      id: "owner-workspace",
      label: "Owner Workspace",
      type: "Owner",
      search(query) {
        const overview = buildOwnerOverviewModel();
        const ownerEntries = [
          { id: "owner-overview-state", label: `Owner Overview: ${overview.state}`, description: `${overview.issueCount} owner summaries need attention`, action: () => selectOwnerPage("overview") },
          ...overview.agentSummaries.map((item) => ({ id: `owner-agent:${item.label}`, label: item.label, description: item.evidence, action: () => selectOwnerPage("overview") })),
          ...overview.adminSummaries.map((item) => ({ id: `owner-admin:${item.label}`, label: item.label, description: item.evidence, action: () => selectOwnerPage("overview") })),
        ];
        const pageEntries = (ownerWorkspaceState.pages || [])
          .filter((page) => matchesSearchQuery(query, page.title, page.id, page.builtIn ? "built-in" : "custom"))
          .map((page) => createGlobalSearchResult(this, {
            id: page.id,
            label: page.title || page.id,
            description: page.builtIn ? "Built-in owner page" : "Custom owner page",
            action: () => selectOwnerPage(page.id),
          }));
        const summaryEntries = ownerEntries
          .filter((entry) => matchesSearchQuery(query, entry.label, entry.description, "owner workspace diagnostics agents dependencies build security maintenance operations"))
          .map((entry) => createGlobalSearchResult(this, {
            id: entry.id,
            label: entry.label,
            description: entry.description,
            action: entry.action,
          }));
        return [...summaryEntries, ...pageEntries];
      },
    });
  }

  return providers;
}

function readGlobalSearchRecents() {
  try {
    const value = JSON.parse(window.localStorage.getItem(GLOBAL_SEARCH_RECENTS_STORAGE_KEY) || "[]");
    return Array.isArray(value) ? value.filter((entry) => typeof entry === "string").slice(0, GLOBAL_SEARCH_RECENT_LIMIT) : [];
  } catch {
    return [];
  }
}

function writeGlobalSearchRecents() {
  try {
    window.localStorage.setItem(GLOBAL_SEARCH_RECENTS_STORAGE_KEY, JSON.stringify(globalSearchState.recentSearches.slice(0, GLOBAL_SEARCH_RECENT_LIMIT)));
  } catch {}
}

function isSensitiveSearchQuery(query) {
  const value = String(query || "").trim();
  if (!value) return true;
  if (value.length > 96) return true;
  if (/(\bpassword\b|\bpasswd\b|\btoken\b|\bsecret\b|\bauthorization\b|\bcookie\b|\bapi[-_ ]?key\b|bearer\s+|sk-[a-z0-9_-]{12,})/i.test(value)) return true;
  if (/^[A-Z0-9]{6,}(?:-[A-Z0-9]{4,}){1,}$/i.test(value)) return true;
  if (/^(?:\/|[A-Za-z]:\\|~\/).{20,}/.test(value)) return true;
  return false;
}

function rememberGlobalSearchQuery(query) {
  const value = String(query || "").trim();
  if (isSensitiveSearchQuery(value)) return;
  globalSearchState.recentSearches = [value, ...globalSearchState.recentSearches.filter((entry) => entry.toLowerCase() !== value.toLowerCase())].slice(0, GLOBAL_SEARCH_RECENT_LIMIT);
  writeGlobalSearchRecents();
}

function appendHighlightedText(target, text, query) {
  const source = String(text || "");
  const normalizedQuery = String(query || "").trim();
  if (!normalizedQuery) {
    target.append(document.createTextNode(source));
    return;
  }
  const lower = source.toLowerCase();
  const needle = normalizedQuery.toLowerCase();
  let cursor = 0;
  let index = lower.indexOf(needle);
  while (index >= 0) {
    if (index > cursor) target.append(document.createTextNode(source.slice(cursor, index)));
    const mark = document.createElement("mark");
    mark.className = "global-search-highlight";
    mark.textContent = source.slice(index, index + needle.length);
    target.append(mark);
    cursor = index + needle.length;
    index = lower.indexOf(needle, cursor);
  }
  if (cursor < source.length) target.append(document.createTextNode(source.slice(cursor)));
}

function renderGlobalSearchRecents() {
  if (!globalSearchRecents || !globalSearchRecentsWrap) return;
  globalSearchRecents.replaceChildren();
  const shouldShow = globalSearchState.open && !globalSearchState.query && globalSearchState.recentSearches.length > 0;
  globalSearchRecentsWrap.hidden = !shouldShow;
  if (!shouldShow) return;
  globalSearchState.recentSearches.forEach((term) => {
    const button = document.createElement("button");
    button.type = "button";
    button.className = "global-search-recent";
    button.textContent = term;
    button.addEventListener("click", () => {
      if (globalSearchInput) globalSearchInput.value = term;
      scheduleGlobalSearch(term, { immediate: true });
    });
    globalSearchRecents.append(button);
  });
}

function renderGlobalSearchEmpty(title, message) {
  if (!globalSearchResults) return;
  const empty = document.createElement("div");
  empty.className = "global-search-empty";
  const strong = document.createElement("strong");
  strong.textContent = title;
  const span = document.createElement("span");
  span.textContent = message;
  empty.append(strong, span);
  globalSearchResults.replaceChildren(empty);
}

function renderGlobalSearchResults() {
  if (!globalSearchResults) return;
  renderGlobalSearchRecents();
  const query = globalSearchState.query;
  if (globalSearchStatus) {
    if (globalSearchState.searching) {
      globalSearchStatus.textContent = "Searching...";
    } else if (globalSearchState.error) {
      globalSearchStatus.textContent = globalSearchState.error;
    } else {
      globalSearchStatus.textContent = query
        ? `${globalSearchState.results.length} result${globalSearchState.results.length === 1 ? "" : "s"}`
        : "Type to search.";
    }
  }
  if (!query) {
    renderGlobalSearchEmpty("Start typing to search", "Global Search uses currently loaded desktop state and bounded local lists.");
    return;
  }
  if (globalSearchState.error) {
    renderGlobalSearchEmpty("Search unavailable", globalSearchState.error);
    return;
  }
  if (!globalSearchState.results.length) {
    renderGlobalSearchEmpty("No matching results", "Try a different workspace, setting, loaded file, node, or Marketplace term.");
    return;
  }
  globalSearchResults.replaceChildren();
  let flatIndex = 0;
  const groups = new Map();
  globalSearchState.results.forEach((result) => {
    if (!groups.has(result.providerLabel)) groups.set(result.providerLabel, []);
    groups.get(result.providerLabel).push(result);
  });
  groups.forEach((results, providerLabel) => {
    const group = document.createElement("section");
    group.className = "global-search-group";
    const heading = document.createElement("div");
    heading.className = "global-search-group-title";
    heading.textContent = providerLabel;
    group.append(heading);
    results.forEach((result) => {
      const index = flatIndex;
      const button = document.createElement("button");
      button.type = "button";
      button.className = "global-search-result";
      button.disabled = result.disabled;
      button.dataset.globalSearchResultIndex = String(index);
      button.setAttribute("role", "option");
      button.setAttribute("aria-selected", index === globalSearchState.activeIndex ? "true" : "false");
      button.classList.toggle("is-active", index === globalSearchState.activeIndex);
      const top = document.createElement("span");
      top.className = "global-search-result__top";
      const title = document.createElement("strong");
      appendHighlightedText(title, result.label, query);
      const type = document.createElement("span");
      type.className = "global-search-result__type";
      type.textContent = result.type;
      top.append(title, type);
      const description = document.createElement("p");
      description.textContent = result.disabled ? result.disabledReason || "Unavailable" : result.description || "Open result";
      button.append(top, description);
      button.addEventListener("click", () => activateGlobalSearchResult(index));
      group.append(button);
      flatIndex += 1;
    });
    globalSearchResults.append(group);
  });
}

async function refreshCurrentFilesDirectory() {
  await refreshFilesDiscovery();
  return refreshFileListing({
    profileId: getFilesRequestProfileId(),
    storageId: getFilesRequestStorageId(),
    path: filesConnectionState.currentPath || filesConnectionState.homePath || "/",
  });
}

let filesDiscoveryRefreshPromise = null;
async function refreshFilesDiscovery() {
  if (filesDiscoveryRefreshPromise) {
    return filesDiscoveryRefreshPromise;
  }
  filesFilesystemIdentityCache.clear();
  filesDiscoveryRefreshPromise = Promise.allSettled([
    refreshNodes(),
    loadSshProfiles(),
    loadStorageConnections(),
  ]).then(() => {
    syncFilesSelectionState();
    renderStorageConnections();
    renderFilesView();
  }).finally(() => {
    filesDiscoveryRefreshPromise = null;
  });
  return filesDiscoveryRefreshPromise;
}

async function runDiagnosticsAction(action) {
  if (action === "health") {
    runDiagnosticsHealthChecks();
    return;
  }
  const api = getDesktopApiState().api?.diagnostics;
  if (!api) {
    showToast("Diagnostics are unavailable in this build.", "warning");
    return;
  }
  if (action === "export" && !confirmDiagnosticsSupportBundleExport()) return;
  const operationId = startOperation({
    type: "Diagnostics",
    title: {
      capture: "Capture diagnostics snapshot",
      open: "Open logs folder",
      copy: "Copy diagnostics summary",
      export: "Export diagnostics bundle",
      health: "Run diagnostics health checks",
    }[action] || "Run diagnostics action",
    target: getActivePageName(),
    step: "Running diagnostics action.",
  });
  try {
    if (action === "capture") await api.capture({ currentWorkspace: getActivePageName() });
    if (action === "open") await api.openFolder();
    if (action === "copy") await api.copySummary();
    if (action === "export") await api.exportBundle();
    finishOperation(operationId, true, "Diagnostic action completed.");
    showToast("Diagnostic action completed.", "success");
  } catch (error) {
    const message = normalizeIpcErrorMessage(error, "Diagnostic action failed.");
    finishOperation(operationId, false, message);
    showToast(message, "error");
    throw error;
  }
}

async function runGlobalSearch(query) {
  const requestId = ++globalSearchState.requestId;
  const normalized = String(query || "").trim();
  globalSearchState.query = normalized;
  globalSearchState.error = null;
  if (!normalized) {
    globalSearchState.results = [];
    globalSearchState.activeIndex = 0;
    globalSearchState.searching = false;
    renderGlobalSearchResults();
    return;
  }
  globalSearchState.searching = true;
  renderGlobalSearchResults();
  try {
    const providerResults = await Promise.allSettled(getGlobalSearchProviders().map(async (provider) => {
      const results = await provider.search(normalized);
      return limitSearchResults(results, provider.limit || GLOBAL_SEARCH_PROVIDER_LIMIT);
    }));
    if (requestId !== globalSearchState.requestId) return;
    const results = providerResults
      .flatMap((result) => result.status === "fulfilled" ? result.value : [])
      .slice(0, GLOBAL_SEARCH_TOTAL_LIMIT);
    globalSearchState.results = results;
    globalSearchState.activeIndex = results.findIndex((result) => !result.disabled);
    if (globalSearchState.activeIndex < 0) globalSearchState.activeIndex = 0;
  } catch (error) {
    if (requestId !== globalSearchState.requestId) return;
    globalSearchState.results = [];
    globalSearchState.error = normalizeIpcErrorMessage(error, "Search failed.");
  } finally {
    if (requestId === globalSearchState.requestId) {
      globalSearchState.searching = false;
      renderGlobalSearchResults();
    }
  }
}

function scheduleGlobalSearch(query, { immediate = false } = {}) {
  window.clearTimeout(globalSearchDebounceTimer);
  if (immediate) {
    runGlobalSearch(query);
    return;
  }
  globalSearchDebounceTimer = window.setTimeout(() => runGlobalSearch(query), GLOBAL_SEARCH_DEBOUNCE_MS);
}

function moveGlobalSearchSelection(delta) {
  const enabled = globalSearchState.results.map((result, index) => ({ result, index })).filter((entry) => !entry.result.disabled);
  if (!enabled.length) return;
  const currentEnabledIndex = Math.max(0, enabled.findIndex((entry) => entry.index === globalSearchState.activeIndex));
  const next = enabled[(currentEnabledIndex + delta + enabled.length) % enabled.length];
  globalSearchState.activeIndex = next.index;
  renderGlobalSearchResults();
  globalSearchResults?.querySelector(`[data-global-search-result-index="${globalSearchState.activeIndex}"]`)?.scrollIntoView({ block: "nearest" });
}

async function activateGlobalSearchResult(index = globalSearchState.activeIndex) {
  const result = globalSearchState.results[index];
  if (!result || result.disabled) {
    if (result?.disabledReason) showToast(result.disabledReason, "warning");
    return;
  }
  rememberGlobalSearchQuery(globalSearchState.query);
  closeGlobalSearch();
  try {
    await result.action?.();
  } catch (error) {
    showToast(normalizeIpcErrorMessage(error, "Search result could not be opened."), "error");
  }
}

function openGlobalSearch(initialQuery = "") {
  if (!globalSearchOverlay || !globalSearchInput) return;
  if (openModalCount > 0) return;
  globalSearchState.previousFocus = document.activeElement instanceof HTMLElement ? document.activeElement : null;
  globalSearchState.open = true;
  globalSearchState.recentSearches = readGlobalSearchRecents();
  globalSearchOverlay.hidden = false;
  document.body.classList.add("has-open-modal");
  const query = String(initialQuery || "");
  globalSearchInput.value = query;
  scheduleGlobalSearch(query, { immediate: true });
  requestAnimationFrame(() => {
    globalSearchInput.focus();
    globalSearchInput.select();
  });
}

function closeGlobalSearch() {
  if (!globalSearchOverlay) return;
  window.clearTimeout(globalSearchDebounceTimer);
  globalSearchState.open = false;
  globalSearchOverlay.hidden = true;
  if (openModalCount === 0) document.body.classList.remove("has-open-modal");
  globalSearchState.previousFocus?.focus?.();
  globalSearchState.previousFocus = null;
}

function handleGlobalSearchKeydown(event) {
  if (!globalSearchState.open) {
    if (!event.defaultPrevented && !event.altKey && (event.ctrlKey || event.metaKey) && event.key.toLowerCase() === "k") {
      event.preventDefault();
      openGlobalSearch();
    }
    return;
  }
  if (event.key === "Escape") {
    event.preventDefault();
    closeGlobalSearch();
  } else if (event.key === "ArrowDown") {
    event.preventDefault();
    moveGlobalSearchSelection(1);
  } else if (event.key === "ArrowUp") {
    event.preventDefault();
    moveGlobalSearchSelection(-1);
  } else if (event.key === "Enter") {
    event.preventDefault();
    activateGlobalSearchResult();
  }
}

function readCommandPaletteRecents() {
  try {
    const value = JSON.parse(window.localStorage.getItem(COMMAND_PALETTE_RECENTS_STORAGE_KEY) || "[]");
    return Array.isArray(value) ? value.filter((entry) => typeof entry === "string").slice(0, COMMAND_PALETTE_RECENT_LIMIT) : [];
  } catch {
    return [];
  }
}

function writeCommandPaletteRecents() {
  try {
    window.localStorage.setItem(COMMAND_PALETTE_RECENTS_STORAGE_KEY, JSON.stringify(commandPaletteState.recentCommandIds.slice(0, COMMAND_PALETTE_RECENT_LIMIT)));
  } catch {}
}

function createCommand(command = {}) {
  if (!command.id || !command.title || typeof command.execute !== "function") {
    throw new Error("Invalid command registration.");
  }
  return {
    id: String(command.id),
    title: String(command.title),
    description: command.description ? String(command.description) : "",
    category: command.category ? String(command.category) : "Application",
    shortcut: command.shortcut ? String(command.shortcut) : "",
    keywords: Array.isArray(command.keywords) ? command.keywords.map(String) : [],
    visible: typeof command.visible === "function" ? command.visible : () => true,
    enabled: typeof command.enabled === "function" ? command.enabled : () => true,
    disabledReason: typeof command.disabledReason === "function" ? command.disabledReason : () => command.disabledReason || "Command unavailable.",
    confirm: command.confirm || null,
    execute: command.execute,
  };
}

